window.STATE_SPECIAL["LA"] = {"code":"LA","name":"Louisiana","agency":"Louisiana OMV","agencyShort":"OMV","handbook":"https://public.powerdms.com/LADPSC/documents/347037","links":{},"en":[{"q":"On Louisiana highways, what is the maximum legal width of a commercial vehicle, exclusive of safety devices?","options":["96 inches","98 inches","102 inches","108 inches"],"answer":2,"explanation":"Louisiana RS 32:380 sets the maximum vehicle width at 102 inches (8 feet 6 inches), exclusive of safety devices such as mirrors. Source: Louisiana Revised Statutes 32:380.","handbook":"","hbref":""},{"q":"What is the maximum legal vehicle height in Louisiana on highways other than the Interstate system?","options":["13 feet","13 feet 6 inches","14 feet","14 feet 6 inches"],"answer":1,"explanation":"Under Louisiana RS 32:381, a vehicle and its load may not exceed 13 feet 6 inches in height on non-Interstate highways. Source: Louisiana Revised Statutes 32:381.","handbook":"","hbref":""},{"q":"What is the maximum legal vehicle height in Louisiana for a vehicle operating exclusively on the Interstate highway system?","options":["13 feet 6 inches","14 feet","14 feet 6 inches","15 feet"],"answer":1,"explanation":"Louisiana RS 32:381 allows a maximum height of 14 feet for a vehicle and its load operating exclusively on the Interstate highway system, compared with 13 feet 6 inches elsewhere. Source: Louisiana Revised Statutes 32:381.","handbook":"","hbref":""},{"q":"In Louisiana, what is the maximum legal length of a single vehicle (such as a straight truck or bus)?","options":["40 feet","45 feet","53 feet","59 feet 6 inches"],"answer":1,"explanation":"Louisiana RS 32:382 limits a single vehicle to a maximum length of 45 feet. Source: Louisiana Revised Statutes 32:382.","handbook":"","hbref":""},{"q":"What is the maximum legal length of the semitrailer portion of a tractor-semitrailer combination in Louisiana?","options":["48 feet","53 feet","57 feet","59 feet 6 inches"],"answer":3,"explanation":"Louisiana RS 32:382 allows the semitrailer portion of a tractor-semitrailer combination to be up to 59 feet 6 inches; there is no separate overall combination length limit for this configuration. Source: Louisiana Revised Statutes 32:382.","handbook":"","hbref":""},{"q":"How far beyond the width of its body may a load project on a Louisiana vehicle?","options":["Not more than 6 inches","Not more than 12 inches","Not more than 18 inches","Not more than 24 inches"],"answer":1,"explanation":"Louisiana RS 32:380 provides that a load shall not project more than 12 inches beyond the width of the vehicle's body. Source: Louisiana Revised Statutes 32:380.","handbook":"","hbref":""},{"q":"What is the maximum gross weight allowed for any vehicle or combination of vehicles on Louisiana highways without a permit?","options":["73,280 pounds","80,000 pounds","88,000 pounds","90,000 pounds"],"answer":1,"explanation":"Louisiana RS 32:386 limits the total gross weight of any vehicle or combination of vehicles to 80,000 pounds. Source: Louisiana Revised Statutes 32:386.","handbook":"","hbref":""},{"q":"In Louisiana, what is the maximum gross weight permitted on a single axle equipped with low-pressure pneumatic tires?","options":["18,000 pounds","20,000 pounds","22,400 pounds","34,000 pounds"],"answer":1,"explanation":"Louisiana RS 32:386 limits a single axle equipped with low-pressure pneumatic tires to 20,000 pounds. Source: Louisiana Revised Statutes 32:386.","handbook":"","hbref":""},{"q":"What is the maximum gross weight permitted on a tandem axle in Louisiana under the general statutory limit?","options":["32,000 pounds","34,000 pounds","37,000 pounds","40,000 pounds"],"answer":1,"explanation":"Louisiana RS 32:386 limits a tandem axle equipped with low-pressure pneumatic tires to 34,000 pounds. Source: Louisiana Revised Statutes 32:386.","handbook":"","hbref":""},{"q":"Louisiana provides a higher tandem-axle weight allowance for vehicles carrying forest products in their natural state. What is that limit, and where does it NOT apply?","options":["37,000 pounds, except on the Interstate system","37,000 pounds, including the Interstate system","40,000 pounds, except on the Interstate system","34,000 pounds, applies everywhere"],"answer":0,"explanation":"Louisiana RS 32:386 allows 37,000 pounds per tandem axle for vehicles hauling forest products in their natural state, except on the Interstate system, where the standard 34,000-pound limit applies. Source: Louisiana Revised Statutes 32:386.","handbook":"","hbref":""},{"q":"Under Louisiana RS 32:386, no tire on any axle may impose a weight on the highway surface greater than how much per inch of tire width?","options":["500 pounds per inch","600 pounds per inch","650 pounds per inch","700 pounds per inch"],"answer":2,"explanation":"Louisiana RS 32:386 states that no tire shall impose a greater weight on the highway surface than 650 pounds per inch of tire width. Source: Louisiana Revised Statutes 32:386.","handbook":"","hbref":""},{"q":"Which formula does Louisiana apply on the Interstate system to determine the maximum allowable gross weight on any group of two or more consecutive axles?","options":["The Federal Bridge Formula W = 500(LN/(N-1) + 12N + 36)","A flat 80,000-pound limit regardless of axle spacing","The single-axle 20,000-pound rule multiplied by axle count","A weight equal to 650 pounds times the wheelbase in inches"],"answer":0,"explanation":"Louisiana RS 32:386 incorporates the Federal Bridge Formula, W = 500(LN/(N-1) + 12N + 36), to cap the weight on consecutive axles on the Interstate, where L is axle spacing in feet and N is the number of axles. Source: Louisiana Revised Statutes 32:386 (Federal Bridge Formula).","handbook":"","hbref":""},{"q":"In the Federal Bridge Formula used in Louisiana, W = 500(LN/(N-1) + 12N + 36), what do the variables L and N represent?","options":["L is the load in tons; N is the number of tires","L is the distance in feet between the outer axles of a group; N is the number of axles in that group","L is the legal speed; N is the axle weight","L is the lane width; N is the number of trailers"],"answer":1,"explanation":"In the Federal Bridge Formula as applied by Louisiana RS 32:386, L is the distance in feet between the extreme (outer) axles of any group, and N is the number of axles in that group. Source: Louisiana Revised Statutes 32:386 / Federal Bridge Formula.","handbook":"","hbref":""},{"q":"A motor carrier in Louisiana must obtain an oversize/overweight permit when a vehicle or load exceeds the legal limits. Which agency issues these permits?","options":["The Louisiana Office of Motor Vehicles (OMV)","The Louisiana Department of Transportation and Development (DOTD)","The Louisiana State Police only","The local parish sheriff's office"],"answer":1,"explanation":"Oversize/overweight permits in Louisiana are issued by the Department of Transportation and Development (DOTD) through its Truck Permit Office and the PERBA electronic routing system. Source: Louisiana DOTD, Oversize and Overweight Truck Permits; LAC Title 73.","handbook":"","hbref":""},{"q":"When must a Louisiana oversize/overweight permit be obtained relative to the move?","options":["Within 24 hours after the move is completed","At any roadside weigh station during the trip","Before the oversize/overweight vehicle or load moves within or enters Louisiana","Only after a citation is issued"],"answer":2,"explanation":"A permit must be applied for and obtained before the oversize/overweight vehicle or load moves within or enters the state of Louisiana. Source: Louisiana DOTD oversize/overweight permit rules; LAC Title 73, Part I.","handbook":"","hbref":""},{"q":"A Louisiana annual oversize/overweight permit (as opposed to a single-trip permit) is valid for travel on which roads?","options":["Interstate highways only","Non-Interstate highways only","All state and Interstate highways","Parish roads only"],"answer":1,"explanation":"Louisiana annual permits are valid for one year and authorize travel only on non-Interstate highways; movements on the Interstate require single-trip permitting. Source: Louisiana DOTD Annual Permits; LAC Title 73, Part I, Chapter 3.","handbook":"","hbref":""},{"q":"What minimum bond or certificate of insurance amount does Louisiana require for a single-trip oversize/overweight permit?","options":["$50,000","$100,000","$250,000","$500,000"],"answer":1,"explanation":"Louisiana requires a bond or certificate of insurance of at least $100,000 for a single-trip permit (and $250,000 for an annual permit). Source: Louisiana DOTD oversize/overweight permit requirements.","handbook":"","hbref":""},{"q":"Louisiana offers a special permit for hauling farm products in their natural state that exceed legal axle or gross weight limits during harvest. What is this permit commonly called?","options":["A harvest season permit","A trip lease permit","A hazmat tonnage permit","A reciprocity permit"],"answer":0,"explanation":"Louisiana DOTD issues harvest season permits for vehicles hauling farm products in their natural state that exceed legal gross or axle weight limits; the annual fee is $100. Source: Louisiana DOTD Harvest Season / Annual Permits; LAC Title 73, Part I.","handbook":"","hbref":""},{"q":"Under Louisiana's sugarcane hauling permit requirements, what axle configuration must the vehicle-and-trailer combination have?","options":["A minimum of four axles total","A total of six axles, with an additional load-bearing single axle on the sugarcane trailer","Only a tandem rear axle","A total of eight axles with all lift axles raised"],"answer":1,"explanation":"Louisiana's sugarcane harvest permit provisions require a total of six axles for the vehicle-and-trailer combination, including an additional dual-tired single axle on the sugarcane trailer that is lowered and functions as a load-bearing axle. Source: Louisiana DOTD harvest permit provisions; LAC Title 73, Part I.","handbook":"","hbref":""},{"q":"In Louisiana, which class of Commercial Driver License is required to operate a combination of vehicles with a gross combination weight rating (GCWR) of 26,001 pounds or more, where the towed unit's GVWR is more than 10,000 pounds?","options":["Class B","Class A","Class C","Class D"],"answer":1,"explanation":"Louisiana R.S. 32:408 B.(2)(a) defines the Class 'A' CDL (Combination Vehicles) as permitting any combination of vehicles with a GCWR of 26,001 pounds or more, provided the GVWR of the unit(s) being towed is in excess of 10,000 pounds. Source: Louisiana CDL Manual (OMV), classes section.","handbook":"","hbref":""},{"q":"Under Louisiana rules, a Class B CDL authorizes operation of any single vehicle with a GVWR of 26,001 pounds or more, optionally towing a unit not in excess of what weight?","options":["5,000 pounds GVWR","15,000 pounds GVWR","26,001 pounds GVWR","10,000 pounds GVWR"],"answer":3,"explanation":"Louisiana R.S. 32:408 B.(2)(b) defines the Class 'B' CDL (Heavy Straight Vehicle) as any single vehicle with a GVWR of 26,001 or more pounds, or such a vehicle towing a vehicle not in excess of 10,000 pounds GVWR. Towing more than 10,000 lbs moves the driver into Class A. Source: Louisiana CDL Manual (OMV).","handbook":"","hbref":""},{"q":"A Louisiana driver operates a single straight truck rated at 24,000 pounds GVWR that is placarded for hazardous materials. Which CDL class is the minimum required?","options":["Class B","Class A","Class D","Class C"],"answer":3,"explanation":"Louisiana R.S. 32:408 B.(2)(c) defines the Class 'C' CDL (Light Vehicle) for single vehicles less than 26,001 pounds GVWR that either are designed to carry 16 or more passengers (including the driver) or are used to transport placarded amounts of hazardous materials. A 24,000-lb HazMat-placarded straight truck needs Class C plus the H endorsement. Source: Louisiana CDL Manual (OMV).","handbook":"","hbref":""},{"q":"On a Louisiana CDL, which endorsement code authorizes the operation of double and triple trailers?","options":["N","X","T","H"],"answer":2,"explanation":"Louisiana R.S. 32:408(3) lists the 'T' endorsement for Double/Triple Trailers. (N = Tank, H = Hazardous Materials, X = combined Tank and HazMat.) Source: Louisiana CDL Manual (OMV), endorsements section.","handbook":"","hbref":""},{"q":"What is the minimum age to obtain a Louisiana CDL for INTRASTATE (within-state) driving only?","options":["21 years old","19 years old","17 years old","18 years old"],"answer":3,"explanation":"Louisiana R.S. 32:408 lists the age requirement for Class A, B, and C CDLs as 18 years or above for intrastate and 21 years or above for interstate. Source: Louisiana CDL Manual (OMV), classes section.","handbook":"","hbref":""},{"q":"A 19-year-old holds a valid Louisiana CDL. Which operation are they permitted to perform?","options":["Drive a CMV in interstate commerce","Transport placarded hazardous materials","Drive a CMV in intrastate commerce within Louisiana","Hold an H (HazMat) endorsement"],"answer":2,"explanation":"Louisiana sets the CDL age at 18 for intrastate but 21 for interstate, and the H (HazMat) endorsement is 'issued only to persons 21 years of age or above.' A 19-year-old may drive intrastate only and cannot get a HazMat endorsement. Source: Louisiana CDL Manual (OMV), R.S. 32:408.","handbook":"","hbref":""},{"q":"In Louisiana, the H (Hazardous Materials) endorsement may be issued only to applicants who are at least what age?","options":["18 years old","25 years old","19 years old","21 years old"],"answer":3,"explanation":"The Louisiana CDL Manual's endorsement list (R.S. 32:408(3)) states the 'H' Hazardous Materials endorsement is 'issued only to persons 21 years of age or above,' consistent with the interstate-only nature of placarded HazMat transport. Source: Louisiana CDL Manual (OMV).","handbook":"","hbref":""},{"q":"Before being issued a Louisiana HazMat (H) endorsement, an applicant must clear which additional screening?","options":["A vision-only re-examination","A 36-hour classroom defensive-driving course","A road test in a tanker vehicle","A TSA security threat assessment including fingerprinting and a background check"],"answer":3,"explanation":"The Louisiana CDL Manual (Section 1.2.6) states a HazMat endorsement requires submitting fingerprints and a background check; an applicant is denied if deemed a security threat by the Transportation Security Administration (TSA). The fingerprint background check must be within the most recent 180 days. Source: Louisiana CDL Manual (OMV), TSA / 49 CFR 1572.","handbook":"","hbref":""},{"q":"An applicant for a Louisiana HazMat endorsement will be DENIED the endorsement under which of the following conditions?","options":["They have fewer than two years of CDL experience","They are under 25 years of age","They are not a lawful permanent resident of the United States","They do not hold a Class A CDL"],"answer":2,"explanation":"Per Louisiana CDL Manual Section 1.2.6, you will be denied or lose the HazMat endorsement if you are not a lawful permanent resident of the U.S., renounce U.S. citizenship, are wanted/under indictment or convicted of certain felonies, have been adjudicated a mental defective, or are deemed a TSA security threat. Source: Louisiana CDL Manual (OMV); TSA HME rule.","handbook":"","hbref":""},{"q":"A Louisiana tank vehicle (N) endorsement is required when a vehicle needing a Class A or B CDL hauls liquids/gases in a permanently mounted cargo tank rated at what minimum capacity?","options":["119 gallons or more","100 gallons or more","500 gallons or more","1,000 gallons or more"],"answer":0,"explanation":"The Louisiana CDL Manual (Section 8, Tank Vehicles) states a tank endorsement is required if your vehicle needs a Class A or B CDL and you haul a liquid or gas in a permanently mounted cargo tank rated at 119 gallons or more, OR a portable tank rated at 1,000 gallons or more. Source: Louisiana CDL Manual (OMV).","handbook":"","hbref":""},{"q":"For the Louisiana tank (N) endorsement, a PORTABLE tank triggers the endorsement requirement when rated at what minimum capacity?","options":["119 gallons or more","1,000 gallons or more","660 gallons or more","2,000 gallons or more"],"answer":1,"explanation":"The Louisiana CDL Manual specifies the tank endorsement applies to a portable tank rated at 1,000 gallons or more (versus 119 gallons or more for a permanently mounted cargo tank). Source: Louisiana CDL Manual (OMV), Tank Vehicles section.","handbook":"","hbref":""},{"q":"Which endorsement code on a Louisiana CDL represents the COMBINATION of Tank Vehicles AND Hazardous Materials?","options":["T","X","N","H"],"answer":1,"explanation":"Louisiana R.S. 32:408(3) lists the 'X' endorsement as the combination of Tank Vehicles and Hazardous Materials. (N = Tank only, H = HazMat only, T = Doubles/Triples.) Source: Louisiana CDL Manual (OMV), endorsements section.","handbook":"","hbref":""},{"q":"Which Louisiana CDL endorsement is required specifically to drive a school bus?","options":["S","P","T","N"],"answer":0,"explanation":"Louisiana R.S. 32:408(3) lists the 'S' endorsement for School Bus. The 'P' (Passenger) endorsement covers buses generally and is also required, but the school-bus-specific endorsement is 'S.' Source: Louisiana CDL Manual (OMV), endorsements section.","handbook":"","hbref":""},{"q":"Under the federal standard applied in Louisiana, after a Commercial Learner Permit (CLP) is first issued, the holder must wait a minimum of how long before being eligible to take the CDL skills test?","options":["14 days","7 days","30 days","10 days"],"answer":0,"explanation":"Per 49 CFR 383.25(e), adopted in Louisiana, a CLP holder is not eligible to take the CDL skills test within the first 14 days after initial issuance of the CLP. This 14-day hold gives time for behind-the-wheel practice. Source: 49 CFR 383.25(e); Louisiana OMV CDL requirements.","handbook":"","hbref":""},{"q":"While practicing in a CMV on a Louisiana CLP, the permit holder must at all times be accompanied by whom?","options":["Any licensed Class E driver over age 21","A CDL holder with the proper class and endorsements seated in the front seat","A certified third-party examiner only","No supervision is required once the knowledge test is passed"],"answer":1,"explanation":"Louisiana OMV CLP rules (per 49 CFR 383.25) require the CLP holder to be accompanied by a valid CDL holder who holds the proper class and endorsements, seated in the front seat (cab) of the vehicle, during all behind-the-wheel operation. Source: Louisiana OMV New CDL page; 49 CFR 383.25.","handbook":"","hbref":""},{"q":"In addition to first-time Class A and Class B applicants, ELDT is required in Louisiana for first-time applicants seeking which endorsements?","options":["Hazardous Materials (H), Passenger (P), and School Bus (S)","Tank (N) and Doubles/Triples (T) only","Motorcycle (M) and Passenger (P) only","All endorsements without exception"],"answer":0,"explanation":"FMCSA ELDT (effective Feb 7, 2022, applied in Louisiana) covers first-time applicants for a Class A or B CDL, upgrades from B to A, and first-time applicants for the Hazardous Materials (H), Passenger (P), and School Bus (S) endorsements. Tank (N) and Doubles/Triples (T) are not ELDT-covered endorsements. Source: FMCSA Training Provider Registry / ELDT Applicability.","handbook":"","hbref":""},{"q":"In Louisiana, what is the maximum blood alcohol concentration (BAC) a driver may have while operating a commercial motor vehicle (CMV) before being considered legally intoxicated for CDL purposes?","options":["0.04 percent","0.08 percent","0.02 percent","0.10 percent"],"answer":0,"explanation":"Louisiana law sets the CMV BAC limit at 0.04 percent, half the 0.08 percent limit for non-commercial drivers. A CDL holder operating a CMV at 0.04 percent or greater is considered under the influence. Source: La. R.S. 32:414.2 and the Louisiana CDL Manual (Section 1.2, Disqualifications).","handbook":"","hbref":""},{"q":"By holding a Louisiana CDL and operating a commercial vehicle, a driver is automatically deemed to have agreed to do what?","options":["Submit to chemical testing of breath, blood, or urine when lawfully requested","Carry a copy of the federal hours-of-service log at all times","Waive the right to a court hearing on any traffic ticket","Pay all toll fees electronically rather than in cash"],"answer":0,"explanation":"Under Louisiana's implied-consent law, anyone operating a CMV is deemed to have consented to a chemical test of breath, blood, or urine to determine alcohol or drug presence when an officer has reasonable cause. Source: La. R.S. 32:414.2 (implied consent) and the Louisiana CDL Manual.","handbook":"","hbref":""},{"q":"How long is a Louisiana CDL holder disqualified for a first major offense, such as operating a CMV with a BAC of 0.04 percent or more?","options":["1 year","60 days","6 months","3 years"],"answer":0,"explanation":"A first major offense (including DUI, BAC of 0.04 percent or greater in a CMV, refusing a test, or leaving the scene) results in a 1-year disqualification under Louisiana law, which mirrors 49 CFR 383.51. Source: La. R.S. 32:414.2 and the Louisiana CDL Manual.","handbook":"","hbref":""},{"q":"If a Louisiana CDL holder commits a first major offense while operating a CMV that is placarded for hazardous materials, the disqualification period increases to:","options":["3 years","1 year","2 years","Lifetime"],"answer":0,"explanation":"When a first major offense occurs in a CMV required to be placarded for hazardous materials, the disqualification is extended from 1 year to 3 years. Source: La. R.S. 32:414.2 and 49 CFR 383.51, as adopted in the Louisiana CDL Manual.","handbook":"","hbref":""},{"q":"What is the disqualification period for a Louisiana CDL holder who is convicted of a second major offense (for example, a second DUI in a CMV)?","options":["Lifetime disqualification","10-year disqualification","5-year disqualification","3-year disqualification"],"answer":0,"explanation":"A second conviction for any combination of major offenses results in a lifetime CDL disqualification in Louisiana, consistent with 49 CFR 383.51. (A 10-year minimum reinstatement may be available under federal rules.) Source: La. R.S. 32:414.2 and the Louisiana CDL Manual.","handbook":"","hbref":""},{"q":"A Louisiana CDL holder lawfully asked to submit to a chemical test refuses. What is the consequence for the CDL?","options":["Disqualification for at least 1 year, the same as a DUI conviction","A warning only on the first refusal","Disqualification for 60 days","No CDL consequence if criminal charges are dismissed"],"answer":0,"explanation":"Refusing a chemical test under Louisiana's implied-consent law results in a CDL disqualification of at least 1 year, the same as a major offense, and this applies regardless of the outcome of any criminal case. Source: La. R.S. 32:414.2 and the Louisiana CDL Manual.","handbook":"","hbref":""},{"q":"Which of the following is classified as a 'serious traffic violation' for a Louisiana CDL holder?","options":["Speeding 15 mph or more over the posted limit","Speeding 5 mph over the posted limit","A parking violation in a commercial zone","Driving with an expired registration sticker"],"answer":0,"explanation":"Speeding 15 mph or more over the posted limit is one of the serious traffic violations listed for CDL holders. Others include reckless driving, improper or erratic lane changes, and following too closely. Source: 49 CFR 383.51 as adopted in the Louisiana CDL Manual.","handbook":"","hbref":""},{"q":"How long is a Louisiana CDL holder disqualified for being convicted of TWO serious traffic violations within a 3-year period?","options":["60 days","30 days","120 days","1 year"],"answer":0,"explanation":"A second serious traffic violation within 3 years (in separate incidents) results in a 60-day disqualification under Louisiana law, matching 49 CFR 383.51. Source: La. R.S. 32:414.2 and the Louisiana CDL Manual.","handbook":"","hbref":""},{"q":"How long is a Louisiana CDL holder disqualified for being convicted of THREE serious traffic violations within a 3-year period?","options":["120 days","60 days","90 days","180 days"],"answer":0,"explanation":"A third serious traffic violation within 3 years (in separate incidents) results in a 120-day disqualification, served consecutively to any prior 60-day period. Source: 49 CFR 383.51 as adopted by the Louisiana CDL Manual and La. R.S. 32:414.2.","handbook":"","hbref":""},{"q":"Using a hand-held mobile telephone while driving a commercial motor vehicle in Louisiana is treated as what kind of offense for CDL purposes?","options":["A serious traffic violation that counts toward disqualification","A non-moving violation with no CDL impact","An automatic 1-year major offense","A violation only if an accident results"],"answer":0,"explanation":"Using a hand-held phone or texting while operating a CMV is a serious traffic violation that counts toward the 2-in-3-years (60-day) and 3-in-3-years (120-day) disqualification thresholds. Source: 49 CFR 383.51 / 392.82 as adopted in the Louisiana CDL Manual.","handbook":"","hbref":""},{"q":"Texting while driving a CMV is also a serious violation. The federal civil penalty a CMV driver may face for texting, as referenced in the CDL rules applied in Louisiana, can be as high as approximately:","options":["$2,750","$500","$1,000","$10,000"],"answer":0,"explanation":"Beyond CDL disqualification, a CMV driver who texts while driving faces a federal civil penalty of up to about $2,750. Source: 49 CFR 392.80/392.82, referenced in the Louisiana CDL Manual.","handbook":"","hbref":""},{"q":"What is the minimum disqualification for a Louisiana CDL holder's FIRST conviction of a railroad-highway grade crossing violation?","options":["60 days","30 days","120 days","1 year"],"answer":0,"explanation":"A first railroad-highway grade crossing violation (such as failing to stop or not having sufficient space to clear) carries a minimum 60-day disqualification in Louisiana. Source: 49 CFR 383.51 as adopted by the Louisiana CDL Manual.","handbook":"","hbref":""},{"q":"A Louisiana CDL holder commits a SECOND railroad-grade crossing violation within a 3-year period. The minimum disqualification is:","options":["120 days","60 days","90 days","1 year"],"answer":0,"explanation":"A second railroad-grade crossing violation within 3 years results in a minimum 120-day disqualification. Source: 49 CFR 383.51 as adopted by the Louisiana CDL Manual.","handbook":"","hbref":""},{"q":"A Louisiana CDL holder commits a THIRD railroad-grade crossing violation within a 3-year period. The minimum disqualification is:","options":["1 year","120 days","180 days","3 years"],"answer":0,"explanation":"A third railroad-grade crossing violation within 3 years results in a minimum 1-year disqualification. Source: 49 CFR 383.51 as adopted by the Louisiana CDL Manual.","handbook":"","hbref":""},{"q":"What is the disqualification period for a Louisiana CDL holder's FIRST conviction of violating an out-of-service order while operating a CMV (non-hazmat, non-passenger)?","options":["At least 180 days, up to 1 year","At least 30 days","At least 60 days","Lifetime"],"answer":0,"explanation":"A first out-of-service (OOS) order violation results in a disqualification of at least 180 days and up to 1 year for a standard CMV. Source: La. R.S. 32:414.2 and 49 CFR 383.51 as adopted in the Louisiana CDL Manual.","handbook":"","hbref":""},{"q":"A Louisiana CDL holder is convicted of a SECOND out-of-service order violation within a 10-year period. The disqualification range is:","options":["2 to 5 years","1 to 2 years","60 to 120 days","Lifetime"],"answer":0,"explanation":"A second out-of-service order violation within 10 years results in a disqualification of 2 to 5 years for a standard CMV. Source: La. R.S. 32:414.2 and 49 CFR 383.51 as adopted in the Louisiana CDL Manual.","handbook":"","hbref":""},{"q":"For a CDL holder hauling hazardous materials requiring placards, a FIRST out-of-service order violation carries a disqualification of:","options":["At least 180 days, up to 2 years","At least 30 days, up to 60 days","Exactly 1 year","Lifetime"],"answer":0,"explanation":"When the OOS violation occurs while transporting placarded hazardous materials or while operating a vehicle designed to carry 16 or more passengers, the first-offense disqualification is at least 180 days and up to 2 years. Source: 49 CFR 383.51 as adopted in the Louisiana CDL Manual.","handbook":"","hbref":""},{"q":"Which of the following best describes how Louisiana counts serious traffic violations toward CDL disqualification?","options":["Convictions in separate incidents within a 3-year period","Only convictions occurring on the same day","All convictions within a 1-year period only","Only violations committed while off duty"],"answer":0,"explanation":"Serious traffic violation disqualifications (60 days for a second, 120 days for a third) are based on convictions arising from separate incidents within a 3-year period. Source: 49 CFR 383.51 as adopted by the Louisiana CDL Manual and La. R.S. 32:414.2.","handbook":"","hbref":""},{"q":"A driver causes a fatality while operating a CMV and is convicted of a traffic offense (such as negligent or reckless operation) connected to the death. For CDL purposes in Louisiana, this is treated as:","options":["A serious traffic violation counting toward disqualification","A non-CDL administrative matter only","An automatic lifetime disqualification","A railroad-crossing violation"],"answer":0,"explanation":"A traffic-control-law violation committed in connection with a fatal accident is included on the serious traffic violation list, counting toward the 60-day and 120-day thresholds. (Manslaughter or a felony with a CMV is a separate 1-year major offense.) Source: 49 CFR 383.51 as adopted in the Louisiana CDL Manual.","handbook":"","hbref":""},{"q":"A Louisiana CDL holder uses a CMV to commit a felony involving the manufacture or distribution of a controlled substance. The disqualification is:","options":["Lifetime, with no reinstatement available","1 year","3 years","60 days"],"answer":0,"explanation":"Using a CMV in the commission of a felony involving controlled-substance manufacturing, distribution, or dispensing results in a lifetime disqualification with no possibility of reinstatement, unlike other major offenses. Source: La. R.S. 32:414.2 and 49 CFR 383.51 as adopted in the Louisiana CDL Manual.","handbook":"","hbref":""},{"q":"On a Louisiana interstate or controlled-access highway, what is the maximum posted speed limit set by statute (unless a different limit is posted)?","options":["60 mph","65 mph","70 mph","75 mph"],"answer":2,"explanation":"Louisiana RS 32:61 sets the statutory maximum at 70 mph on interstate or controlled-access highways unless otherwise posted. Source: Louisiana RS 32:61; Louisiana DOTD 'Speed Limit' brochure.","handbook":"","hbref":""},{"q":"Under Louisiana law, what is the statutory speed limit on a multi-lane DIVIDED highway that is not an interstate, unless otherwise posted?","options":["55 mph","65 mph","70 mph","60 mph"],"answer":1,"explanation":"RS 32:61 provides that the limit on any Louisiana highway should not exceed 55 mph unless it is a multi-lane divided highway (65 mph) or an interstate/controlled-access highway (70 mph). Source: Louisiana RS 32:61; Louisiana DOTD 'Speed Limit' brochure.","handbook":"","hbref":""},{"q":"On a Louisiana interstate, how does the maximum speed limit for a tractor-trailer compare to the limit for a passenger car?","options":["Trucks must stay 10 mph below the posted limit","Trucks are capped 5 mph lower than cars","Trucks have the same maximum limit as cars","Trucks are limited to 55 mph statewide"],"answer":2,"explanation":"Louisiana has no separate lower interstate speed limit for trucks; the former truck-speed statute RS 32:62 was repealed (Acts 2010, No. 81) and a later '10 mph below' proposal was not enacted. The RS 32:61 limits apply to all vehicles unless otherwise posted. Source: Louisiana RS 32:61; RS 32:62 (repealed 2010).","handbook":"","hbref":""},{"q":"A Louisiana bus driver approaches a railroad crossing that requires a stop. Where must the bus be stopped relative to the nearest rail?","options":["Between 5 and 25 feet","Between 15 and 50 feet","Between 50 and 100 feet","Between 10 and 40 feet"],"answer":1,"explanation":"The Louisiana CDL Manual states a bus must stop between 15 and 50 feet before a railroad crossing, then look and listen in both directions before crossing. Source: Louisiana CDL Manual, Sec. 4.3.5 (Railroad-highway Crossing Stops).","handbook":"","hbref":""},{"q":"A driver hauling placarded hazardous materials in Louisiana reaches a non-exempt railroad crossing. At what distance from the nearest rail must the vehicle stop?","options":["Not closer than 15 feet and not more than 50 feet","Not closer than 10 feet and not more than 25 feet","Not closer than 25 feet and not more than 75 feet","Exactly 50 feet, then creep forward"],"answer":0,"explanation":"Buses, school buses, and placarded vehicles must stop the vehicle within 50 feet but not less than 15 feet from the nearest rail, then look and listen before crossing. Source: Louisiana CDL Manual, Sec. 13.1.8 (Railroad Crossing procedures).","handbook":"","hbref":""},{"q":"Under Louisiana RS 32:80, a driver meeting or overtaking a stopped school bus with its visual signals operating must stop no closer than what distance from the bus?","options":["10 feet","20 feet","30 feet","50 feet"],"answer":2,"explanation":"RS 32:80 requires drivers approaching from any direction to stop not less than 30 feet from a school bus that is stopped to load or discharge children while its visual signals are activated, and to remain stopped until the bus moves or the signals stop. Source: Louisiana RS 32:80.","handbook":"","hbref":""},{"q":"On a four-lane DIVIDED highway with separate roadways in Louisiana, a school bus stops on the OPPOSITE roadway to discharge children. What must a driver traveling the other direction do?","options":["Stop and wait until the signals turn off","Stop only if children are crossing","Need not stop; the divided-highway exception applies","Slow to 15 mph but need not stop"],"answer":2,"explanation":"RS 32:80 provides that a driver need not stop for a school bus on a different roadway of a divided highway with separate roadways (or a controlled-access highway where the bus is in a loading zone). Source: Louisiana RS 32:80.","handbook":"","hbref":""},{"q":"In Louisiana, a two-lane road with one lane each way plus a center two-way left-turn lane has a stopped school bus loading children. For the school-bus stopping law, this road is treated as:","options":["A divided highway, so oncoming traffic need not stop","NOT a divided highway, so oncoming traffic must stop","A controlled-access highway exempt from stopping","A one-way street with no stopping duty"],"answer":1,"explanation":"RS 32:80 expressly states that a highway with one lane in each direction and a dedicated two-way left-turn lane shall NOT be considered a divided highway with separate roadways, so oncoming drivers must still stop. Source: Louisiana RS 32:80.","handbook":"","hbref":""},{"q":"Louisiana's Move Over law (RS 32:125) applies when you approach a STOPPED emergency vehicle displaying visual signals on a highway with two or more lanes in your direction. What is the FIRST required action?","options":["Come to a complete stop in your lane","Change into a lane not adjacent to the parked vehicle, if possible","Sound your horn and maintain speed","Pull onto the right shoulder and stop"],"answer":1,"explanation":"RS 32:125 requires drivers on a road with two or more lanes in the same direction to yield by making a lane change into a lane not adjacent to the parked emergency vehicle, when possible with due regard to safety and traffic. Source: Louisiana RS 32:125.","handbook":"","hbref":""},{"q":"Under Louisiana's Move Over law, if you CANNOT safely change lanes away from a stopped emergency vehicle (or you are on a two-lane road), what must you do?","options":["Stop completely until the scene clears","Maintain your normal speed and steer left","Slow to a reasonably safe speed for conditions","Accelerate past to clear the area quickly"],"answer":2,"explanation":"RS 32:125 provides that if a lane change is not possible or you are on a two-lane road, you must slow to a reasonably safe speed for the road conditions while passing the parked emergency vehicle. Source: Louisiana RS 32:125.","handbook":"","hbref":""},{"q":"In addition to police, fire, and EMS, the Louisiana Move Over law (RS 32:125) protects which other stopped vehicles displaying warning lights?","options":["Only marked law-enforcement units","Tow trucks/wreckers and vehicles using flashing amber/yellow lights","Only ambulances and fire apparatus","Mail-delivery vehicles only"],"answer":1,"explanation":"RS 32:125 covers any vehicle lawfully displaying authorized visual signals, including alternately flashing amber, yellow, or green warning lights, which extends the protection to tow trucks/wreckers and similar service vehicles. Source: Louisiana RS 32:125 (amended Acts 2021, No. 78).","handbook":"","hbref":""},{"q":"Upon the immediate approach of an authorized emergency vehicle sounding a siren and showing lights, Louisiana RS 32:125 requires the driver of every other vehicle to:","options":["Speed up to clear the intersection ahead","Move to the center lane and slow down","Drive to the right edge or curb, clear of any intersection, and stop","Stop immediately wherever the vehicle is, including in an intersection"],"answer":2,"explanation":"RS 32:125 requires yielding the right-of-way by driving to a position parallel and as close as possible to the right-hand edge or curb, clear of any intersection, and stopping until the emergency vehicle passes. Source: Louisiana RS 32:125.","handbook":"","hbref":""},{"q":"On a Louisiana multi-lane highway, a slow commercial vehicle that is impeding a faster vehicle wishing to pass in the left lane must, under RS 32:71:","options":["Maintain position until the next exit","Expeditiously merge into the right lane","Slow further to let the vehicle pass on the right","Move onto the left shoulder"],"answer":1,"explanation":"RS 32:71 prohibits using the left lane to impede or block an overtaking vehicle; the slower vehicle must expeditiously merge into the right lane. First-offense fine is $150. Source: Louisiana RS 32:71.","handbook":"","hbref":""},{"q":"When a Louisiana CMV is stopped on the shoulder of a one-way or divided highway, where must the three emergency warning devices (triangles) be placed?","options":["10 feet, 100 feet, and 200 feet toward approaching traffic","10 feet, 50 feet, and 150 feet toward approaching traffic","25 feet, 100 feet, and 250 feet toward approaching traffic","15 feet, 75 feet, and 200 feet toward approaching traffic"],"answer":0,"explanation":"The Louisiana CDL Manual (adopting the federal rule) requires placing warning devices at 10 feet, 100 feet, and 200 feet toward approaching traffic when stopped on or by a one-way or divided highway. Source: Louisiana CDL Manual, Sec. 2.5 (Warning Devices).","handbook":"","hbref":""},{"q":"After stopping a CMV on a roadway or shoulder in Louisiana, within how many minutes must the driver put out the emergency warning devices?","options":["5 minutes","10 minutes","15 minutes","30 minutes"],"answer":1,"explanation":"The Louisiana CDL Manual states that if you must stop on a road or shoulder you must put out your emergency warning devices within 10 minutes. Source: Louisiana CDL Manual, Sec. 2.5 (Warning Devices).","handbook":"","hbref":""},{"q":"On a Louisiana two-lane road carrying traffic in both directions, where should a stopped CMV place its warning triangles ahead of and behind the vehicle?","options":["200 feet ahead and 200 feet behind","100 feet ahead and 100 feet behind","50 feet ahead and 100 feet behind","10 feet ahead and 10 feet behind"],"answer":1,"explanation":"On a two-way/undivided road the Louisiana CDL Manual requires a device within 10 feet of the vehicle and devices 100 feet ahead and 100 feet behind it. Source: Louisiana CDL Manual, Sec. 2.5 (Warning Devices).","handbook":"","hbref":""},{"q":"A Louisiana school bus approaches a railroad crossing. The CDL Manual recommends activating the bus hazard warning lights at about what distance before the crossing?","options":["50 feet","100 feet","200 feet","500 feet"],"answer":2,"explanation":"The Louisiana CDL Manual's school-bus procedures recommend activating hazard lights approximately 200 feet before the crossing, then stopping 15 to 50 feet from the nearest rail. Source: Louisiana CDL Manual, Sec. 10.4.3 (Recommended Procedures).","handbook":"","hbref":""},{"q":"A Louisiana bus reaches a drawbridge that has NO signal light and NO traffic-control attendant. The driver must stop at least how far before the draw of the bridge?","options":["15 feet","30 feet","50 feet","100 feet"],"answer":2,"explanation":"The Louisiana CDL Manual requires stopping at least 50 feet before the draw of a drawbridge that has no signal light or traffic-control attendant, and confirming the draw is fully closed before crossing. Source: Louisiana CDL Manual, Sec. 4.3.6 (Drawbridges).","handbook":"","hbref":""},{"q":"If a Louisiana driver commits a railroad-highway grade crossing violation while operating a CMV that is PLACARDED for hazardous materials, the minimum CDL disqualification is:","options":["60 days","120 days","1 year","3 years"],"answer":3,"explanation":"The Louisiana CDL Manual states you will lose your CDL for at least three years if a railroad-crossing violation occurs while operating a CMV placarded for hazardous materials (versus 60/120 days for non-placarded serious crossing violations). Source: Louisiana CDL Manual, Sec. 1.2.5 (Railroad-highway Grade Crossing Violations).","handbook":"","hbref":""},{"q":"Without an oversize permit from Louisiana DOTD, what is the maximum legal WIDTH for a commercial vehicle and load on Louisiana highways?","options":["8 feet 0 inches","8 feet 6 inches","9 feet 0 inches","10 feet 0 inches"],"answer":1,"explanation":"Louisiana's legal size limits are 8 feet 6 inches wide, 13 feet 6 inches high, and 80,000 pounds; loads exceeding these require a DOTD oversize/overweight permit, with permitted movement generally restricted to sunrise to sunset. Source: Louisiana DOTD Weights & Standards; LAC Title 73, Part I, Chapter 3.","handbook":"","hbref":""},{"q":"Which agency issues Commercial Driver's Licenses (CDLs) in Louisiana?","options":["The Louisiana Office of Motor Vehicles (OMV)","The Louisiana State Police","The Federal Motor Carrier Safety Administration (FMCSA)","The Louisiana Department of Transportation and Development (DOTD)"],"answer":0,"explanation":"CDLs in Louisiana are issued by the Office of Motor Vehicles (OMV), a part of the Louisiana Department of Public Safety. FMCSA sets federal standards but does not issue licenses; DOTD handles roads and oversize/overweight permits, not CDLs. Source: Louisiana OMV CDL pages (expresslane.la.gov).","handbook":"","hbref":""},{"q":"Before being licensed, every Louisiana CDL applicant must first obtain which credential?","options":["A Commercial Learner's Permit (CLP)","A federal interstate operating authority number","A DOTD oversize/overweight permit","A temporary chauffeur's endorsement"],"answer":0,"explanation":"In Louisiana you must hold a Commercial Learner's Permit (CLP) before you can take the CDL skills test and be licensed. The CLP lets you practice on public roads while accompanied by a CDL holder. Source: Louisiana OMV 'New CDL' page.","handbook":"","hbref":""},{"q":"How long must a Louisiana CLP holder wait after the permit is first issued before becoming eligible to take the CDL skills test?","options":["14 days","30 days","10 days","60 days"],"answer":0,"explanation":"Louisiana applies the federal 14-day hold: a CLP holder is not eligible to take the CDL skills test during the first 14 days after the initial issuance of the CLP. Source: Louisiana OMV 'New CDL' page (49 CFR 383.25).","handbook":"","hbref":""},{"q":"What is the maximum period a Louisiana CLP can remain valid, counting its initial term plus the allowed extension?","options":["360 days (180 days plus one 180-day extension)","180 days with no extension allowed","1 year (365 days)","90 days plus one 90-day extension"],"answer":0,"explanation":"A Louisiana CLP is issued for up to 180 days and may be extended one time for an additional 180 days, for a maximum of 360 days. Source: Louisiana OMV 'New CDL' page (49 CFR 383.25).","handbook":"","hbref":""},{"q":"How many distinct self-certification categories must a Louisiana CDL/CLP applicant choose from regarding the type of commerce they will operate in?","options":["Four","Two","Three","Five"],"answer":0,"explanation":"There are four self-certification categories: Non-Excepted Interstate (NI), Excepted Interstate (EI), Non-Excepted Intrastate (NA), and Excepted Intrastate (EA). Source: Louisiana OMV CDL self-certification materials (49 CFR 383.71).","handbook":"","hbref":""},{"q":"Which two self-certification categories require a Louisiana CDL holder to have and maintain a Medical Examiner's Certificate on file?","options":["Non-Excepted Interstate and Non-Excepted Intrastate","Excepted Interstate and Excepted Intrastate","Non-Excepted Interstate and Excepted Interstate","Excepted Intrastate and Non-Excepted Intrastate"],"answer":0,"explanation":"Drivers who self-certify as Non-Excepted Interstate (NI) or Non-Excepted Intrastate (NA) must meet medical qualification standards and keep a current Medical Examiner's Certificate on file. The 'excepted' categories (EI, EA) are not required to. Source: Louisiana OMV self-certification materials (49 CFR 383.71).","handbook":"","hbref":""},{"q":"A driver who hauls freight only within Louisiana for hire and must meet medical standards should self-certify under which category?","options":["Non-Excepted Intrastate (NA)","Non-Excepted Interstate (NI)","Excepted Interstate (EI)","Excepted Intrastate (EA)"],"answer":0,"explanation":"Operating commercially only within Louisiana ('intrastate') and being subject to medical qualification standards is the Non-Excepted Intrastate (NA) category. Interstate categories apply to crossing state lines. Source: Louisiana OMV self-certification definitions (49 CFR 383.71).","handbook":"","hbref":""},{"q":"Which medical form must a Louisiana CDL applicant who self-certifies as non-excepted submit as proof of medical qualification?","options":["The Medical Examiner's Certificate (form MCSA-5876)","A DOTD oversize/overweight medical waiver","The CDL Supplemental Form (DPSMV2211)","A Louisiana State Police fitness affidavit"],"answer":0,"explanation":"Non-excepted CDL applicants must submit a current Medical Examiner's Certificate (form MCSA-5876) completed by a certified examiner. The DPSMV2211 is the CDL supplemental application form, not the medical certificate. Source: Louisiana OMV 'New CDL' / 'Submit CDL Medical Certificate' pages.","handbook":"","hbref":""},{"q":"Who is authorized to perform the physical examination underlying a Louisiana CDL Medical Examiner's Certificate?","options":["A medical examiner listed on the FMCSA National Registry of Certified Medical Examiners","Any licensed physician chosen by the driver","A physician employed by the Louisiana OMV","Any licensed nurse practitioner regardless of registry status"],"answer":0,"explanation":"The physical must be performed by a medical examiner certified and listed on the FMCSA National Registry of Certified Medical Examiners. Source: Louisiana OMV 'New CDL' / CDL medical certificate information pages.","handbook":"","hbref":""},{"q":"By which of the following methods does the Louisiana OMV accept a CDL Medical Examiner's Certificate?","options":["By email, fax, or standard mail to the OMV","Only by appearing in person at an OMV field office","Only through the examiner uploading it to FMCSA","Only by certified mail with a notarized cover sheet"],"answer":0,"explanation":"Louisiana OMV accepts the Medical Examiner's Certificate by email (OMV_CDL_Medical@dps.la.gov), fax, or standard mail. Source: Louisiana OMV 'Submit CDL Medical Certificate' page.","handbook":"","hbref":""},{"q":"How far in advance of a CDL holder's medical certificate expiration does the Louisiana OMV send a notice requesting a new medical examination?","options":["60 days before expiration","30 days before expiration","90 days before expiration","10 days before expiration"],"answer":0,"explanation":"The Louisiana OMV generates a notice to the customer 60 days prior to the expiration of the medical certificate on file, requesting a new examination form and certificate. Source: Louisiana OMV CDL medical certificate information page.","handbook":"","hbref":""},{"q":"If a Louisiana CDL holder does not submit a new medical certificate, when is the driver marked 'medically not certified'?","options":["10 days after the medical certificate on file expires","Immediately on the expiration date","60 days after the certificate expires","30 days after the certificate expires"],"answer":0,"explanation":"Failure to meet self-certification/medical requirements results in the driver being marked 'medically not certified' 10 days after the medical certificate on file expires; the CDL is later cancelled if non-compliance continues. Source: Louisiana OMV CDL medical certificate information page.","handbook":"","hbref":""},{"q":"The Louisiana CDL skills test is made up of which three parts, performed in order?","options":["Pre-trip inspection, basic vehicle control, and on-road driving","Written knowledge, vision screening, and on-road driving","Pre-trip inspection, hazmat handling, and air-brake bleed-down","Basic vehicle control, log-book audit, and on-road driving"],"answer":0,"explanation":"The CDL skills test in Louisiana has three parts: the pre-trip inspection, the basic vehicle control test, and the on-road driving test. Source: Louisiana CDL manual / Louisiana OMV CDL pages (49 CFR 383.113).","handbook":"","hbref":""},{"q":"Which training must a Louisiana applicant complete before taking the CDL skills test for a first Class A or Class B license?","options":["Entry-Level Driver Training (ELDT) from an FMCSA-registered provider","A Louisiana OMV defensive-driving course","A DOTD oversize-load handling course","A state-run weigh-station inspection seminar"],"answer":0,"explanation":"Entry-Level Driver Training (ELDT), provided by a school listed on FMCSA's Training Provider Registry, must be completed before taking the skills test for an initial CDL (and before the hazmat knowledge test). Source: Louisiana OMV 'New CDL' page (49 CFR Part 380 Subpart F).","handbook":"","hbref":""},{"q":"Before testing, what is the first test a Louisiana CDL applicant must pass to qualify for a Commercial Learner's Permit?","options":["The general knowledge written (knowledge) test","The on-road driving skills test","The basic vehicle control test","The pre-trip inspection test"],"answer":0,"explanation":"Applicants must pass the required written knowledge tests, starting with the general knowledge test, to be issued a CLP; the skills tests come later, after the CLP is held. Source: Louisiana CDL manual / OMV CDL pages.","handbook":"","hbref":""},{"q":"On the Louisiana CDL general knowledge written test of 50 questions, what minimum score is required to pass?","options":["80% (40 of 50 correct)","70% (35 of 50 correct)","75% (38 of 50 correct)","90% (45 of 50 correct)"],"answer":0,"explanation":"The general knowledge test has 50 multiple-choice questions, and a score of 80% (40 of 50) is required to pass, consistent with the federal CDL standard. Source: Louisiana CDL manual / OMV testing materials (49 CFR 383.135).","handbook":"","hbref":""},{"q":"What is the minimum age to obtain a Louisiana CDL limited to intrastate (within-state) operation?","options":["18 years old","21 years old","19 years old","16 years old"],"answer":0,"explanation":"An applicant must be at least 18 to hold a Louisiana CDL restricted to intrastate operation; 21 is required for interstate driving and for hazardous-materials transport. Source: Louisiana OMV CDL pages (49 CFR 383.3 / 391.11).","handbook":"","hbref":""},{"q":"What documentation, in addition to identity and the medical certificate, must a Louisiana CDL applicant provide at application?","options":["Proof of Louisiana residency (such as utility statements or a lease)","A notarized employer sponsorship letter","A DOTD route survey for intended cargo","A copy of the carrier's USDOT operating authority"],"answer":0,"explanation":"Louisiana requires proof of Louisiana residency (e.g., utility statements, lease, voter registration) along with the CDL Supplemental Form (DPSMV2211) and the Medical Examiner's Certificate. Source: Louisiana OMV 'New CDL' page.","handbook":"","hbref":""},{"q":"For how many years is a Louisiana CDL normally valid before it must be renewed?","options":["6 years","4 years","8 years","5 years"],"answer":0,"explanation":"A Louisiana CDL is generally valid for 6 years. Self-certification of operation type and a current medical certificate (for non-excepted drivers) must be maintained throughout. Source: Louisiana OMV CDL renewal information.","handbook":"","hbref":""},{"q":"Regarding the fee for the Louisiana CDL skills test conducted by a third-party examiner, which statement is the most accurate process description?","options":["Skills testing can be done through approved third-party examiners, and the exact fee is set by the tester and can change, so applicants should confirm the current amount","The skills test is always free of charge when taken at any OMV office","The skills test fee is fixed by federal law and is identical in every state","No skills test fee may ever be charged if the applicant brings their own vehicle"],"answer":0,"explanation":"Louisiana allows the skills test to be administered by approved third-party examiners, and the fee is set by the tester and is subject to change, so applicants should verify the current amount rather than rely on a fixed figure. Source: Louisiana OMV CDL pages (third-party testing program).","handbook":"","hbref":""}],"ru":{"0":{"q":"Какова максимальная допустимая ширина коммерческого транспортного средства на дорогах штата Луизиана, не считая устройств безопасности?","options":["96 inches","98 inches","102 inches","108 inches"],"explanation":"Louisiana RS 32:380 устанавливает максимальную ширину транспортного средства в 102 inches (8 feet 6 inches), не считая устройств безопасности, таких как зеркала. Источник: Louisiana Revised Statutes 32:380."},"1":{"q":"Какова максимальная допустимая высота транспортного средства в Луизиане на дорогах, не относящихся к системе межштатных автомагистралей (Interstate)?","options":["13 feet","13 feet 6 inches","14 feet","14 feet 6 inches"],"explanation":"Согласно Louisiana RS 32:381, транспортное средство вместе с грузом не может превышать 13 feet 6 inches в высоту на дорогах, не относящихся к системе Interstate. Источник: Louisiana Revised Statutes 32:381."},"2":{"q":"Какова максимальная допустимая высота транспортного средства в Луизиане для транспортного средства, эксплуатируемого исключительно на системе межштатных автомагистралей (Interstate)?","options":["13 feet 6 inches","14 feet","14 feet 6 inches","15 feet"],"explanation":"Louisiana RS 32:381 допускает максимальную высоту 14 feet для транспортного средства и его груза, эксплуатируемого исключительно на системе межштатных автомагистралей Interstate, по сравнению с 13 feet 6 inches в других местах. Источник: Louisiana Revised Statutes 32:381."},"3":{"q":"Какова максимальная допустимая длина одиночного транспортного средства (например, грузовика с цельной рамой или автобуса) в Луизиане?","options":["40 feet","45 feet","53 feet","59 feet 6 inches"],"explanation":"Louisiana RS 32:382 ограничивает одиночное транспортное средство максимальной длиной 45 feet. Источник: Louisiana Revised Statutes 32:382."},"4":{"q":"Какова максимальная допустимая длина полуприцепа в составе автопоезда «тягач-полуприцеп» в Луизиане?","options":["48 feet","53 feet","57 feet","59 feet 6 inches"],"explanation":"Louisiana RS 32:382 допускает, чтобы часть полуприцепа в составе автопоезда «тягач-полуприцеп» имела длину до 59 feet 6 inches; для этой конфигурации отдельного ограничения по общей длине автопоезда не предусмотрено. Источник: Louisiana Revised Statutes 32:382."},"5":{"q":"Насколько груз может выступать за пределы ширины кузова транспортного средства в Луизиане?","options":["Not more than 6 inches","Not more than 12 inches","Not more than 18 inches","Not more than 24 inches"],"explanation":"Louisiana RS 32:380 предусматривает, что груз не должен выступать более чем на 12 inches за пределы ширины кузова транспортного средства. Источник: Louisiana Revised Statutes 32:380."},"6":{"q":"Каков максимальный полный вес, разрешённый для любого транспортного средства или состава транспортных средств на дорогах Луизианы без разрешения?","options":["73,280 pounds","80,000 pounds","88,000 pounds","90,000 pounds"],"explanation":"Louisiana RS 32:386 ограничивает общий полный вес любого транспортного средства или состава транспортных средств величиной 80,000 pounds. Источник: Louisiana Revised Statutes 32:386."},"7":{"q":"Каков максимальный полный вес, допустимый на одиночную ось, оснащённую пневматическими шинами низкого давления, в Луизиане?","options":["18,000 pounds","20,000 pounds","22,400 pounds","34,000 pounds"],"explanation":"Louisiana RS 32:386 ограничивает одиночную ось, оснащённую пневматическими шинами низкого давления, величиной 20,000 pounds. Источник: Louisiana Revised Statutes 32:386."},"8":{"q":"Каков максимальный полный вес, допустимый на сдвоенную ось (tandem) в Луизиане согласно общему законодательному ограничению?","options":["32,000 pounds","34,000 pounds","37,000 pounds","40,000 pounds"],"explanation":"Louisiana RS 32:386 ограничивает сдвоенную ось (tandem), оснащённую пневматическими шинами низкого давления, величиной 34,000 pounds. Источник: Louisiana Revised Statutes 32:386."},"9":{"q":"Луизиана предусматривает повышенный допустимый вес на сдвоенную ось (tandem) для транспортных средств, перевозящих лесную продукцию в её естественном состоянии. Каков этот предел и где он НЕ применяется?","options":["37,000 pounds, except on the Interstate system","37,000 pounds, including the Interstate system","40,000 pounds, except on the Interstate system","34,000 pounds, applies everywhere"],"explanation":"Louisiana RS 32:386 допускает 37,000 pounds на сдвоенную ось (tandem) для транспортных средств, перевозящих лесную продукцию в её естественном состоянии, за исключением системы Interstate, где действует стандартный предел 34,000 pounds. Источник: Louisiana Revised Statutes 32:386."},"10":{"q":"Согласно Louisiana RS 32:386, ни одна шина на любой оси не может создавать нагрузку на поверхность дороги больше, чем какова величина на дюйм ширины шины?","options":["500 pounds per inch","600 pounds per inch","650 pounds per inch","700 pounds per inch"],"explanation":"Louisiana RS 32:386 устанавливает, что ни одна шина не должна создавать на поверхность дороги нагрузку больше, чем 650 pounds на inch ширины шины. Источник: Louisiana Revised Statutes 32:386."},"11":{"q":"Какую формулу Луизиана применяет в системе Interstate для определения максимального допустимого полного веса на любую группу из двух или более последовательных осей?","options":["The Federal Bridge Formula W = 500(LN/(N-1) + 12N + 36)","A flat 80,000-pound limit regardless of axle spacing","The single-axle 20,000-pound rule multiplied by axle count","A weight equal to 650 pounds times the wheelbase in inches"],"explanation":"Louisiana RS 32:386 включает Federal Bridge Formula, W = 500(LN/(N-1) + 12N + 36), для ограничения веса на последовательные оси на Interstate, где L — расстояние между осями в футах, а N — количество осей. Источник: Louisiana Revised Statutes 32:386 (Federal Bridge Formula)."},"12":{"q":"В Federal Bridge Formula, применяемой в Луизиане, W = 500(LN/(N-1) + 12N + 36), что обозначают переменные L и N?","options":["L is the load in tons; N is the number of tires","L is the distance in feet between the outer axles of a group; N is the number of axles in that group","L is the legal speed; N is the axle weight","L is the lane width; N is the number of trailers"],"explanation":"В Federal Bridge Formula в том виде, в каком её применяет Louisiana RS 32:386, L — это расстояние в футах между крайними (внешними) осями любой группы, а N — количество осей в этой группе. Источник: Louisiana Revised Statutes 32:386 / Federal Bridge Formula."},"13":{"q":"Автоперевозчик в Луизиане должен получить разрешение на негабаритный/сверхтяжёлый груз, когда транспортное средство или груз превышает законные пределы. Какое ведомство выдаёт эти разрешения?","options":["The Louisiana Office of Motor Vehicles (OMV)","The Louisiana Department of Transportation and Development (DOTD)","The Louisiana State Police only","The local parish sheriff's office"],"explanation":"Разрешения на негабаритный/сверхтяжёлый груз в Луизиане выдаются Department of Transportation and Development (DOTD) через его Truck Permit Office и электронную систему маршрутизации PERBA. Источник: Louisiana DOTD, Oversize and Overweight Truck Permits; LAC Title 73."},"14":{"q":"Когда необходимо получить разрешение Луизианы на негабаритный/сверхтяжёлый груз относительно момента перемещения?","options":["Within 24 hours after the move is completed","At any roadside weigh station during the trip","Before the oversize/overweight vehicle or load moves within or enters Louisiana","Only after a citation is issued"],"explanation":"Разрешение необходимо запросить и получить до того, как негабаритное/сверхтяжёлое транспортное средство или груз начнёт перемещаться внутри штата Луизиана или въезжать в него. Источник: Louisiana DOTD oversize/overweight permit rules; LAC Title 73, Part I."},"15":{"q":"Годовое разрешение Луизианы на негабаритный/сверхтяжёлый груз (в отличие от разового разрешения на одну поездку) действительно для движения по каким дорогам?","options":["Interstate highways only","Non-Interstate highways only","All state and Interstate highways","Parish roads only"],"explanation":"Годовые разрешения в Луизиане действительны в течение одного года и дают право на движение только по дорогам, не относящимся к системе Interstate; для перемещений по Interstate требуется разовое разрешение на одну поездку. Источник: Louisiana DOTD Annual Permits; LAC Title 73, Part I, Chapter 3."},"16":{"q":"Какую минимальную сумму залога или страхового сертификата требует Луизиана для разового разрешения на негабаритный/сверхтяжёлый груз на одну поездку?","options":["$50,000","$100,000","$250,000","$500,000"],"explanation":"Луизиана требует залог или страховой сертификат на сумму не менее $100,000 для разрешения на одну поездку (и $250,000 для годового разрешения). Источник: Louisiana DOTD oversize/overweight permit requirements."},"17":{"q":"Луизиана предлагает специальное разрешение на перевозку сельскохозяйственной продукции в её естественном состоянии, превышающей законные ограничения по осевой или полной нагрузке в период уборки урожая. Как обычно называется это разрешение?","options":["A harvest season permit","A trip lease permit","A hazmat tonnage permit","A reciprocity permit"],"explanation":"Louisiana DOTD выдаёт harvest season permits для транспортных средств, перевозящих сельскохозяйственную продукцию в её естественном состоянии, которая превышает законные ограничения по полной или осевой нагрузке; годовой сбор составляет $100. Источник: Louisiana DOTD Harvest Season / Annual Permits; LAC Title 73, Part I."},"18":{"q":"Согласно требованиям Луизианы к разрешению на перевозку сахарного тростника, какую конфигурацию осей должен иметь состав «транспортное средство и прицеп»?","options":["A minimum of four axles total","A total of six axles, with an additional load-bearing single axle on the sugarcane trailer","Only a tandem rear axle","A total of eight axles with all lift axles raised"],"explanation":"Положения Луизианы о разрешении на уборку сахарного тростника требуют в общей сложности шести осей для состава «транспортное средство и прицеп», включая дополнительную одиночную ось со сдвоенными шинами на прицепе для сахарного тростника, которая опускается и работает как несущая ось. Источник: Louisiana DOTD harvest permit provisions; LAC Title 73, Part I."},"19":{"q":"Какой класс коммерческих водительских прав (Commercial Driver License) требуется в Луизиане для управления составом транспортных средств с полной массой состава (GCWR) 26,001 pounds или более, когда GVWR буксируемого блока превышает 10,000 pounds?","options":["Class B","Class A","Class C","Class D"],"explanation":"Louisiana R.S. 32:408 B.(2)(a) определяет CDL класса «A» (составы транспортных средств) как дающие право на управление любым составом транспортных средств с GCWR 26,001 pounds или более при условии, что GVWR буксируемого(-ых) блока(-ов) превышает 10,000 pounds. Источник: Louisiana CDL Manual (OMV), раздел о классах."},"20":{"q":"Согласно правилам Луизианы, CDL класса B даёт право на управление любым одиночным транспортным средством с GVWR 26,001 pounds или более, опционально буксирующим блок весом не более какой величины?","options":["5,000 pounds GVWR","15,000 pounds GVWR","26,001 pounds GVWR","10,000 pounds GVWR"],"explanation":"Louisiana R.S. 32:408 B.(2)(b) определяет CDL класса «B» (тяжёлое одиночное транспортное средство) как любое одиночное транспортное средство с GVWR 26,001 pounds или более, либо такое транспортное средство, буксирующее транспортное средство весом не более 10,000 pounds GVWR. Буксировка более 10,000 lbs переводит водителя в Class A. Источник: Louisiana CDL Manual (OMV)."},"21":{"q":"Водитель в Луизиане управляет одиночным грузовиком с цельной рамой с расчётной массой 24,000 pounds GVWR, на котором размещены таблички (placards) опасных грузов. Какой класс CDL является минимально необходимым?","options":["Class B","Class A","Class D","Class C"],"explanation":"Louisiana R.S. 32:408 B.(2)(c) определяет CDL класса «C» (лёгкое транспортное средство) для одиночных транспортных средств с GVWR менее 26,001 pounds, которые либо рассчитаны на перевозку 16 или более пассажиров (включая водителя), либо используются для перевозки опасных грузов в количествах, требующих табличек. Грузовику с цельной рамой массой 24,000 lbs с табличками HazMat требуется Class C плюс эндорсмент H. Источник: Louisiana CDL Manual (OMV)."},"22":{"q":"Какой код эндорсмента в CDL Луизианы даёт право на управление двойными и тройными прицепами?","options":["N","X","T","H"],"explanation":"Louisiana R.S. 32:408(3) указывает эндорсмент «T» для двойных/тройных прицепов. (N = цистерна, H = опасные грузы, X = совмещённый эндорсмент цистерны и HazMat.) Источник: Louisiana CDL Manual (OMV), раздел об эндорсментах."},"23":{"q":"Каков минимальный возраст для получения CDL в Луизиане только для ВНУТРИШТАТНОГО (intrastate) вождения?","options":["21 years old","19 years old","17 years old","18 years old"],"explanation":"Louisiana R.S. 32:408 указывает возрастное требование для CDL классов A, B и C: 18 лет или старше для внутриштатных перевозок (intrastate) и 21 год или старше для межштатных (interstate). Источник: Louisiana CDL Manual (OMV), раздел о классах."},"24":{"q":"19-летний водитель имеет действующий CDL Луизианы. Какую операцию ему разрешено выполнять?","options":["Drive a CMV in interstate commerce","Transport placarded hazardous materials","Drive a CMV in intrastate commerce within Louisiana","Hold an H (HazMat) endorsement"],"explanation":"Луизиана устанавливает возраст для CDL в 18 лет для внутриштатных перевозок (intrastate), но 21 год для межштатных (interstate), а эндорсмент H (HazMat) «выдаётся только лицам в возрасте 21 года и старше». 19-летний водитель может водить только внутри штата и не может получить эндорсмент HazMat. Источник: Louisiana CDL Manual (OMV), R.S. 32:408."},"25":{"q":"В Луизиане эндорсмент H (опасные грузы) может быть выдан только заявителям, достигшим какого минимального возраста?","options":["18 years old","25 years old","19 years old","21 years old"],"explanation":"Перечень эндорсментов в Louisiana CDL Manual (R.S. 32:408(3)) устанавливает, что эндорсмент «H» на опасные грузы «выдаётся только лицам в возрасте 21 года и старше», что согласуется с тем, что перевозка опасных грузов с табличками разрешена только для межштатных (interstate) перевозок. Источник: Louisiana CDL Manual (OMV)."},"26":{"q":"Перед выдачей эндорсмента HazMat (H) в Луизиане заявитель должен пройти какую дополнительную проверку?","options":["A vision-only re-examination","A 36-hour classroom defensive-driving course","A road test in a tanker vehicle","A TSA security threat assessment including fingerprinting and a background check"],"explanation":"Louisiana CDL Manual (раздел 1.2.6) устанавливает, что для эндорсмента HazMat требуется сдача отпечатков пальцев и проверка биографических данных; заявителю отказывают, если Transportation Security Administration (TSA) признаёт его угрозой безопасности. Проверка биографических данных по отпечаткам пальцев должна быть проведена в течение последних 180 дней. Источник: Louisiana CDL Manual (OMV), TSA / 49 CFR 1572."},"27":{"q":"Заявителю на эндорсмент HazMat в Луизиане будет ОТКАЗАНО в эндорсменте при каком из следующих условий?","options":["They have fewer than two years of CDL experience","They are under 25 years of age","They are not a lawful permanent resident of the United States","They do not hold a Class A CDL"],"explanation":"Согласно разделу 1.2.6 Louisiana CDL Manual, вам будет отказано в эндорсменте HazMat или вы его потеряете, если вы не являетесь законным постоянным жителем США, отказываетесь от гражданства США, разыскиваетесь/находитесь под обвинением или осуждены за определённые тяжкие преступления, признаны психически недееспособным или признаны TSA угрозой безопасности. Источник: Louisiana CDL Manual (OMV); TSA HME rule."},"28":{"q":"Эндорсмент Луизианы на транспортное средство-цистерну (N) требуется, когда транспортное средство, для которого нужен CDL класса A или B, перевозит жидкости/газы в стационарно установленной грузовой цистерне с какой минимальной номинальной вместимостью?","options":["119 gallons or more","100 gallons or more","500 gallons or more","1,000 gallons or more"],"explanation":"Louisiana CDL Manual (раздел 8, транспортные средства-цистерны) устанавливает, что эндорсмент на цистерну требуется, если для вашего транспортного средства нужен CDL класса A или B и вы перевозите жидкость или газ в стационарно установленной грузовой цистерне с номинальной вместимостью 119 gallons или более ЛИБО в переносной цистерне с номинальной вместимостью 1,000 gallons или более. Источник: Louisiana CDL Manual (OMV)."},"29":{"q":"Для эндорсмента Луизианы на цистерну (N) ПЕРЕНОСНАЯ цистерна влечёт за собой требование об эндорсменте при какой минимальной номинальной вместимости?","options":["119 gallons or more","1,000 gallons or more","660 gallons or more","2,000 gallons or more"],"explanation":"Louisiana CDL Manual указывает, что эндорсмент на цистерну применяется к переносной цистерне с номинальной вместимостью 1,000 gallons или более (по сравнению с 119 gallons или более для стационарно установленной грузовой цистерны). Источник: Louisiana CDL Manual (OMV), раздел о транспортных средствах-цистернах."},"30":{"q":"Какой код эндорсмента в CDL Луизианы представляет СОВМЕЩЕНИЕ транспортных средств-цистерн И опасных грузов?","options":["T","X","N","H"],"explanation":"Louisiana R.S. 32:408(3) указывает эндорсмент «X» как совмещение транспортных средств-цистерн и опасных грузов. (N = только цистерна, H = только HazMat, T = двойные/тройные прицепы.) Источник: Louisiana CDL Manual (OMV), раздел об эндорсментах."},"31":{"q":"Какой эндорсмент CDL Луизианы требуется именно для управления школьным автобусом?","options":["S","P","T","N"],"explanation":"Louisiana R.S. 32:408(3) указывает эндорсмент «S» для школьного автобуса. Эндорсмент «P» (пассажирский) распространяется на автобусы в целом и также требуется, но эндорсмент именно для школьного автобуса — это «S». Источник: Louisiana CDL Manual (OMV), раздел об эндорсментах."},"32":{"q":"Согласно федеральному стандарту, применяемому в Луизиане, после первичной выдачи коммерческого ученического разрешения (CLP) его держатель должен подождать минимум сколько времени, прежде чем получит право сдавать экзамен по навыкам вождения CDL?","options":["14 days","7 days","30 days","10 days"],"explanation":"Согласно 49 CFR 383.25(e), принятому в Луизиане, держатель CLP не имеет права сдавать экзамен по навыкам вождения CDL в течение первых 14 days после первичной выдачи CLP. Этот 14-дневный период дает время для практики вождения. Источник: 49 CFR 383.25(e); Louisiana OMV CDL requirements."},"33":{"q":"Во время практики на CMV с CLP Луизианы держатель разрешения в любой момент должен сопровождаться кем?","options":["Any licensed Class E driver over age 21","A CDL holder with the proper class and endorsements seated in the front seat","A certified third-party examiner only","No supervision is required once the knowledge test is passed"],"explanation":"Правила Louisiana OMV в отношении CLP (согласно 49 CFR 383.25) требуют, чтобы держатель CLP сопровождался действующим держателем CDL, имеющим надлежащий класс и эндорсменты, сидящим на переднем сиденье (в кабине) транспортного средства во время всего управления транспортным средством. Источник: Louisiana OMV New CDL page; 49 CFR 383.25."},"34":{"q":"Помимо впервые подающих заявление на класс A и класс B, ELDT требуется в Луизиане для впервые подающих заявление на какие эндорсменты?","options":["Hazardous Materials (H), Passenger (P), and School Bus (S)","Tank (N) and Doubles/Triples (T) only","Motorcycle (M) and Passenger (P) only","All endorsements without exception"],"explanation":"FMCSA ELDT (вступившее в силу 7 февраля 2022 года, применяемое в Луизиане) распространяется на впервые подающих заявление на CDL класса A или B, переход с B на A, а также на впервые подающих заявление на эндорсменты на опасные грузы (H), пассажирский (P) и школьный автобус (S). Эндорсменты на цистерну (N) и двойные/тройные прицепы (T) не подпадают под ELDT. Источник: FMCSA Training Provider Registry / ELDT Applicability."},"35":{"q":"Каков максимальный уровень концентрации алкоголя в крови (BAC), который может быть у водителя при управлении коммерческим транспортным средством (CMV), прежде чем он будет считаться юридически в состоянии опьянения для целей CDL в Луизиане?","options":["0.04 percent","0.08 percent","0.02 percent","0.10 percent"],"explanation":"Закон Луизианы устанавливает предел BAC для CMV в 0.04 percent, что составляет половину от предела в 0.08 percent для некоммерческих водителей. Держатель CDL, управляющий CMV с BAC 0.04 percent или выше, считается находящимся под воздействием. Источник: La. R.S. 32:414.2 и Louisiana CDL Manual (раздел 1.2, Disqualifications)."},"36":{"q":"Имея CDL Луизианы и управляя коммерческим транспортным средством, водитель автоматически считается согласившимся сделать что?","options":["Submit to chemical testing of breath, blood, or urine when lawfully requested","Carry a copy of the federal hours-of-service log at all times","Waive the right to a court hearing on any traffic ticket","Pay all toll fees electronically rather than in cash"],"explanation":"Согласно закону Луизианы о подразумеваемом согласии, любой, кто управляет CMV, считается давшим согласие на химический анализ дыхания, крови или мочи для определения наличия алкоголя или наркотиков, когда у сотрудника есть разумные основания. Источник: La. R.S. 32:414.2 (implied consent) и Louisiana CDL Manual."},"37":{"q":"На какой срок дисквалифицируется держатель CDL Луизианы за первое серьёзное правонарушение (major offense), например, за управление CMV с BAC 0.04 percent или более?","options":["1 year","60 days","6 months","3 years"],"explanation":"Первое серьёзное правонарушение (включая DUI, BAC 0.04 percent или выше в CMV, отказ от теста или оставление места происшествия) влечёт за собой дисквалификацию на 1 year согласно закону Луизианы, что соответствует 49 CFR 383.51. Источник: La. R.S. 32:414.2 и Louisiana CDL Manual."},"38":{"q":"Если держатель CDL Луизианы совершает первое серьёзное правонарушение (major offense) при управлении CMV, на котором размещены таблички (placards) опасных грузов, срок дисквалификации увеличивается до:","options":["3 years","1 year","2 years","Lifetime"],"explanation":"Когда первое серьёзное правонарушение совершается в CMV, на котором должны быть размещены таблички опасных грузов, дисквалификация продлевается с 1 year до 3 years. Источник: La. R.S. 32:414.2 и 49 CFR 383.51, как принято в Louisiana CDL Manual."},"39":{"q":"Каков срок дисквалификации для держателя CDL Луизианы, осуждённого за второе серьёзное правонарушение (major offense) (например, второе DUI в CMV)?","options":["Lifetime disqualification","10-year disqualification","5-year disqualification","3-year disqualification"],"explanation":"Второе осуждение за любую комбинацию серьёзных правонарушений влечёт за собой пожизненную дисквалификацию CDL в Луизиане, что согласуется с 49 CFR 383.51. (Согласно федеральным правилам может быть доступно восстановление с минимальным сроком 10 лет.) Источник: La. R.S. 32:414.2 и Louisiana CDL Manual."},"40":{"q":"Держатель CDL Луизианы, которого на законных основаниях попросили пройти химический тест, отказывается. Каковы последствия для CDL?","options":["Disqualification for at least 1 year, the same as a DUI conviction","A warning only on the first refusal","Disqualification for 60 days","No CDL consequence if criminal charges are dismissed"],"explanation":"Отказ от химического теста согласно закону Луизианы о подразумеваемом согласии влечёт за собой дисквалификацию CDL как минимум на 1 year, так же как и за серьёзное правонарушение, и это применяется независимо от исхода любого уголовного дела. Источник: La. R.S. 32:414.2 и Louisiana CDL Manual."},"41":{"q":"Что из перечисленного классифицируется как «серьёзное нарушение правил дорожного движения» (serious traffic violation) для держателя CDL Луизианы?","options":["Speeding 15 mph or more over the posted limit","Speeding 5 mph over the posted limit","A parking violation in a commercial zone","Driving with an expired registration sticker"],"explanation":"Превышение скорости на 15 mph или более сверх установленного ограничения является одним из серьёзных нарушений правил дорожного движения, перечисленных для держателей CDL. К другим относятся неосторожное вождение, неправильная или беспорядочная смена полос и движение на слишком близком расстоянии. Источник: 49 CFR 383.51, как принято в Louisiana CDL Manual."},"42":{"q":"На какой срок дисквалифицируется держатель CDL Луизианы за осуждение по ДВУМ серьёзным нарушениям правил дорожного движения в течение 3-летнего периода?","options":["60 days","30 days","120 days","1 year"],"explanation":"Второе серьёзное нарушение правил дорожного движения в течение 3 лет (в отдельных инцидентах) влечёт за собой дисквалификацию на 60 days согласно закону Луизианы, что соответствует 49 CFR 383.51. Источник: La. R.S. 32:414.2 и Louisiana CDL Manual."},"43":{"q":"На какой срок дисквалифицируется держатель CDL Луизианы за осуждение по ТРЁМ серьёзным нарушениям правил дорожного движения в течение 3-летнего периода?","options":["120 days","60 days","90 days","180 days"],"explanation":"Третье серьёзное нарушение правил дорожного движения в течение 3 лет (в отдельных инцидентах) влечёт за собой дисквалификацию на 120 days, которая отбывается последовательно с любым предыдущим 60-дневным периодом. Источник: 49 CFR 383.51, как принято в Louisiana CDL Manual, и La. R.S. 32:414.2."},"44":{"q":"Использование ручного мобильного телефона во время управления коммерческим транспортным средством в Луизиане рассматривается как какой вид правонарушения для целей CDL?","options":["A serious traffic violation that counts toward disqualification","A non-moving violation with no CDL impact","An automatic 1-year major offense","A violation only if an accident results"],"explanation":"Использование ручного телефона или отправка текстовых сообщений во время управления CMV является серьёзным нарушением правил дорожного движения, которое учитывается при достижении порогов дисквалификации «2 за 3 года» (60 days) и «3 за 3 года» (120 days). Источник: 49 CFR 383.51 / 392.82, как принято в Louisiana CDL Manual."},"45":{"q":"Отправка текстовых сообщений во время управления CMV также является серьёзным нарушением. Федеральный гражданский штраф, который может грозить водителю CMV за отправку текстовых сообщений, согласно правилам CDL, применяемым в Луизиане, может достигать приблизительно:","options":["$2,750","$500","$1,000","$10,000"],"explanation":"Помимо дисквалификации CDL, водителю CMV, который отправляет текстовые сообщения во время вождения, грозит федеральный гражданский штраф до примерно $2,750. Источник: 49 CFR 392.80/392.82, упомянутые в Louisiana CDL Manual."},"46":{"q":"Какова минимальная дисквалификация для держателя CDL Луизианы за ПЕРВОЕ осуждение по нарушению правил проезда железнодорожного переезда (railroad-highway grade crossing)?","options":["60 days","30 days","120 days","1 year"],"explanation":"Первое нарушение правил проезда железнодорожного переезда (например, непрекращение движения или отсутствие достаточного пространства для проезда) влечёт за собой минимальную дисквалификацию на 60 days в Луизиане. Источник: 49 CFR 383.51, как принято в Louisiana CDL Manual."},"47":{"q":"Держатель CDL Луизианы совершает ВТОРОЕ нарушение правил проезда железнодорожного переезда в течение 3-летнего периода. Минимальная дисквалификация составляет:","options":["120 days","60 days","90 days","1 year"],"explanation":"Второе нарушение правил проезда железнодорожного переезда в течение 3 лет влечёт за собой минимальную дисквалификацию на 120 days. Источник: 49 CFR 383.51, как принято в Louisiana CDL Manual."},"48":{"q":"Держатель CDL Луизианы совершает ТРЕТЬЕ нарушение правил проезда железнодорожного переезда в течение 3-летнего периода. Минимальная дисквалификация составляет:","options":["1 year","120 days","180 days","3 years"],"explanation":"Третье нарушение правил проезда железнодорожного переезда в течение 3 лет влечёт за собой минимальную дисквалификацию на 1 year. Источник: 49 CFR 383.51, как принято в Louisiana CDL Manual."},"49":{"q":"Каков срок дисквалификации для держателя CDL Луизианы за ПЕРВОЕ осуждение по нарушению предписания о выводе из эксплуатации (out-of-service order) при управлении CMV (без опасных грузов, без пассажиров)?","options":["At least 180 days, up to 1 year","At least 30 days","At least 60 days","Lifetime"],"explanation":"Первое нарушение предписания о выводе из эксплуатации (OOS) влечёт за собой дисквалификацию как минимум на 180 days и до 1 year для стандартного CMV. Источник: La. R.S. 32:414.2 и 49 CFR 383.51, как принято в Louisiana CDL Manual."},"50":{"q":"Держатель CDL Луизианы осуждён за ВТОРОЕ нарушение предписания о выводе из эксплуатации (out-of-service order) в течение 10-летнего периода. Диапазон дисквалификации составляет:","options":["2 to 5 years","1 to 2 years","60 to 120 days","Lifetime"],"explanation":"Второе нарушение предписания о выводе из эксплуатации в течение 10 лет влечёт за собой дисквалификацию на 2–5 years для стандартного CMV. Источник: La. R.S. 32:414.2 и 49 CFR 383.51, как принято в Louisiana CDL Manual."},"51":{"q":"Для держателя CDL, перевозящего опасные грузы, требующие табличек (placards), ПЕРВОЕ нарушение предписания о выводе из эксплуатации (out-of-service order) влечёт за собой дисквалификацию:","options":["At least 180 days, up to 2 years","At least 30 days, up to 60 days","Exactly 1 year","Lifetime"],"explanation":"Когда нарушение OOS происходит при перевозке опасных грузов с табличками или при управлении транспортным средством, рассчитанным на перевозку 16 или более пассажиров, дисквалификация за первое правонарушение составляет как минимум 180 days и до 2 years. Источник: 49 CFR 383.51, как принято в Louisiana CDL Manual."},"52":{"q":"Что из перечисленного лучше всего описывает, как Луизиана учитывает серьёзные нарушения правил дорожного движения при дисквалификации CDL?","options":["Convictions in separate incidents within a 3-year period","Only convictions occurring on the same day","All convictions within a 1-year period only","Only violations committed while off duty"],"explanation":"Дисквалификации за серьёзные нарушения правил дорожного движения (60 days за второе, 120 days за третье) основываются на осуждениях, вытекающих из отдельных инцидентов в течение 3-летнего периода. Источник: 49 CFR 383.51, как принято в Louisiana CDL Manual, и La. R.S. 32:414.2."},"53":{"q":"Водитель становится причиной гибели человека при управлении CMV и осуждён за правонарушение в области дорожного движения (например, небрежное или неосторожное управление), связанное с этой гибелью. Для целей CDL в Луизиане это рассматривается как:","options":["A serious traffic violation counting toward disqualification","A non-CDL administrative matter only","An automatic lifetime disqualification","A railroad-crossing violation"],"explanation":"Нарушение закона о регулировании дорожного движения, совершённое в связи с ДТП со смертельным исходом, включено в перечень серьёзных нарушений правил дорожного движения и учитывается при достижении порогов в 60 days и 120 days. (Непредумышленное убийство или тяжкое преступление с использованием CMV является отдельным серьёзным правонарушением с дисквалификацией на 1 год.) Источник: 49 CFR 383.51, как принято в Louisiana CDL Manual."},"54":{"q":"Держатель CDL Луизианы использует CMV для совершения тяжкого преступления, связанного с производством или распространением контролируемого вещества. Дисквалификация составляет:","options":["Lifetime, with no reinstatement available","1 year","3 years","60 days"],"explanation":"Использование CMV при совершении тяжкого преступления, связанного с производством, распространением или сбытом контролируемых веществ, влечёт за собой пожизненную дисквалификацию без возможности восстановления, в отличие от других серьёзных правонарушений. Источник: La. R.S. 32:414.2 и 49 CFR 383.51, как принято в Louisiana CDL Manual."},"55":{"q":"На межштатной автомагистрали Луизианы или на автодороге с ограниченным доступом, какое максимальное ограничение скорости установлено законом (если не указано иное ограничение)?","options":["60 mph","65 mph","70 mph","75 mph"],"explanation":"Закон Луизианы RS 32:61 устанавливает максимальное законное ограничение в 70 mph на межштатных автомагистралях или дорогах с ограниченным доступом, если не указано иное. Источник: Louisiana RS 32:61; брошюра Louisiana DOTD 'Speed Limit'."},"56":{"q":"По закону Луизианы, какое законное ограничение скорости установлено на многополосной РАЗДЕЛЁННОЙ автодороге, не являющейся межштатной автомагистралью, если не указано иное?","options":["55 mph","65 mph","70 mph","60 mph"],"explanation":"RS 32:61 предусматривает, что ограничение на любой автодороге Луизианы не должно превышать 55 mph, за исключением случаев, когда это многополосная разделённая автодорога (65 mph) или межштатная автомагистраль / дорога с ограниченным доступом (70 mph). Источник: Louisiana RS 32:61; брошюра Louisiana DOTD 'Speed Limit'."},"57":{"q":"На межштатной автомагистрали Луизианы, как максимальное ограничение скорости для тягача с прицепом соотносится с ограничением для легкового автомобиля?","options":["Грузовики должны держаться на 10 mph ниже установленного ограничения","Для грузовиков ограничение на 5 mph ниже, чем для легковых автомобилей","Для грузовиков действует то же максимальное ограничение, что и для легковых автомобилей","Грузовики ограничены 55 mph по всему штату"],"explanation":"В Луизиане нет отдельного пониженного ограничения скорости для грузовиков на межштатных автомагистралях; прежний закон о скорости грузовиков RS 32:62 был отменён (Acts 2010, No. 81), а более позднее предложение о '10 mph ниже' не было принято. Ограничения RS 32:61 применяются ко всем транспортным средствам, если не указано иное. Источник: Louisiana RS 32:61; RS 32:62 (отменён в 2010)."},"58":{"q":"Водитель автобуса в Луизиане приближается к железнодорожному переезду, требующему остановки. Где должен быть остановлен автобус относительно ближайшего рельса?","options":["Между 5 и 25 feet","Между 15 и 50 feet","Между 50 и 100 feet","Между 10 и 40 feet"],"explanation":"Руководство Louisiana CDL Manual гласит, что автобус должен остановиться между 15 и 50 feet перед железнодорожным переездом, а затем посмотреть и прислушаться в обоих направлениях перед проездом. Источник: Louisiana CDL Manual, Sec. 4.3.5 (Railroad-highway Crossing Stops)."},"59":{"q":"Водитель, перевозящий опасные грузы с табличками-плакардами в Луизиане, достигает железнодорожного переезда, на который не распространяется исключение. На каком расстоянии от ближайшего рельса должно остановиться транспортное средство?","options":["Не ближе 15 feet и не дальше 50 feet","Не ближе 10 feet и не дальше 25 feet","Не ближе 25 feet и не дальше 75 feet","Ровно 50 feet, затем медленно продвигаться вперёд"],"explanation":"Автобусы, школьные автобусы и транспортные средства с плакардами должны остановить транспортное средство в пределах 50 feet, но не ближе 15 feet от ближайшего рельса, а затем посмотреть и прислушаться перед проездом. Источник: Louisiana CDL Manual, Sec. 13.1.8 (Railroad Crossing procedures)."},"60":{"q":"Согласно закону Луизианы RS 32:80, водитель, встречающий или обгоняющий остановившийся школьный автобус с включёнными визуальными сигналами, должен остановиться не ближе какого расстояния от автобуса?","options":["10 feet","20 feet","30 feet","50 feet"],"explanation":"RS 32:80 требует, чтобы водители, приближающиеся с любого направления, останавливались не ближе 30 feet от школьного автобуса, который остановился для посадки или высадки детей при включённых визуальных сигналах, и оставались на месте, пока автобус не тронется или сигналы не выключатся. Источник: Louisiana RS 32:80."},"61":{"q":"На четырёхполосной РАЗДЕЛЁННОЙ автодороге с отдельными проезжими частями в Луизиане школьный автобус останавливается на ПРОТИВОПОЛОЖНОЙ проезжей части для высадки детей. Что должен сделать водитель, движущийся в другом направлении?","options":["Остановиться и ждать, пока сигналы не выключатся","Остановиться только если дети переходят дорогу","Останавливаться не обязан; применяется исключение для разделённых автодорог","Снизить скорость до 15 mph, но останавливаться не обязан"],"explanation":"RS 32:80 предусматривает, что водителю не нужно останавливаться перед школьным автобусом, находящимся на другой проезжей части разделённой автодороги с отдельными проезжими частями (или на дороге с ограниченным доступом, где автобус находится в зоне посадки/высадки). Источник: Louisiana RS 32:80."},"62":{"q":"В Луизиане на двухполосной дороге с одной полосой в каждом направлении плюс центральная полоса для левого поворота в обе стороны остановился школьный автобус, осуществляющий посадку детей. Для закона об остановке перед школьным автобусом такая дорога рассматривается как:","options":["Разделённая автодорога, поэтому встречному транспорту останавливаться не нужно","НЕ разделённая автодорога, поэтому встречный транспорт должен остановиться","Дорога с ограниченным доступом, освобождённая от обязанности останавливаться","Дорога с односторонним движением без обязанности останавливаться"],"explanation":"RS 32:80 прямо указывает, что автодорога с одной полосой в каждом направлении и выделенной полосой для левого поворота в обе стороны НЕ считается разделённой автодорогой с отдельными проезжими частями, поэтому встречные водители всё равно должны остановиться. Источник: Louisiana RS 32:80."},"63":{"q":"Закон Луизианы 'Move Over' (RS 32:125) применяется, когда вы приближаетесь к ОСТАНОВИВШЕМУСЯ аварийному транспортному средству с включёнными визуальными сигналами на автодороге с двумя или более полосами в вашем направлении. Какое ПЕРВОЕ требуемое действие?","options":["Полностью остановиться на своей полосе","Перестроиться в полосу, не примыкающую к стоящему транспортному средству, если это возможно","Подать звуковой сигнал и сохранять скорость","Съехать на правую обочину и остановиться"],"explanation":"RS 32:125 требует, чтобы водители на дороге с двумя или более полосами в одном направлении уступали дорогу, перестраиваясь в полосу, не примыкающую к стоящему аварийному транспортному средству, когда это возможно с надлежащим учётом безопасности и движения. Источник: Louisiana RS 32:125."},"64":{"q":"Согласно закону Луизианы 'Move Over', если вы НЕ МОЖЕТЕ безопасно перестроиться в полосу подальше от остановившегося аварийного транспортного средства (или вы находитесь на двухполосной дороге), что вы должны сделать?","options":["Полностью остановиться, пока место происшествия не освободится","Сохранять обычную скорость и держаться левее","Снизить скорость до разумно безопасной для данных условий","Ускориться и проехать мимо, чтобы быстро покинуть зону"],"explanation":"RS 32:125 предусматривает, что если перестроение невозможно или вы находитесь на двухполосной дороге, вы должны снизить скорость до разумно безопасной для дорожных условий, проезжая мимо стоящего аварийного транспортного средства. Источник: Louisiana RS 32:125."},"65":{"q":"Помимо полиции, пожарных и скорой помощи, закон Луизианы 'Move Over' (RS 32:125) защищает какие ещё остановившиеся транспортные средства с включёнными предупредительными огнями?","options":["Только обозначенные подразделения правоохранительных органов","Эвакуаторы / тягачи и транспортные средства с мигающими янтарными/жёлтыми огнями","Только машины скорой помощи и пожарную технику","Только транспортные средства, доставляющие почту"],"explanation":"RS 32:125 распространяется на любое транспортное средство, законно использующее разрешённые визуальные сигналы, включая попеременно мигающие янтарные, жёлтые или зелёные предупредительные огни, что распространяет защиту на эвакуаторы / тягачи и аналогичные сервисные транспортные средства. Источник: Louisiana RS 32:125 (с изменениями Acts 2021, No. 78)."},"66":{"q":"При непосредственном приближении уполномоченного аварийного транспортного средства, подающего сирену и включившего огни, закон Луизианы RS 32:125 требует от водителя каждого другого транспортного средства:","options":["Ускориться, чтобы освободить перекрёсток впереди","Перестроиться в центральную полосу и снизить скорость","Подъехать к правому краю проезжей части или бордюру, вне любого перекрёстка, и остановиться","Немедленно остановиться там, где находится транспортное средство, в том числе на перекрёстке"],"explanation":"RS 32:125 требует уступить дорогу, подъехав к позиции параллельно и как можно ближе к правому краю проезжей части или бордюру, вне любого перекрёстка, и остановиться, пока аварийное транспортное средство не проедет. Источник: Louisiana RS 32:125."},"67":{"q":"На многополосной автодороге Луизианы медленное коммерческое транспортное средство, мешающее более быстрому транспортному средству, желающему совершить обгон по левой полосе, должно, согласно RS 32:71:","options":["Сохранять своё положение до следующего съезда","Незамедлительно перестроиться в правую полосу","Ещё больше снизить скорость, чтобы позволить транспортному средству обогнать справа","Съехать на левую обочину"],"explanation":"RS 32:71 запрещает использовать левую полосу для создания помех или блокирования обгоняющего транспортного средства; более медленное транспортное средство должно незамедлительно перестроиться в правую полосу. Штраф за первое нарушение составляет $150. Источник: Louisiana RS 32:71."},"68":{"q":"Когда CMV в Луизиане остановлено на обочине дороги с односторонним движением или разделённой автодороги, где должны быть размещены три аварийных предупредительных устройства (треугольники)?","options":["10 feet, 100 feet и 200 feet в сторону приближающегося транспорта","10 feet, 50 feet и 150 feet в сторону приближающегося транспорта","25 feet, 100 feet и 250 feet в сторону приближающегося транспорта","15 feet, 75 feet и 200 feet в сторону приближающегося транспорта"],"explanation":"Руководство Louisiana CDL Manual (принимающее федеральное правило) требует размещать предупредительные устройства на 10 feet, 100 feet и 200 feet в сторону приближающегося транспорта при остановке на дороге с односторонним движением или разделённой автодороге, либо рядом с ними. Источник: Louisiana CDL Manual, Sec. 2.5 (Warning Devices)."},"69":{"q":"После остановки CMV на проезжей части или обочине в Луизиане, в течение скольких минут водитель должен выставить аварийные предупредительные устройства?","options":["5 minutes","10 minutes","15 minutes","30 minutes"],"explanation":"Руководство Louisiana CDL Manual гласит, что если вы вынуждены остановиться на дороге или обочине, вы должны выставить аварийные предупредительные устройства в течение 10 minutes. Источник: Louisiana CDL Manual, Sec. 2.5 (Warning Devices)."},"70":{"q":"На двухполосной дороге Луизианы с движением в обоих направлениях, где остановившееся CMV должно размещать предупредительные треугольники впереди и позади транспортного средства?","options":["200 feet впереди и 200 feet позади","100 feet впереди и 100 feet позади","50 feet впереди и 100 feet позади","10 feet впереди и 10 feet позади"],"explanation":"На двусторонней / неразделённой дороге руководство Louisiana CDL Manual требует размещения устройства в пределах 10 feet от транспортного средства и устройств на 100 feet впереди и 100 feet позади него. Источник: Louisiana CDL Manual, Sec. 2.5 (Warning Devices)."},"71":{"q":"Школьный автобус в Луизиане приближается к железнодорожному переезду. Руководство CDL Manual рекомендует включать аварийные предупредительные огни автобуса примерно на каком расстоянии перед переездом?","options":["50 feet","100 feet","200 feet","500 feet"],"explanation":"Процедуры для школьных автобусов в руководстве Louisiana CDL Manual рекомендуют включать аварийные огни примерно за 200 feet до переезда, а затем останавливаться в 15-50 feet от ближайшего рельса. Источник: Louisiana CDL Manual, Sec. 10.4.3 (Recommended Procedures)."},"72":{"q":"Автобус в Луизиане достигает разводного моста, на котором НЕТ сигнального светофора и НЕТ дежурного по регулированию движения. Водитель должен остановиться не менее чем на каком расстоянии перед разводной частью моста?","options":["15 feet","30 feet","50 feet","100 feet"],"explanation":"Руководство Louisiana CDL Manual требует останавливаться не менее чем за 50 feet до разводной части разводного моста, на котором нет сигнального светофора или дежурного по регулированию движения, и убедиться, что разводная часть полностью закрыта, прежде чем проезжать. Источник: Louisiana CDL Manual, Sec. 4.3.6 (Drawbridges)."},"73":{"q":"Если водитель в Луизиане совершает нарушение на железнодорожном переезде в одном уровне, управляя CMV, на котором установлены ПЛАКАРДЫ опасных грузов, минимальная дисквалификация CDL составляет:","options":["60 days","120 days","1 year","3 years"],"explanation":"Руководство Louisiana CDL Manual гласит, что вы лишитесь CDL не менее чем на три года, если нарушение на железнодорожном переезде произойдёт при управлении CMV с установленными плакардами опасных грузов (против 60/120 days за серьёзные нарушения на переездах без плакардов). Источник: Louisiana CDL Manual, Sec. 1.2.5 (Railroad-highway Grade Crossing Violations)."},"74":{"q":"Без разрешения на негабаритный груз от Louisiana DOTD, какова максимальная законная ШИРИНА для коммерческого транспортного средства с грузом на автодорогах Луизианы?","options":["8 feet 0 inches","8 feet 6 inches","9 feet 0 inches","10 feet 0 inches"],"explanation":"Законные ограничения по габаритам в Луизиане составляют 8 feet 6 inches в ширину, 13 feet 6 inches в высоту и 80,000 pounds; грузы, превышающие эти значения, требуют разрешения DOTD на негабаритный/сверхтяжёлый груз, причём перемещение с таким разрешением, как правило, ограничено временем от восхода до заката. Источник: Louisiana DOTD Weights & Standards; LAC Title 73, Part I, Chapter 3."},"75":{"q":"Какое ведомство выдаёт коммерческие водительские удостоверения (CDL) в Луизиане?","options":["Louisiana Office of Motor Vehicles (OMV)","Louisiana State Police","Federal Motor Carrier Safety Administration (FMCSA)","Louisiana Department of Transportation and Development (DOTD)"],"explanation":"CDL в Луизиане выдаёт Office of Motor Vehicles (OMV), входящий в состав Louisiana Department of Public Safety. FMCSA устанавливает федеральные стандарты, но не выдаёт удостоверения; DOTD занимается дорогами и разрешениями на негабаритные/сверхтяжёлые грузы, а не CDL. Источник: страницы Louisiana OMV CDL (expresslane.la.gov)."},"76":{"q":"Прежде чем получить удостоверение, каждый заявитель на CDL в Луизиане должен сначала получить какой документ?","options":["Commercial Learner's Permit (CLP)","Федеральный номер разрешения на межштатную деятельность","Разрешение DOTD на негабаритный/сверхтяжёлый груз","Временную отметку шофёра"],"explanation":"В Луизиане вы должны иметь Commercial Learner's Permit (CLP), прежде чем сможете сдать тест навыков CDL и получить удостоверение. CLP позволяет практиковаться на дорогах общего пользования в сопровождении владельца CDL. Источник: страница Louisiana OMV 'New CDL'."},"77":{"q":"Сколько должен ждать владелец CLP в Луизиане после первой выдачи разрешения, прежде чем получить право сдавать тест навыков CDL?","options":["14 days","30 days","10 days","60 days"],"explanation":"Луизиана применяет федеральный 14-дневный период ожидания: владелец CLP не имеет права сдавать тест навыков CDL в течение первых 14 days после первоначальной выдачи CLP. Источник: страница Louisiana OMV 'New CDL' (49 CFR 383.25)."},"78":{"q":"Каков максимальный срок, в течение которого CLP в Луизиане может оставаться действительным, считая первоначальный срок плюс разрешённое продление?","options":["360 days (180 days плюс одно продление на 180 days)","180 days без права продления","1 year (365 days)","90 days плюс одно продление на 90 days"],"explanation":"CLP в Луизиане выдаётся на срок до 180 days и может быть продлён один раз на дополнительные 180 days, максимум на 360 days. Источник: страница Louisiana OMV 'New CDL' (49 CFR 383.25)."},"79":{"q":"Из скольких отдельных категорий самосертификации должен выбрать заявитель на CDL/CLP в Луизиане относительно типа коммерческой деятельности, которой он будет заниматься?","options":["Четыре","Две","Три","Пять"],"explanation":"Существует четыре категории самосертификации: Non-Excepted Interstate (NI), Excepted Interstate (EI), Non-Excepted Intrastate (NA) и Excepted Intrastate (EA). Источник: материалы Louisiana OMV CDL по самосертификации (49 CFR 383.71)."},"80":{"q":"Какие две категории самосертификации требуют, чтобы владелец CDL в Луизиане имел и поддерживал в актуальном состоянии Medical Examiner's Certificate?","options":["Non-Excepted Interstate и Non-Excepted Intrastate","Excepted Interstate и Excepted Intrastate","Non-Excepted Interstate и Excepted Interstate","Excepted Intrastate и Non-Excepted Intrastate"],"explanation":"Водители, которые самосертифицируются как Non-Excepted Interstate (NI) или Non-Excepted Intrastate (NA), должны соответствовать стандартам медицинской пригодности и иметь действующий Medical Examiner's Certificate. 'Excepted' категории (EI, EA) этого не требуют. Источник: материалы Louisiana OMV по самосертификации (49 CFR 383.71)."},"81":{"q":"Водитель, который перевозит грузы за плату только в пределах Луизианы и должен соответствовать медицинским стандартам, должен самосертифицироваться по какой категории?","options":["Non-Excepted Intrastate (NA)","Non-Excepted Interstate (NI)","Excepted Interstate (EI)","Excepted Intrastate (EA)"],"explanation":"Коммерческая деятельность только в пределах Луизианы ('intrastate') при условии соответствия стандартам медицинской пригодности относится к категории Non-Excepted Intrastate (NA). Категории interstate применяются при пересечении границ штатов. Источник: определения самосертификации Louisiana OMV (49 CFR 383.71)."},"82":{"q":"Какую медицинскую форму должен предоставить заявитель на CDL в Луизиане, самосертифицирующийся как non-excepted, в качестве доказательства медицинской пригодности?","options":["Medical Examiner's Certificate (форма MCSA-5876)","Медицинский отказ DOTD для негабаритного/сверхтяжёлого груза","CDL Supplemental Form (DPSMV2211)","Аффидевит о пригодности от Louisiana State Police"],"explanation":"Заявители на CDL категории non-excepted должны предоставить действующий Medical Examiner's Certificate (форма MCSA-5876), заполненный сертифицированным экзаменатором. DPSMV2211 — это дополнительная форма заявления на CDL, а не медицинский сертификат. Источник: страницы Louisiana OMV 'New CDL' / 'Submit CDL Medical Certificate'."},"83":{"q":"Кто уполномочен проводить медицинский осмотр, лежащий в основе Medical Examiner's Certificate для CDL в Луизиане?","options":["Медицинский экзаменатор, внесённый в FMCSA National Registry of Certified Medical Examiners","Любой лицензированный врач по выбору водителя","Врач, работающий в Louisiana OMV","Любая лицензированная медсестра-практик независимо от статуса в реестре"],"explanation":"Медицинский осмотр должен проводить медицинский экзаменатор, сертифицированный и внесённый в FMCSA National Registry of Certified Medical Examiners. Источник: страницы Louisiana OMV 'New CDL' / информация о медицинском сертификате CDL."},"84":{"q":"Каким из следующих способов Louisiana OMV принимает Medical Examiner's Certificate для CDL?","options":["По электронной почте, факсу или обычной почте в OMV","Только при личной явке в полевой офис OMV","Только через загрузку экзаменатором в FMCSA","Только заказным письмом с нотариально заверенным сопроводительным листом"],"explanation":"Louisiana OMV принимает Medical Examiner's Certificate по электронной почте (OMV_CDL_Medical@dps.la.gov), факсу или обычной почте. Источник: страница Louisiana OMV 'Submit CDL Medical Certificate'."},"85":{"q":"За сколько времени до истечения срока действия медицинского сертификата владельца CDL Louisiana OMV направляет уведомление с просьбой пройти новый медицинский осмотр?","options":["За 60 days до истечения срока","За 30 days до истечения срока","За 90 days до истечения срока","За 10 days до истечения срока"],"explanation":"Louisiana OMV формирует уведомление клиенту за 60 days до истечения срока действия медицинского сертификата, находящегося в деле, с просьбой предоставить новую форму осмотра и сертификат. Источник: информационная страница Louisiana OMV о медицинском сертификате CDL."},"86":{"q":"Если владелец CDL в Луизиане не предоставит новый медицинский сертификат, когда водитель отмечается как 'medically not certified'?","options":["Через 10 days после истечения срока действия медицинского сертификата в деле","Немедленно в дату истечения срока","Через 60 days после истечения срока действия сертификата","Через 30 days после истечения срока действия сертификата"],"explanation":"Несоблюдение требований самосертификации / медицинских требований приводит к тому, что водитель отмечается как 'medically not certified' через 10 days после истечения срока действия медицинского сертификата в деле; CDL впоследствии аннулируется, если несоблюдение продолжается. Источник: информационная страница Louisiana OMV о медицинском сертификате CDL."},"87":{"q":"Из каких трёх частей состоит тест навыков CDL в Луизиане, выполняемых по порядку?","options":["Предрейсовый осмотр, базовое управление транспортным средством и вождение по дороге","Письменный тест на знания, проверка зрения и вождение по дороге","Предрейсовый осмотр, обращение с опасными грузами и стравливание воздуха из тормозов","Базовое управление транспортным средством, аудит бортового журнала и вождение по дороге"],"explanation":"Тест навыков CDL в Луизиане состоит из трёх частей: предрейсовый осмотр, тест базового управления транспортным средством и тест вождения по дороге. Источник: руководство Louisiana CDL / страницы Louisiana OMV CDL (49 CFR 383.113)."},"88":{"q":"Какое обучение должен пройти заявитель в Луизиане перед сдачей теста навыков CDL для получения первого удостоверения Class A или Class B?","options":["Entry-Level Driver Training (ELDT) у поставщика, зарегистрированного в FMCSA","Курс безопасного вождения от Louisiana OMV","Курс DOTD по обращению с негабаритными грузами","Государственный семинар по инспекции на весовых станциях"],"explanation":"Entry-Level Driver Training (ELDT), предоставляемое школой, внесённой в FMCSA's Training Provider Registry, должно быть пройдено перед сдачей теста навыков на первоначальное CDL (и перед тестом на знания HazMat). Источник: страница Louisiana OMV 'New CDL' (49 CFR Part 380 Subpart F)."},"89":{"q":"Перед тестированием, какой первый тест должен сдать заявитель на CDL в Луизиане, чтобы получить право на Commercial Learner's Permit?","options":["Письменный тест на общие знания (knowledge test)","Тест навыков вождения по дороге","Тест базового управления транспортным средством","Тест предрейсового осмотра"],"explanation":"Заявители должны сдать необходимые письменные тесты на знания, начиная с теста на общие знания, чтобы получить CLP; тесты навыков сдаются позже, после получения CLP. Источник: руководство Louisiana CDL / страницы OMV CDL."},"90":{"q":"На письменном тесте на общие знания CDL в Луизиане из 50 вопросов, какой минимальный балл требуется для сдачи?","options":["80% (40 из 50 правильных)","70% (35 из 50 правильных)","75% (38 из 50 правильных)","90% (45 из 50 правильных)"],"explanation":"Тест на общие знания состоит из 50 вопросов с выбором ответа, и для сдачи требуется балл 80% (40 из 50), что соответствует федеральному стандарту CDL. Источник: руководство Louisiana CDL / материалы OMV по тестированию (49 CFR 383.135)."},"91":{"q":"Каков минимальный возраст для получения CDL в Луизиане, ограниченного деятельностью в пределах штата (intrastate)?","options":["18 years old","21 years old","19 years old","16 years old"],"explanation":"Заявитель должен быть не моложе 18 лет, чтобы иметь CDL в Луизиане, ограниченное деятельностью в пределах штата; для межштатного вождения и перевозки опасных грузов требуется 21 год. Источник: страницы Louisiana OMV CDL (49 CFR 383.3 / 391.11)."},"92":{"q":"Какие документы, помимо удостоверения личности и медицинского сертификата, должен предоставить заявитель на CDL в Луизиане при подаче заявления?","options":["Подтверждение проживания в Луизиане (например, счета за коммунальные услуги или договор аренды)","Нотариально заверенное письмо-поручительство от работодателя","Обследование маршрута DOTD для предполагаемого груза","Копию разрешения USDOT перевозчика на осуществление деятельности"],"explanation":"Луизиана требует подтверждение проживания в Луизиане (например, счета за коммунальные услуги, договор аренды, регистрация избирателя) вместе с CDL Supplemental Form (DPSMV2211) и Medical Examiner's Certificate. Источник: страница Louisiana OMV 'New CDL'."},"93":{"q":"В течение скольких лет CDL в Луизиане обычно действительно, прежде чем его необходимо продлить?","options":["6 years","4 years","8 years","5 years"],"explanation":"CDL в Луизиане, как правило, действительно в течение 6 years. На протяжении всего срока должны поддерживаться самосертификация типа деятельности и действующий медицинский сертификат (для водителей категории non-excepted). Источник: информация Louisiana OMV о продлении CDL."},"94":{"q":"Относительно платы за тест навыков CDL в Луизиане, проводимый сторонним экзаменатором, какое утверждение наиболее точно описывает процесс?","options":["Тестирование навыков может проводиться через утверждённых сторонних экзаменаторов, и точная плата устанавливается тестирующей стороной и может меняться, поэтому заявителям следует уточнять текущую сумму","Тест навыков всегда бесплатен при сдаче в любом офисе OMV","Плата за тест навыков установлена федеральным законом и одинакова во всех штатах","Плата за тест навыков никогда не может взиматься, если заявитель приезжает на собственном транспортном средстве"],"explanation":"Луизиана разрешает проводить тест навыков утверждёнными сторонними экзаменаторами, и плата устанавливается тестирующей стороной и может меняться, поэтому заявителям следует уточнять текущую сумму, а не полагаться на фиксированную цифру. Источник: страницы Louisiana OMV CDL (программа стороннего тестирования)."}},"tr":{"0":{"q":"Louisiana karayollarında, güvenlik donanımları hariç olmak üzere bir ticari aracın yasal azami genişliği nedir?","options":["96 inches","98 inches","102 inches","108 inches"],"explanation":"Louisiana RS 32:380, aynalar gibi güvenlik donanımları hariç olmak üzere azami araç genişliğini 102 inches (8 feet 6 inches) olarak belirler. Kaynak: Louisiana Revised Statutes 32:380."},"1":{"q":"Louisiana'da Interstate sistemi dışındaki karayollarında yasal azami araç yüksekliği nedir?","options":["13 feet","13 feet 6 inches","14 feet","14 feet 6 inches"],"explanation":"Louisiana RS 32:381 uyarınca, bir araç ve yükü Interstate dışı karayollarında 13 feet 6 inches yüksekliği aşamaz. Kaynak: Louisiana Revised Statutes 32:381."},"2":{"q":"Louisiana'da yalnızca Interstate karayolu sisteminde çalışan bir araç için yasal azami araç yüksekliği nedir?","options":["13 feet 6 inches","14 feet","14 feet 6 inches","15 feet"],"explanation":"Louisiana RS 32:381, yalnızca Interstate karayolu sisteminde çalışan bir araç ve yükü için azami 14 feet yüksekliğe izin verir; bu, başka yerlerdeki 13 feet 6 inches ile karşılaştırılır. Kaynak: Louisiana Revised Statutes 32:381."},"3":{"q":"Louisiana'da tek bir aracın (düz kamyon veya otobüs gibi) yasal azami uzunluğu nedir?","options":["40 feet","45 feet","53 feet","59 feet 6 inches"],"explanation":"Louisiana RS 32:382, tek bir aracın uzunluğunu azami 45 feet ile sınırlar. Kaynak: Louisiana Revised Statutes 32:382."},"4":{"q":"Louisiana'da bir çekici-yarı römork kombinasyonunun yarı römork kısmının yasal azami uzunluğu nedir?","options":["48 feet","53 feet","57 feet","59 feet 6 inches"],"explanation":"Louisiana RS 32:382, bir çekici-yarı römork kombinasyonunun yarı römork kısmının 59 feet 6 inches'e kadar olmasına izin verir; bu konfigürasyon için ayrı bir toplam kombinasyon uzunluk sınırı yoktur. Kaynak: Louisiana Revised Statutes 32:382."},"5":{"q":"Louisiana'da bir araçta bir yük, aracın gövde genişliğinin ne kadar ötesine taşabilir?","options":["6 inches'ten fazla değil","12 inches'ten fazla değil","18 inches'ten fazla değil","24 inches'ten fazla değil"],"explanation":"Louisiana RS 32:380, bir yükün aracın gövde genişliğinin 12 inches'ten fazla ötesine taşmamasını öngörür. Kaynak: Louisiana Revised Statutes 32:380."},"6":{"q":"Louisiana karayollarında izin gerektirmeden herhangi bir araç veya araç kombinasyonu için izin verilen azami brüt ağırlık nedir?","options":["73,280 pounds","80,000 pounds","88,000 pounds","90,000 pounds"],"explanation":"Louisiana RS 32:386, herhangi bir araç veya araç kombinasyonunun toplam brüt ağırlığını 80,000 pounds ile sınırlar. Kaynak: Louisiana Revised Statutes 32:386."},"7":{"q":"Louisiana'da düşük basınçlı pnömatik lastiklerle donatılmış tek bir aks üzerinde izin verilen azami brüt ağırlık nedir?","options":["18,000 pounds","20,000 pounds","22,400 pounds","34,000 pounds"],"explanation":"Louisiana RS 32:386, düşük basınçlı pnömatik lastiklerle donatılmış tek bir aksı 20,000 pounds ile sınırlar. Kaynak: Louisiana Revised Statutes 32:386."},"8":{"q":"Louisiana'da genel yasal sınır uyarınca bir tandem aks üzerinde izin verilen azami brüt ağırlık nedir?","options":["32,000 pounds","34,000 pounds","37,000 pounds","40,000 pounds"],"explanation":"Louisiana RS 32:386, düşük basınçlı pnömatik lastiklerle donatılmış bir tandem aksı 34,000 pounds ile sınırlar. Kaynak: Louisiana Revised Statutes 32:386."},"9":{"q":"Louisiana, doğal halindeki orman ürünlerini taşıyan araçlar için daha yüksek bir tandem aks ağırlık limiti sağlar. Bu limit nedir ve nerede geçerli DEĞİLDİR?","options":["37,000 pounds, Interstate sistemi hariç","37,000 pounds, Interstate sistemi dahil","40,000 pounds, Interstate sistemi hariç","34,000 pounds, her yerde geçerli"],"explanation":"Louisiana RS 32:386, doğal halindeki orman ürünlerini taşıyan araçlar için tandem aks başına 37,000 pounds'a izin verir; standart 34,000 pounds limitinin geçerli olduğu Interstate sistemi hariç. Kaynak: Louisiana Revised Statutes 32:386."},"10":{"q":"Louisiana RS 32:386 uyarınca, herhangi bir aks üzerindeki hiçbir lastik, karayolu yüzeyine lastik genişliğinin inch'i başına ne kadardan fazla ağırlık uygulayamaz?","options":["inch başına 500 pounds","inch başına 600 pounds","inch başına 650 pounds","inch başına 700 pounds"],"explanation":"Louisiana RS 32:386, hiçbir lastiğin karayolu yüzeyine lastik genişliğinin inch'i başına 650 pounds'tan fazla ağırlık uygulayamayacağını belirtir. Kaynak: Louisiana Revised Statutes 32:386."},"11":{"q":"Louisiana, Interstate sisteminde iki veya daha fazla ardışık akstan oluşan herhangi bir grup üzerindeki azami izin verilen brüt ağırlığı belirlemek için hangi formülü uygular?","options":["Federal Köprü Formülü W = 500(LN/(N-1) + 12N + 36)","Aks aralığından bağımsız sabit bir 80,000 pounds limiti","Tek aks 20,000 pounds kuralı, aks sayısıyla çarpılır","inch cinsinden dingil mesafesinin 650 pounds ile çarpımına eşit bir ağırlık"],"explanation":"Louisiana RS 32:386, Interstate üzerindeki ardışık akslar üzerindeki ağırlığı sınırlamak için Federal Köprü Formülü W = 500(LN/(N-1) + 12N + 36)'yı dahil eder; burada L feet cinsinden aks aralığı ve N aks sayısıdır. Kaynak: Louisiana Revised Statutes 32:386 (Federal Bridge Formula)."},"12":{"q":"Louisiana'da kullanılan Federal Köprü Formülünde, W = 500(LN/(N-1) + 12N + 36), L ve N değişkenleri neyi temsil eder?","options":["L ton cinsinden yüktür; N lastik sayısıdır","L bir grubun dış aksları arasındaki feet cinsinden mesafedir; N o gruptaki aks sayısıdır","L yasal hızdır; N aks ağırlığıdır","L şerit genişliğidir; N römork sayısıdır"],"explanation":"Louisiana RS 32:386 tarafından uygulanan Federal Köprü Formülünde, L herhangi bir gruptaki uç (dış) akslar arasındaki feet cinsinden mesafedir ve N o gruptaki aks sayısıdır. Kaynak: Louisiana Revised Statutes 32:386 / Federal Bridge Formula."},"13":{"q":"Louisiana'da bir motorlu taşıyıcı, bir araç veya yük yasal sınırları aştığında bir aşırı boyut/aşırı ağırlık izni almalıdır. Bu izinleri hangi kurum verir?","options":["Louisiana Office of Motor Vehicles (OMV)","Louisiana Department of Transportation and Development (DOTD)","Yalnızca Louisiana Eyalet Polisi","Yerel parish şerif ofisi"],"explanation":"Louisiana'da aşırı boyut/aşırı ağırlık izinleri, Department of Transportation and Development (DOTD) tarafından Truck Permit Office ve PERBA elektronik rotalama sistemi aracılığıyla verilir. Kaynak: Louisiana DOTD, Oversize and Overweight Truck Permits; LAC Title 73."},"14":{"q":"Bir Louisiana aşırı boyut/aşırı ağırlık izni, taşıma işlemine göre ne zaman alınmalıdır?","options":["Taşıma tamamlandıktan sonraki 24 saat içinde","Seyahat sırasında herhangi bir yol kenarı tartı istasyonunda","Aşırı boyutlu/aşırı ağırlıklı araç veya yük Louisiana içinde hareket etmeden veya eyalete girmeden önce","Yalnızca bir ceza düzenlendikten sonra"],"explanation":"Aşırı boyutlu/aşırı ağırlıklı araç veya yük Louisiana eyaleti içinde hareket etmeden veya eyalete girmeden önce bir izin için başvurulmalı ve izin alınmalıdır. Kaynak: Louisiana DOTD aşırı boyut/aşırı ağırlık izin kuralları; LAC Title 73, Part I."},"15":{"q":"Bir Louisiana yıllık aşırı boyut/aşırı ağırlık izni (tek seferlik izin yerine) hangi yollarda seyahat için geçerlidir?","options":["Yalnızca Interstate karayolları","Yalnızca Interstate dışı karayollar","Tüm eyalet ve Interstate karayolları","Yalnızca parish yolları"],"explanation":"Louisiana yıllık izinleri bir yıl boyunca geçerlidir ve yalnızca Interstate dışı karayollarda seyahate izin verir; Interstate üzerindeki hareketler tek seferlik izin gerektirir. Kaynak: Louisiana DOTD Annual Permits; LAC Title 73, Part I, Chapter 3."},"16":{"q":"Louisiana, tek seferlik bir aşırı boyut/aşırı ağırlık izni için asgari ne kadar teminat veya sigorta sertifikası tutarı gerektirir?","options":["$50,000","$100,000","$250,000","$500,000"],"explanation":"Louisiana, tek seferlik bir izin için en az $100,000 teminat veya sigorta sertifikası gerektirir (ve yıllık izin için $250,000). Kaynak: Louisiana DOTD aşırı boyut/aşırı ağırlık izin gereklilikleri."},"17":{"q":"Louisiana, hasat sırasında yasal aks veya brüt ağırlık sınırlarını aşan doğal halindeki tarım ürünlerini taşımak için özel bir izin sunar. Bu izin yaygın olarak ne diye adlandırılır?","options":["Hasat sezonu izni","Trip lease izni","HazMat tonaj izni","Karşılıklılık (reciprocity) izni"],"explanation":"Louisiana DOTD, yasal brüt veya aks ağırlık sınırlarını aşan doğal halindeki tarım ürünlerini taşıyan araçlar için hasat sezonu izinleri verir; yıllık ücret $100'dır. Kaynak: Louisiana DOTD Harvest Season / Annual Permits; LAC Title 73, Part I."},"18":{"q":"Louisiana'nın şeker kamışı taşıma izin gereklilikleri uyarınca, araç-ve-römork kombinasyonu hangi aks konfigürasyonuna sahip olmalıdır?","options":["Toplam en az dört aks","Şeker kamışı römorkunda ek bir yük taşıyan tek aks ile birlikte toplam altı aks","Yalnızca bir tandem arka aks","Tüm kaldırma aksları kaldırılmış olarak toplam sekiz aks"],"explanation":"Louisiana'nın şeker kamışı hasat izin hükümleri, şeker kamışı römorkunda indirilen ve yük taşıyan aks olarak işlev gören ek bir çift lastikli tek aks dahil olmak üzere, araç-ve-römork kombinasyonu için toplam altı aks gerektirir. Kaynak: Louisiana DOTD harvest permit provisions; LAC Title 73, Part I."},"19":{"q":"Louisiana'da, brüt kombinasyon ağırlık derecesi (GCWR) 26,001 pounds veya daha fazla olan ve çekilen birimin GVWR'si 10,000 pounds'tan fazla olan bir araç kombinasyonunu kullanmak için hangi sınıf Ticari Sürücü Belgesi gereklidir?","options":["Class B","Class A","Class C","Class D"],"explanation":"Louisiana R.S. 32:408 B.(2)(a), Class 'A' CDL'yi (Combination Vehicles) GCWR'si 26,001 pounds veya daha fazla olan herhangi bir araç kombinasyonuna izin veren belge olarak tanımlar; çekilen birim(ler)in GVWR'si 10,000 pounds'tan fazla olmak kaydıyla. Kaynak: Louisiana CDL Manual (OMV), classes section."},"20":{"q":"Louisiana kurallarına göre, bir Class B CDL, GVWR'si 26,001 pounds veya daha fazla olan herhangi bir tek aracın kullanılmasına izin verir; isteğe bağlı olarak ne kadar ağırlığı aşmayan bir birimi çekerek?","options":["5,000 pounds GVWR","15,000 pounds GVWR","26,001 pounds GVWR","10,000 pounds GVWR"],"explanation":"Louisiana R.S. 32:408 B.(2)(b), Class 'B' CDL'yi (Heavy Straight Vehicle) GVWR'si 26,001 pounds veya daha fazla olan herhangi bir tek araç veya GVWR'si 10,000 pounds'u aşmayan bir aracı çeken böyle bir araç olarak tanımlar. 10,000 lbs'tan fazlasını çekmek sürücüyü Class A'ya taşır. Kaynak: Louisiana CDL Manual (OMV)."},"21":{"q":"Bir Louisiana sürücüsü, GVWR'si 24,000 pounds olan ve tehlikeli maddeler için plakartlanmış tek bir düz kamyon kullanır. Asgari olarak hangi CDL sınıfı gereklidir?","options":["Class B","Class A","Class D","Class C"],"explanation":"Louisiana R.S. 32:408 B.(2)(c), Class 'C' CDL'yi (Light Vehicle) GVWR'si 26,001 pounds'tan az olan ve ya 16 veya daha fazla yolcu (sürücü dahil) taşımak için tasarlanmış ya da plakart gerektiren miktarda tehlikeli madde taşımak için kullanılan tek araçlar için tanımlar. 24,000 lbs HazMat-plakartlı bir düz kamyon, Class C artı H endorsement gerektirir. Kaynak: Louisiana CDL Manual (OMV)."},"22":{"q":"Bir Louisiana CDL'sinde, ikili ve üçlü römorkların kullanılmasına hangi endorsement kodu izin verir?","options":["N","X","T","H"],"explanation":"Louisiana R.S. 32:408(3), İkili/Üçlü Römorklar için 'T' endorsement'ını listeler. (N = Tank, H = Hazardous Materials, X = birleşik Tank ve HazMat.) Kaynak: Louisiana CDL Manual (OMV), endorsements section."},"23":{"q":"Yalnızca INTRASTATE (eyalet içi) sürüş için bir Louisiana CDL almanın asgari yaşı nedir?","options":["21 yaşında","19 yaşında","17 yaşında","18 yaşında"],"explanation":"Louisiana R.S. 32:408, Class A, B ve C CDL'leri için yaş gerekliliğini eyalet içi için 18 yaş ve üzeri ve eyaletler arası için 21 yaş ve üzeri olarak listeler. Kaynak: Louisiana CDL Manual (OMV), classes section."},"24":{"q":"19 yaşındaki biri geçerli bir Louisiana CDL'ye sahiptir. Hangi işlemi yapmasına izin verilir?","options":["Eyaletler arası ticarette bir CMV kullanmak","Plakartlanmış tehlikeli maddeleri taşımak","Louisiana içinde eyalet içi ticarette bir CMV kullanmak","Bir H (HazMat) endorsement'ına sahip olmak"],"explanation":"Louisiana CDL yaşını eyalet içi için 18, ancak eyaletler arası için 21 olarak belirler ve H (HazMat) endorsement'ı 'yalnızca 21 yaş ve üzerindeki kişilere verilir.' 19 yaşındaki biri yalnızca eyalet içi sürüş yapabilir ve bir HazMat endorsement'ı alamaz. Kaynak: Louisiana CDL Manual (OMV), R.S. 32:408."},"25":{"q":"Louisiana'da, H (Hazardous Materials) endorsement'ı yalnızca en az kaç yaşında olan başvuru sahiplerine verilebilir?","options":["18 yaşında","25 yaşında","19 yaşında","21 yaşında"],"explanation":"Louisiana CDL Manual'ın endorsement listesi (R.S. 32:408(3)), 'H' Hazardous Materials endorsement'ının plakartlı HazMat taşımacılığının yalnızca eyaletler arası niteliğiyle tutarlı olarak 'yalnızca 21 yaş ve üzerindeki kişilere verildiğini' belirtir. Kaynak: Louisiana CDL Manual (OMV)."},"26":{"q":"Bir Louisiana HazMat (H) endorsement'ı verilmeden önce, bir başvuru sahibi hangi ek taramayı geçmelidir?","options":["Yalnızca görme yeniden muayenesi","36 saatlik sınıf içi savunmacı sürüş kursu","Bir tanker araçta yol testi","Parmak izi alımı ve geçmiş kontrolü dahil bir TSA güvenlik tehdit değerlendirmesi"],"explanation":"Louisiana CDL Manual (Section 1.2.6), bir HazMat endorsement'ının parmak izi ve geçmiş kontrolü sunmayı gerektirdiğini belirtir; Transportation Security Administration (TSA) tarafından güvenlik tehdidi olarak değerlendirilen bir başvuru sahibi reddedilir. Parmak izi geçmiş kontrolü en son 180 gün içinde olmalıdır. Kaynak: Louisiana CDL Manual (OMV), TSA / 49 CFR 1572."},"27":{"q":"Bir Louisiana HazMat endorsement'ı başvuru sahibine, aşağıdaki koşullardan hangisi altında endorsement REDDEDİLİR?","options":["İki yıldan az CDL deneyimleri var","25 yaşından küçükler","Amerika Birleşik Devletleri'nin yasal daimi sakini değiller","Bir Class A CDL'ye sahip değiller"],"explanation":"Louisiana CDL Manual Section 1.2.6'ya göre, ABD'nin yasal daimi sakini değilseniz, ABD vatandaşlığından feragat ederseniz, aranıyor/iddianame altında veya belirli ağır suçlardan mahkûm iseniz, akıl hastası olarak adli karara bağlandıysanız veya bir TSA güvenlik tehdidi olarak değerlendirildiyseniz HazMat endorsement'ı reddedilir veya kaybedilir. Kaynak: Louisiana CDL Manual (OMV); TSA HME rule."},"28":{"q":"Bir Class A veya B CDL gerektiren bir araç, sürekli monteli bir kargo tankında sıvı/gaz taşıdığında, hangi asgari kapasitede dereceli olduğunda bir Louisiana tank aracı (N) endorsement'ı gereklidir?","options":["119 gallons veya daha fazla","100 gallons veya daha fazla","500 gallons veya daha fazla","1,000 gallons veya daha fazla"],"explanation":"Louisiana CDL Manual (Section 8, Tank Vehicles), aracınız bir Class A veya B CDL gerektiriyorsa ve sürekli monteli bir kargo tankında 119 gallons veya daha fazla dereceli bir sıvı veya gaz taşıyorsanız VEYA 1,000 gallons veya daha fazla dereceli taşınabilir bir tankta taşıyorsanız bir tank endorsement'ının gerekli olduğunu belirtir. Kaynak: Louisiana CDL Manual (OMV)."},"29":{"q":"Louisiana tank (N) endorsement'ı için, bir TAŞINABİLİR tank, hangi asgari kapasitede dereceli olduğunda endorsement gerekliliğini tetikler?","options":["119 gallons veya daha fazla","1,000 gallons veya daha fazla","660 gallons veya daha fazla","2,000 gallons veya daha fazla"],"explanation":"Louisiana CDL Manual, tank endorsement'ının 1,000 gallons veya daha fazla dereceli taşınabilir bir tank için geçerli olduğunu belirtir (sürekli monteli bir kargo tankı için 119 gallons veya daha fazlaya kıyasla). Kaynak: Louisiana CDL Manual (OMV), Tank Vehicles section."},"30":{"q":"Bir Louisiana CDL'sinde hangi endorsement kodu Tank Araçları VE Tehlikeli Maddelerin KOMBİNASYONUNU temsil eder?","options":["T","X","N","H"],"explanation":"Louisiana R.S. 32:408(3), 'X' endorsement'ını Tank Araçları ve Tehlikeli Maddelerin kombinasyonu olarak listeler. (N = yalnızca Tank, H = yalnızca HazMat, T = İkili/Üçlü Römorklar.) Kaynak: Louisiana CDL Manual (OMV), endorsements section."},"31":{"q":"Bir okul otobüsü kullanmak için özellikle hangi Louisiana CDL endorsement'ı gereklidir?","options":["S","P","T","N"],"explanation":"Louisiana R.S. 32:408(3), Okul Otobüsü için 'S' endorsement'ını listeler. 'P' (Passenger) endorsement'ı genel olarak otobüsleri kapsar ve ayrıca gereklidir, ancak okul otobüsüne özgü endorsement 'S'dir. Kaynak: Louisiana CDL Manual (OMV), endorsements section."},"32":{"q":"Louisiana'da uygulanan federal standart uyarınca, bir Commercial Learner Permit (CLP) ilk kez verildikten sonra, sahibi CDL beceri testine girmeye uygun olmadan önce asgari ne kadar beklemelidir?","options":["14 gün","7 gün","30 gün","10 gün"],"explanation":"Louisiana'da benimsenen 49 CFR 383.25(e) uyarınca, bir CLP sahibi, CLP'nin ilk verilmesinden sonraki ilk 14 gün içinde CDL beceri testine girmeye uygun değildir. Bu 14 günlük bekleme, direksiyon başında pratik için zaman tanır. Kaynak: 49 CFR 383.25(e); Louisiana OMV CDL requirements."},"33":{"q":"Bir Louisiana CLP'sinde bir CMV'de pratik yaparken, izin sahibine her zaman kim eşlik etmelidir?","options":["21 yaşından büyük herhangi bir lisanslı Class E sürücüsü","Ön koltukta oturan, uygun sınıf ve endorsement'lara sahip bir CDL sahibi","Yalnızca sertifikalı bir üçüncü taraf sınav görevlisi","Bilgi testi geçildikten sonra hiçbir denetim gerekmez"],"explanation":"Louisiana OMV CLP kuralları (49 CFR 383.25 uyarınca), tüm direksiyon başındaki işlem sırasında CLP sahibine, aracın ön koltuğunda (kabininde) oturan, uygun sınıf ve endorsement'lara sahip geçerli bir CDL sahibinin eşlik etmesini gerektirir. Kaynak: Louisiana OMV New CDL page; 49 CFR 383.25."},"34":{"q":"İlk kez Class A ve Class B başvuru sahiplerine ek olarak, Louisiana'da hangi endorsement'ları arayan ilk kez başvuranlar için ELDT gereklidir?","options":["Hazardous Materials (H), Passenger (P) ve School Bus (S)","Yalnızca Tank (N) ve İkili/Üçlü (T)","Yalnızca Motorcycle (M) ve Passenger (P)","İstisnasız tüm endorsement'lar"],"explanation":"FMCSA ELDT (7 Şubat 2022'de yürürlükte, Louisiana'da uygulanır), bir Class A veya B CDL için ilk kez başvuranları, B'den A'ya yükseltmeleri ve Hazardous Materials (H), Passenger (P) ve School Bus (S) endorsement'ları için ilk kez başvuranları kapsar. Tank (N) ve İkili/Üçlü (T), ELDT kapsamındaki endorsement'lar değildir. Kaynak: FMCSA Training Provider Registry / ELDT Applicability."},"35":{"q":"Louisiana'da, bir sürücü bir ticari motorlu araç (CMV) kullanırken, CDL açısından yasal olarak sarhoş kabul edilmeden önce sahip olabileceği azami kan alkol konsantrasyonu (BAC) nedir?","options":["yüzde 0.04","yüzde 0.08","yüzde 0.02","yüzde 0.10"],"explanation":"Louisiana yasası, CMV BAC limitini, ticari olmayan sürücüler için olan yüzde 0.08 limitinin yarısı olan yüzde 0.04 olarak belirler. Bir CMV'yi yüzde 0.04 veya daha fazla ile kullanan bir CDL sahibi etki altında kabul edilir. Kaynak: La. R.S. 32:414.2 ve Louisiana CDL Manual (Section 1.2, Disqualifications)."},"36":{"q":"Bir sürücü, bir Louisiana CDL'sine sahip olarak ve bir ticari araç kullanarak, otomatik olarak neyi kabul etmiş sayılır?","options":["Yasal olarak talep edildiğinde nefes, kan veya idrarın kimyasal testine tabi olmayı","Federal hizmet saatleri kaydının bir kopyasını her zaman taşımayı","Herhangi bir trafik cezasında mahkeme duruşması hakkından feragat etmeyi","Tüm geçiş ücretlerini nakit yerine elektronik olarak ödemeyi"],"explanation":"Louisiana'nın zımni rıza yasası uyarınca, bir CMV kullanan herkes, bir memurun makul nedeni olduğunda alkol veya uyuşturucu varlığını belirlemek için nefes, kan veya idrarın kimyasal testine rıza göstermiş sayılır. Kaynak: La. R.S. 32:414.2 (implied consent) ve Louisiana CDL Manual."},"37":{"q":"Bir Louisiana CDL sahibi, bir CMV'yi yüzde 0.04 veya daha fazla BAC ile kullanmak gibi ilk büyük ihlal için ne kadar süreyle diskalifiye edilir?","options":["1 yıl","60 gün","6 ay","3 yıl"],"explanation":"İlk büyük ihlal (DUI, bir CMV'de yüzde 0.04 veya daha fazla BAC, testi reddetme veya olay yerinden ayrılma dahil), Louisiana yasası uyarınca 1 yıllık diskalifiye ile sonuçlanır ve bu 49 CFR 383.51 ile uyumludur. Kaynak: La. R.S. 32:414.2 ve Louisiana CDL Manual."},"38":{"q":"Bir Louisiana CDL sahibi, tehlikeli maddeler için plakartlanmış bir CMV'yi kullanırken ilk büyük ihlali işlerse, diskalifiye süresi şu kadara çıkar:","options":["3 yıl","1 yıl","2 yıl","Ömür boyu"],"explanation":"İlk büyük ihlal, tehlikeli maddeler için plakartlanması gereken bir CMV'de gerçekleştiğinde, diskalifiye 1 yıldan 3 yıla uzatılır. Kaynak: La. R.S. 32:414.2 ve 49 CFR 383.51, Louisiana CDL Manual'da benimsendiği şekliyle."},"39":{"q":"İkinci bir büyük ihlalden (örneğin, bir CMV'de ikinci bir DUI) mahkûm olan bir Louisiana CDL sahibi için diskalifiye süresi nedir?","options":["Ömür boyu diskalifiye","10 yıllık diskalifiye","5 yıllık diskalifiye","3 yıllık diskalifiye"],"explanation":"Büyük ihlallerin herhangi bir kombinasyonu için ikinci bir mahkûmiyet, 49 CFR 383.51 ile tutarlı olarak Louisiana'da ömür boyu CDL diskalifiyesi ile sonuçlanır. (Federal kurallar uyarınca asgari 10 yıllık bir yeniden ehliyetlendirme mümkün olabilir.) Kaynak: La. R.S. 32:414.2 ve Louisiana CDL Manual."},"40":{"q":"Bir kimyasal teste tabi olması yasal olarak istenen bir Louisiana CDL sahibi reddeder. CDL için sonuç nedir?","options":["Bir DUI mahkûmiyetiyle aynı şekilde en az 1 yıl diskalifiye","İlk reddetmede yalnızca bir uyarı","60 gün diskalifiye","Cezai suçlamalar düşerse CDL üzerinde hiçbir sonuç olmaz"],"explanation":"Louisiana'nın zımni rıza yasası uyarınca bir kimyasal testi reddetmek, bir büyük ihlalle aynı şekilde en az 1 yıllık bir CDL diskalifiyesi ile sonuçlanır ve bu, herhangi bir cezai davanın sonucundan bağımsız olarak geçerlidir. Kaynak: La. R.S. 32:414.2 ve Louisiana CDL Manual."},"41":{"q":"Aşağıdakilerden hangisi bir Louisiana CDL sahibi için 'ciddi trafik ihlali' olarak sınıflandırılır?","options":["Belirtilen sınırın 15 mph veya daha fazla üzerinde hız yapmak","Belirtilen sınırın 5 mph üzerinde hız yapmak","Bir ticari bölgede park ihlali","Süresi dolmuş bir tescil etiketiyle sürüş"],"explanation":"Belirtilen sınırın 15 mph veya daha fazla üzerinde hız yapmak, CDL sahipleri için listelenen ciddi trafik ihlallerinden biridir. Diğerleri arasında dikkatsiz sürüş, uygunsuz veya düzensiz şerit değişiklikleri ve çok yakından takip etme yer alır. Kaynak: 49 CFR 383.51, Louisiana CDL Manual'da benimsendiği şekliyle."},"42":{"q":"Bir Louisiana CDL sahibi, 3 yıllık bir süre içinde İKİ ciddi trafik ihlalinden mahkûm olduğu için ne kadar süreyle diskalifiye edilir?","options":["60 gün","30 gün","120 gün","1 yıl"],"explanation":"3 yıl içinde ikinci bir ciddi trafik ihlali (ayrı olaylarda), 49 CFR 383.51 ile eşleşen şekilde Louisiana yasası uyarınca 60 günlük diskalifiye ile sonuçlanır. Kaynak: La. R.S. 32:414.2 ve Louisiana CDL Manual."},"43":{"q":"Bir Louisiana CDL sahibi, 3 yıllık bir süre içinde ÜÇ ciddi trafik ihlalinden mahkûm olduğu için ne kadar süreyle diskalifiye edilir?","options":["120 gün","60 gün","90 gün","180 gün"],"explanation":"3 yıl içinde üçüncü bir ciddi trafik ihlali (ayrı olaylarda), önceki herhangi bir 60 günlük süreye art arda hizmet edilen 120 günlük diskalifiye ile sonuçlanır. Kaynak: 49 CFR 383.51, Louisiana CDL Manual ve La. R.S. 32:414.2 tarafından benimsendiği şekliyle."},"44":{"q":"Louisiana'da bir ticari motorlu araç kullanırken elde taşınan bir cep telefonu kullanmak, CDL açısından ne tür bir ihlal olarak değerlendirilir?","options":["Diskalifiyeye doğru sayılan ciddi bir trafik ihlali","CDL üzerinde etkisi olmayan hareketsiz bir ihlal","Otomatik 1 yıllık büyük ihlal","Yalnızca bir kaza meydana gelirse ihlal"],"explanation":"Bir CMV kullanırken elde taşınan bir telefon kullanmak veya mesaj yazmak, 3 yılda 2 (60 gün) ve 3 yılda 3 (120 gün) diskalifiye eşiklerine doğru sayılan ciddi bir trafik ihlalidir. Kaynak: 49 CFR 383.51 / 392.82, Louisiana CDL Manual'da benimsendiği şekliyle."},"45":{"q":"Bir CMV kullanırken mesaj yazmak da ciddi bir ihlaldir. Louisiana'da uygulanan CDL kurallarında atıfta bulunulduğu üzere, bir CMV sürücüsünün mesaj yazma için karşılaşabileceği federal hukuki ceza yaklaşık olarak şu kadar yüksek olabilir:","options":["$2,750","$500","$1,000","$10,000"],"explanation":"CDL diskalifiyesinin ötesinde, sürüş sırasında mesaj yazan bir CMV sürücüsü, yaklaşık $2,750'ye kadar federal hukuki ceza ile karşı karşıya kalır. Kaynak: 49 CFR 392.80/392.82, Louisiana CDL Manual'da atıfta bulunulduğu şekliyle."},"46":{"q":"Bir Louisiana CDL sahibinin İLK demiryolu-karayolu hemzemin geçit ihlali mahkûmiyeti için asgari diskalifiye nedir?","options":["60 gün","30 gün","120 gün","1 yıl"],"explanation":"İlk demiryolu-karayolu hemzemin geçit ihlali (durmamak veya geçişi temizlemek için yeterli alana sahip olmamak gibi), Louisiana'da asgari 60 günlük diskalifiye taşır. Kaynak: 49 CFR 383.51, Louisiana CDL Manual tarafından benimsendiği şekliyle."},"47":{"q":"Bir Louisiana CDL sahibi, 3 yıllık bir süre içinde İKİNCİ bir demiryolu hemzemin geçit ihlali işler. Asgari diskalifiye şudur:","options":["120 gün","60 gün","90 gün","1 yıl"],"explanation":"3 yıl içinde ikinci bir demiryolu hemzemin geçit ihlali, asgari 120 günlük diskalifiye ile sonuçlanır. Kaynak: 49 CFR 383.51, Louisiana CDL Manual tarafından benimsendiği şekliyle."},"48":{"q":"Bir Louisiana CDL sahibi, 3 yıllık bir süre içinde ÜÇÜNCÜ bir demiryolu hemzemin geçit ihlali işler. Asgari diskalifiye şudur:","options":["1 yıl","120 gün","180 gün","3 yıl"],"explanation":"3 yıl içinde üçüncü bir demiryolu hemzemin geçit ihlali, asgari 1 yıllık diskalifiye ile sonuçlanır. Kaynak: 49 CFR 383.51, Louisiana CDL Manual tarafından benimsendiği şekliyle."},"49":{"q":"Bir Louisiana CDL sahibinin bir CMV kullanırken (HazMat olmayan, yolcu olmayan) bir hizmet dışı (out-of-service) emrini ihlal etmekten İLK mahkûmiyeti için diskalifiye süresi nedir?","options":["En az 180 gün, 1 yıla kadar","En az 30 gün","En az 60 gün","Ömür boyu"],"explanation":"İlk hizmet dışı (OOS) emir ihlali, standart bir CMV için en az 180 gün ve 1 yıla kadar diskalifiye ile sonuçlanır. Kaynak: La. R.S. 32:414.2 ve 49 CFR 383.51, Louisiana CDL Manual'da benimsendiği şekliyle."},"50":{"q":"Bir Louisiana CDL sahibi, 10 yıllık bir süre içinde İKİNCİ bir hizmet dışı emir ihlalinden mahkûm olur. Diskalifiye aralığı şudur:","options":["2 ila 5 yıl","1 ila 2 yıl","60 ila 120 gün","Ömür boyu"],"explanation":"10 yıl içinde ikinci bir hizmet dışı emir ihlali, standart bir CMV için 2 ila 5 yıllık diskalifiye ile sonuçlanır. Kaynak: La. R.S. 32:414.2 ve 49 CFR 383.51, Louisiana CDL Manual'da benimsendiği şekliyle."},"51":{"q":"Plakart gerektiren tehlikeli maddeler taşıyan bir CDL sahibi için, İLK bir hizmet dışı emir ihlali şu diskalifiyeyi taşır:","options":["En az 180 gün, 2 yıla kadar","En az 30 gün, 60 güne kadar","Tam olarak 1 yıl","Ömür boyu"],"explanation":"OOS ihlali, plakartlı tehlikeli maddeler taşırken veya 16 veya daha fazla yolcu taşımak için tasarlanmış bir araç kullanırken gerçekleştiğinde, ilk ihlal diskalifiyesi en az 180 gün ve 2 yıla kadardır. Kaynak: 49 CFR 383.51, Louisiana CDL Manual'da benimsendiği şekliyle."},"52":{"q":"Aşağıdakilerden hangisi, Louisiana'nın ciddi trafik ihlallerini CDL diskalifiyesine doğru nasıl saydığını en iyi şekilde açıklar?","options":["3 yıllık bir süre içinde ayrı olaylardaki mahkûmiyetler","Yalnızca aynı gün meydana gelen mahkûmiyetler","Yalnızca 1 yıllık bir süre içindeki tüm mahkûmiyetler","Yalnızca görev dışında işlenen ihlaller"],"explanation":"Ciddi trafik ihlali diskalifiyeleri (ikincisi için 60 gün, üçüncüsü için 120 gün), 3 yıllık bir süre içinde ayrı olaylardan kaynaklanan mahkûmiyetlere dayanır. Kaynak: 49 CFR 383.51, Louisiana CDL Manual ve La. R.S. 32:414.2 tarafından benimsendiği şekliyle."},"53":{"q":"Bir sürücü bir CMV kullanırken bir ölüme neden olur ve ölümle bağlantılı bir trafik suçundan (ihmalkâr veya dikkatsiz kullanım gibi) mahkûm olur. Louisiana'da CDL açısından bu şu şekilde değerlendirilir:","options":["Diskalifiyeye doğru sayılan ciddi bir trafik ihlali","Yalnızca CDL dışı idari bir mesele","Otomatik ömür boyu diskalifiye","Bir demiryolu geçit ihlali"],"explanation":"Ölümcül bir kazayla bağlantılı olarak işlenen bir trafik kontrol yasası ihlali, ciddi trafik ihlali listesinde yer alır ve 60 günlük ve 120 günlük eşiklere doğru sayılır. (Adam öldürme veya bir CMV ile ağır suç, ayrı bir 1 yıllık büyük ihlaldir.) Kaynak: 49 CFR 383.51, Louisiana CDL Manual'da benimsendiği şekliyle."},"54":{"q":"Bir Louisiana CDL sahibi, kontrollü bir maddenin üretimi veya dağıtımını içeren bir ağır suç işlemek için bir CMV kullanır. Diskalifiye şudur:","options":["Ömür boyu, yeniden ehliyetlendirme imkânı olmadan","1 yıl","3 yıl","60 gün"],"explanation":"Kontrollü madde üretimi, dağıtımı veya temini içeren bir ağır suçun işlenmesinde bir CMV kullanmak, diğer büyük ihlallerin aksine, yeniden ehliyetlendirme imkânı olmadan ömür boyu diskalifiye ile sonuçlanır. Kaynak: La. R.S. 32:414.2 ve 49 CFR 383.51, Louisiana CDL Manual'da benimsendiği şekliyle."},"55":{"q":"Louisiana'da bir eyaletler arası otoyolda veya kontrollü erişimli otoyolda, yasayla belirlenmiş azami hız sınırı nedir (farklı bir sınır levhayla belirtilmemişse)?","options":["60 mph","65 mph","70 mph","75 mph"],"explanation":"Louisiana RS 32:61, aksi belirtilmedikçe eyaletler arası veya kontrollü erişimli otoyollarda yasal azami hızı 70 mph olarak belirler. Kaynak: Louisiana RS 32:61; Louisiana DOTD 'Speed Limit' broşürü."},"56":{"q":"Louisiana yasalarına göre, eyaletler arası otoyol olmayan, çok şeritli BÖLÜNMÜŞ bir otoyolda, aksi belirtilmedikçe yasal hız sınırı nedir?","options":["55 mph","65 mph","70 mph","60 mph"],"explanation":"RS 32:61, herhangi bir Louisiana otoyolundaki sınırın, çok şeritli bölünmüş bir otoyol (65 mph) ya da eyaletler arası/kontrollü erişimli otoyol (70 mph) olmadıkça 55 mph'yi aşmaması gerektiğini öngörür. Kaynak: Louisiana RS 32:61; Louisiana DOTD 'Speed Limit' broşürü."},"57":{"q":"Louisiana'da bir eyaletler arası otoyolda, bir çekici-römork için azami hız sınırı, bir binek otomobil için geçerli sınırla nasıl karşılaştırılır?","options":["Kamyonlar levhada belirtilen sınırın 10 mph altında kalmalıdır","Kamyonlar, otomobillerden 5 mph daha düşük bir sınırla sınırlandırılmıştır","Kamyonların azami sınırı otomobillerle aynıdır","Kamyonlar eyalet genelinde 55 mph ile sınırlandırılmıştır"],"explanation":"Louisiana'da kamyonlar için ayrı ve daha düşük bir eyaletler arası hız sınırı yoktur; eski kamyon hızı yasası RS 32:62 yürürlükten kaldırılmıştır (Acts 2010, No. 81) ve daha sonraki bir 'sınırın 10 mph altında' önerisi yasalaşmamıştır. RS 32:61 sınırları, aksi belirtilmedikçe tüm araçlar için geçerlidir. Kaynak: Louisiana RS 32:61; RS 32:62 (2010'da yürürlükten kaldırıldı)."},"58":{"q":"Louisiana'da bir otobüs sürücüsü, durmayı gerektiren bir demiryolu geçidine yaklaşıyor. Otobüs en yakın raya göre nerede durdurulmalıdır?","options":["5 ile 25 feet arasında","15 ile 50 feet arasında","50 ile 100 feet arasında","10 ile 40 feet arasında"],"explanation":"Louisiana CDL El Kitabı, bir otobüsün demiryolu geçidinden önce 15 ile 50 feet arasında durması, ardından geçmeden önce her iki yöne bakıp dinlemesi gerektiğini belirtir. Kaynak: Louisiana CDL El Kitabı, Sec. 4.3.5 (Railroad-highway Crossing Stops)."},"59":{"q":"Louisiana'da plakartlı (levhalı) tehlikeli madde taşıyan bir sürücü, muafiyet kapsamında olmayan bir demiryolu geçidine ulaşıyor. Araç en yakın raydan ne kadar mesafede durmalıdır?","options":["15 feet'ten daha yakın olmamak ve 50 feet'ten fazla olmamak üzere","10 feet'ten daha yakın olmamak ve 25 feet'ten fazla olmamak üzere","25 feet'ten daha yakın olmamak ve 75 feet'ten fazla olmamak üzere","Tam 50 feet'te, ardından yavaşça ilerleyerek"],"explanation":"Otobüsler, okul otobüsleri ve plakartlı araçlar, aracı en yakın raydan 50 feet içinde ancak 15 feet'ten az olmamak üzere durdurmalı, ardından geçmeden önce bakıp dinlemelidir. Kaynak: Louisiana CDL El Kitabı, Sec. 13.1.8 (Railroad Crossing procedures)."},"60":{"q":"Louisiana RS 32:80 kapsamında, görsel sinyalleri çalışır durumda olan, durmuş bir okul otobüsüyle karşılaşan veya onu geçen bir sürücü, otobüsten en az ne kadar mesafede durmalıdır?","options":["10 feet","20 feet","30 feet","50 feet"],"explanation":"RS 32:80, herhangi bir yönden yaklaşan sürücülerin, görsel sinyalleri etkin durumdayken çocukları bindirmek veya indirmek için durmuş bir okul otobüsünden en az 30 feet uzakta durmasını ve otobüs hareket edene ya da sinyaller kapanana kadar durmuş halde kalmasını gerektirir. Kaynak: Louisiana RS 32:80."},"61":{"q":"Louisiana'da, ayrı yol platformlarına sahip dört şeritli BÖLÜNMÜŞ bir otoyolda, bir okul otobüsü çocukları indirmek için KARŞI yol platformunda duruyor. Diğer yönde seyreden bir sürücü ne yapmalıdır?","options":["Durmalı ve sinyaller kapanana kadar beklemelidir","Yalnızca çocuklar karşıdan karşıya geçiyorsa durmalıdır","Durması gerekmez; bölünmüş otoyol istisnası geçerlidir","15 mph'ye yavaşlamalı ancak durması gerekmez"],"explanation":"RS 32:80, ayrı yol platformlarına sahip bölünmüş bir otoyolun farklı bir yol platformundaki bir okul otobüsü için (veya otobüsün bir yükleme bölgesinde olduğu kontrollü erişimli bir otoyolda) bir sürücünün durmasının gerekmediğini öngörür. Kaynak: Louisiana RS 32:80."},"62":{"q":"Louisiana'da, her yönde birer şeride ek olarak ortada çift yönlü bir sola dönüş şeridi bulunan iki şeritli bir yolda, durmuş bir okul otobüsü çocukları bindiriyor. Okul otobüsünde durma yasası bakımından bu yol nasıl değerlendirilir?","options":["Bölünmüş bir otoyol olarak; bu nedenle karşıdan gelen trafiğin durması gerekmez","Bölünmüş bir otoyol DEĞİL; bu nedenle karşıdan gelen trafiğin durması gerekir","Durma zorunluluğundan muaf, kontrollü erişimli bir otoyol olarak","Durma yükümlülüğü olmayan tek yönlü bir cadde olarak"],"explanation":"RS 32:80, her yönde bir şerit ile özel bir çift yönlü sola dönüş şeridi bulunan bir otoyolun, ayrı yol platformlarına sahip bölünmüş bir otoyol olarak DEĞERLENDİRİLMEYECEĞİNİ açıkça belirtir; bu nedenle karşıdan gelen sürücülerin yine de durması gerekir. Kaynak: Louisiana RS 32:80."},"63":{"q":"Louisiana'nın Move Over (Şerit Değiştir) yasası (RS 32:125), kendi yönünüzde iki veya daha fazla şeride sahip bir otoyolda görsel sinyaller gösteren DURMUŞ bir acil durum aracına yaklaştığınızda geçerlidir. İLK gerekli eylem nedir?","options":["Kendi şeridinizde tamamen durmak","Mümkünse, park etmiş araca komşu olmayan bir şeride geçmek","Kornaya basıp hızınızı korumak","Sağ banket üzerine çekip durmak"],"explanation":"RS 32:125, aynı yönde iki veya daha fazla şeride sahip bir yoldaki sürücülerin, güvenlik ve trafik gözetilerek mümkün olduğunda, park etmiş acil durum aracına komşu olmayan bir şeride geçerek yol vermesini gerektirir. Kaynak: Louisiana RS 32:125."},"64":{"q":"Louisiana'nın Move Over yasası kapsamında, durmuş bir acil durum aracından güvenli bir şekilde uzağa şerit değiştiremiyorsanız (veya iki şeritli bir yoldaysanız), ne yapmalısınız?","options":["Olay yeri temizlenene kadar tamamen durmak","Normal hızınızı koruyup sola yönelmek","Yol koşulları için makul derecede güvenli bir hıza yavaşlamak","Alanı hızla geçmek için hızlanarak geçmek"],"explanation":"RS 32:125, bir şerit değişikliği mümkün değilse veya iki şeritli bir yoldaysanız, park etmiş acil durum aracını geçerken yol koşulları için makul derecede güvenli bir hıza yavaşlamanız gerektiğini öngörür. Kaynak: Louisiana RS 32:125."},"65":{"q":"Polis, itfaiye ve EMS'ye ek olarak, Louisiana Move Over yasası (RS 32:125), uyarı ışıkları gösteren hangi diğer durmuş araçları korur?","options":["Yalnızca işaretli kolluk kuvveti birimlerini","Çekici kamyonları/kurtarıcıları ve yanıp sönen kehribar/sarı ışık kullanan araçları","Yalnızca ambulansları ve itfaiye araçlarını","Yalnızca posta dağıtım araçlarını"],"explanation":"RS 32:125, yanıp sönen kehribar, sarı veya yeşil uyarı ışıkları da dahil olmak üzere yetkili görsel sinyalleri yasal olarak gösteren her aracı kapsar; bu da korumayı çekici kamyonlara/kurtarıcılara ve benzeri hizmet araçlarına genişletir. Kaynak: Louisiana RS 32:125 (Acts 2021, No. 78 ile değiştirildi)."},"66":{"q":"Siren çalan ve ışıkları gösteren yetkili bir acil durum aracının hemen yaklaşması üzerine, Louisiana RS 32:125, diğer her aracın sürücüsünün ne yapmasını gerektirir?","options":["İleride kavşağı boşaltmak için hızlanmak","Orta şeride geçmek ve yavaşlamak","Sağ kenara veya kaldırım kenarına çekmek, herhangi bir kavşaktan uzakta durmak","Kavşağın içinde bile olsa, aracın bulunduğu yerde derhal durmak"],"explanation":"RS 32:125, sağ kenara veya kaldırım kenarına mümkün olduğunca paralel ve yakın bir konuma çekilerek, herhangi bir kavşaktan uzakta durarak ve acil durum aracı geçene kadar bekleyerek geçiş üstünlüğü tanınmasını gerektirir. Kaynak: Louisiana RS 32:125."},"67":{"q":"Louisiana'da çok şeritli bir otoyolda, sol şeritte geçmek isteyen daha hızlı bir aracı engelleyen yavaş bir ticari araç, RS 32:71 kapsamında ne yapmalıdır?","options":["Bir sonraki çıkışa kadar konumunu korumak","Hızlı bir şekilde sağ şeride geçmek","Aracın sağdan geçmesine izin vermek için daha da yavaşlamak","Sol bankete geçmek"],"explanation":"RS 32:71, sol şeridi geçen bir aracı engellemek veya tıkamak için kullanmayı yasaklar; daha yavaş araç hızlı bir şekilde sağ şeride geçmelidir. İlk ihlal cezası 150 dolardır. Kaynak: Louisiana RS 32:71."},"68":{"q":"Louisiana'da bir CMV, tek yönlü veya bölünmüş bir otoyolun banketinde durduğunda, üç adet acil durum uyarı cihazı (üçgen) nereye yerleştirilmelidir?","options":["Yaklaşan trafiğe doğru 10 feet, 100 feet ve 200 feet","Yaklaşan trafiğe doğru 10 feet, 50 feet ve 150 feet","Yaklaşan trafiğe doğru 25 feet, 100 feet ve 250 feet","Yaklaşan trafiğe doğru 15 feet, 75 feet ve 200 feet"],"explanation":"Louisiana CDL El Kitabı (federal kuralı benimseyerek), tek yönlü veya bölünmüş bir otoyolda ya da yanında durulduğunda uyarı cihazlarının yaklaşan trafiğe doğru 10 feet, 100 feet ve 200 feet'e yerleştirilmesini gerektirir. Kaynak: Louisiana CDL El Kitabı, Sec. 2.5 (Warning Devices)."},"69":{"q":"Louisiana'da bir CMV'yi bir yolda veya bankette durdurduktan sonra, sürücü acil durum uyarı cihazlarını kaç dakika içinde yerleştirmelidir?","options":["5 dakika","10 dakika","15 dakika","30 dakika"],"explanation":"Louisiana CDL El Kitabı, bir yolda veya bankette durmanız gerekirse acil durum uyarı cihazlarınızı 10 dakika içinde yerleştirmeniz gerektiğini belirtir. Kaynak: Louisiana CDL El Kitabı, Sec. 2.5 (Warning Devices)."},"70":{"q":"Louisiana'da her iki yönde de trafik taşıyan iki şeritli bir yolda, durmuş bir CMV uyarı üçgenlerini aracın önüne ve arkasına nereye yerleştirmelidir?","options":["200 feet öne ve 200 feet arkaya","100 feet öne ve 100 feet arkaya","50 feet öne ve 100 feet arkaya","10 feet öne ve 10 feet arkaya"],"explanation":"İki yönlü/bölünmemiş bir yolda Louisiana CDL El Kitabı, aracın 10 feet yakınına bir cihaz ve önüne 100 feet, arkasına 100 feet birer cihaz yerleştirilmesini gerektirir. Kaynak: Louisiana CDL El Kitabı, Sec. 2.5 (Warning Devices)."},"71":{"q":"Louisiana'da bir okul otobüsü bir demiryolu geçidine yaklaşıyor. CDL El Kitabı, otobüsün tehlike uyarı ışıklarının geçitten yaklaşık ne kadar önce yakılmasını önerir?","options":["50 feet","100 feet","200 feet","500 feet"],"explanation":"Louisiana CDL El Kitabı'nın okul otobüsü prosedürleri, tehlike ışıklarının geçitten yaklaşık 200 feet önce yakılmasını, ardından en yakın raydan 15 ile 50 feet arasında durulmasını önerir. Kaynak: Louisiana CDL El Kitabı, Sec. 10.4.3 (Recommended Procedures)."},"72":{"q":"Louisiana'da bir otobüs, sinyal ışığı OLMAYAN ve trafik kontrol görevlisi OLMAYAN bir açılır köprüye ulaşıyor. Sürücü, köprünün açılır bölümünden en az ne kadar önce durmalıdır?","options":["15 feet","30 feet","50 feet","100 feet"],"explanation":"Louisiana CDL El Kitabı, sinyal ışığı veya trafik kontrol görevlisi olmayan bir açılır köprünün açılır bölümünden en az 50 feet önce durulmasını ve geçmeden önce açılır bölümün tamamen kapalı olduğunun doğrulanmasını gerektirir. Kaynak: Louisiana CDL El Kitabı, Sec. 4.3.6 (Drawbridges)."},"73":{"q":"Louisiana'da bir sürücü, tehlikeli maddeler için PLAKARTLI (levhalı) bir CMV kullanırken bir demiryolu-otoyol hemzemin geçit ihlali işlerse, asgari CDL diskalifiye süresi nedir?","options":["60 gün","120 gün","1 yıl","3 yıl"],"explanation":"Louisiana CDL El Kitabı, tehlikeli maddeler için plakartlı bir CMV kullanırken bir demiryolu geçit ihlali meydana gelirse CDL'nizi en az üç yıl kaybedeceğinizi belirtir (plakartlı olmayan ciddi geçit ihlalleri için 60/120 güne kıyasla). Kaynak: Louisiana CDL El Kitabı, Sec. 1.2.5 (Railroad-highway Grade Crossing Violations)."},"74":{"q":"Louisiana DOTD'den bir geniş gabari (oversize) izni olmadan, Louisiana otoyollarında bir ticari araç ve yük için azami yasal GENİŞLİK nedir?","options":["8 feet 0 inches","8 feet 6 inches","9 feet 0 inches","10 feet 0 inches"],"explanation":"Louisiana'nın yasal boyut sınırları 8 feet 6 inches genişlik, 13 feet 6 inches yükseklik ve 80,000 pounds'tur; bunları aşan yükler, hareketi genellikle gün doğumundan gün batımına kadar kısıtlanmış olan bir DOTD geniş gabari/aşırı yük izni gerektirir. Kaynak: Louisiana DOTD Weights & Standards; LAC Title 73, Part I, Chapter 3."},"75":{"q":"Louisiana'da Ticari Sürücü Belgelerini (CDL) hangi kurum verir?","options":["Louisiana Motorlu Taşıtlar Dairesi (OMV)","Louisiana Eyalet Polisi","Federal Motorlu Taşıyıcı Güvenliği İdaresi (FMCSA)","Louisiana Ulaştırma ve Kalkınma Bakanlığı (DOTD)"],"explanation":"Louisiana'da CDL'ler, Louisiana Kamu Güvenliği Bakanlığı'nın bir parçası olan Motorlu Taşıtlar Dairesi (OMV) tarafından verilir. FMCSA federal standartları belirler ancak belge vermez; DOTD yolları ve geniş gabari/aşırı yük izinlerini yönetir, CDL'leri değil. Kaynak: Louisiana OMV CDL sayfaları (expresslane.la.gov)."},"76":{"q":"Belge alınmadan önce, her Louisiana CDL başvuru sahibi öncelikle hangi belgeyi edinmelidir?","options":["Ticari Öğrenci Ehliyeti (CLP)","Bir federal eyaletler arası işletme yetkisi numarası","Bir DOTD geniş gabari/aşırı yük izni","Geçici bir şoför onayı (endorsement)"],"explanation":"Louisiana'da CDL beceri testine girip belge alabilmeniz için önce bir Ticari Öğrenci Ehliyeti (CLP) tutmanız gerekir. CLP, bir CDL sahibi eşliğinde halka açık yollarda pratik yapmanıza olanak tanır. Kaynak: Louisiana OMV 'New CDL' sayfası."},"77":{"q":"Bir Louisiana CLP sahibi, CDL beceri testine girmeye uygun hale gelmeden önce, ehliyet ilk verildikten sonra ne kadar beklemelidir?","options":["14 gün","30 gün","10 gün","60 gün"],"explanation":"Louisiana, federal 14 günlük bekleme süresini uygular: bir CLP sahibi, CLP'nin ilk verilmesinden sonraki ilk 14 gün boyunca CDL beceri testine girmeye uygun değildir. Kaynak: Louisiana OMV 'New CDL' sayfası (49 CFR 383.25)."},"78":{"q":"Bir Louisiana CLP'sinin, ilk süresi artı izin verilen uzatma sayıldığında geçerli kalabileceği azami süre nedir?","options":["360 gün (180 gün artı bir kez 180 günlük uzatma)","Uzatmaya izin verilmeden 180 gün","1 yıl (365 gün)","90 gün artı bir kez 90 günlük uzatma"],"explanation":"Bir Louisiana CLP'si en fazla 180 gün için verilir ve toplam 360 gün olmak üzere bir kez 180 gün daha uzatılabilir. Kaynak: Louisiana OMV 'New CDL' sayfası (49 CFR 383.25)."},"79":{"q":"Bir Louisiana CDL/CLP başvuru sahibi, faaliyet göstereceği ticaret türüne ilişkin olarak kaç farklı öz beyan (self-certification) kategorisinden seçim yapmalıdır?","options":["Dört","İki","Üç","Beş"],"explanation":"Dört öz beyan kategorisi vardır: Non-Excepted Interstate (NI), Excepted Interstate (EI), Non-Excepted Intrastate (NA) ve Excepted Intrastate (EA). Kaynak: Louisiana OMV CDL öz beyan materyalleri (49 CFR 383.71)."},"80":{"q":"Hangi iki öz beyan kategorisi, bir Louisiana CDL sahibinin dosyasında bir Tıbbi Muayene Sertifikasına (Medical Examiner's Certificate) sahip olmasını ve bunu güncel tutmasını gerektirir?","options":["Non-Excepted Interstate ve Non-Excepted Intrastate","Excepted Interstate ve Excepted Intrastate","Non-Excepted Interstate ve Excepted Interstate","Excepted Intrastate ve Non-Excepted Intrastate"],"explanation":"Non-Excepted Interstate (NI) veya Non-Excepted Intrastate (NA) olarak öz beyanda bulunan sürücüler, tıbbi yeterlilik standartlarını karşılamalı ve dosyalarında güncel bir Tıbbi Muayene Sertifikası bulundurmalıdır. 'Excepted' (muaf) kategorilerin (EI, EA) buna uyması gerekmez. Kaynak: Louisiana OMV öz beyan materyalleri (49 CFR 383.71)."},"81":{"q":"Yalnızca Louisiana içinde ücret karşılığı yük taşıyan ve tıbbi standartları karşılaması gereken bir sürücü hangi kategori altında öz beyanda bulunmalıdır?","options":["Non-Excepted Intrastate (NA)","Non-Excepted Interstate (NI)","Excepted Interstate (EI)","Excepted Intrastate (EA)"],"explanation":"Ticari faaliyeti yalnızca Louisiana içinde ('intrastate') yürütmek ve tıbbi yeterlilik standartlarına tabi olmak, Non-Excepted Intrastate (NA) kategorisidir. Interstate kategorileri eyalet sınırlarını geçmek için geçerlidir. Kaynak: Louisiana OMV öz beyan tanımları (49 CFR 383.71)."},"82":{"q":"Non-excepted olarak öz beyanda bulunan bir Louisiana CDL başvuru sahibi, tıbbi yeterlilik kanıtı olarak hangi tıbbi formu sunmalıdır?","options":["Tıbbi Muayene Sertifikası (form MCSA-5876)","Bir DOTD geniş gabari/aşırı yük tıbbi muafiyeti","CDL Ek Formu (DPSMV2211)","Bir Louisiana Eyalet Polisi uygunluk beyannamesi"],"explanation":"Non-excepted CDL başvuru sahipleri, sertifikalı bir muayene uzmanı tarafından doldurulmuş güncel bir Tıbbi Muayene Sertifikası (form MCSA-5876) sunmalıdır. DPSMV2211, tıbbi sertifika değil, CDL ek başvuru formudur. Kaynak: Louisiana OMV 'New CDL' / 'Submit CDL Medical Certificate' sayfaları."},"83":{"q":"Bir Louisiana CDL Tıbbi Muayene Sertifikasının dayandığı fiziksel muayeneyi yapmaya kim yetkilidir?","options":["FMCSA Ulusal Sertifikalı Tıbbi Muayene Uzmanları Sicilinde (National Registry of Certified Medical Examiners) listelenen bir tıbbi muayene uzmanı","Sürücü tarafından seçilen herhangi bir ruhsatlı hekim","Louisiana OMV tarafından istihdam edilen bir hekim","Sicil durumuna bakılmaksızın herhangi bir ruhsatlı pratisyen hemşire"],"explanation":"Fiziksel muayene, FMCSA Ulusal Sertifikalı Tıbbi Muayene Uzmanları Sicilinde sertifikalı ve listelenmiş bir tıbbi muayene uzmanı tarafından yapılmalıdır. Kaynak: Louisiana OMV 'New CDL' / CDL tıbbi sertifika bilgi sayfaları."},"84":{"q":"Louisiana OMV, bir CDL Tıbbi Muayene Sertifikasını aşağıdaki yöntemlerden hangisiyle kabul eder?","options":["OMV'ye e-posta, faks veya standart posta yoluyla","Yalnızca bir OMV saha ofisine bizzat giderek","Yalnızca muayene uzmanının onu FMCSA'ya yüklemesiyle","Yalnızca noter onaylı bir kapak sayfasıyla iadeli taahhütlü posta yoluyla"],"explanation":"Louisiana OMV, Tıbbi Muayene Sertifikasını e-posta (OMV_CDL_Medical@dps.la.gov), faks veya standart posta yoluyla kabul eder. Kaynak: Louisiana OMV 'Submit CDL Medical Certificate' sayfası."},"85":{"q":"Louisiana OMV, bir CDL sahibinin tıbbi sertifikasının sona ermesinden ne kadar önce yeni bir tıbbi muayene talep eden bir bildirim gönderir?","options":["Sona ermeden 60 gün önce","Sona ermeden 30 gün önce","Sona ermeden 90 gün önce","Sona ermeden 10 gün önce"],"explanation":"Louisiana OMV, dosyadaki tıbbi sertifikanın sona ermesinden 60 gün önce müşteriye, yeni bir muayene formu ve sertifikası talep eden bir bildirim oluşturur. Kaynak: Louisiana OMV CDL tıbbi sertifika bilgi sayfası."},"86":{"q":"Bir Louisiana CDL sahibi yeni bir tıbbi sertifika sunmazsa, sürücü ne zaman 'medically not certified' (tıbbi olarak sertifikalı değil) olarak işaretlenir?","options":["Dosyadaki tıbbi sertifikanın sona ermesinden 10 gün sonra","Sona erme tarihinde derhal","Sertifikanın sona ermesinden 60 gün sonra","Sertifikanın sona ermesinden 30 gün sonra"],"explanation":"Öz beyan/tıbbi gerekliliklerin karşılanmaması, dosyadaki tıbbi sertifikanın sona ermesinden 10 gün sonra sürücünün 'medically not certified' olarak işaretlenmesiyle sonuçlanır; uyumsuzluk devam ederse CDL daha sonra iptal edilir. Kaynak: Louisiana OMV CDL tıbbi sertifika bilgi sayfası."},"87":{"q":"Louisiana CDL beceri testi, sırayla gerçekleştirilen hangi üç bölümden oluşur?","options":["Sefer öncesi muayene, temel araç kontrolü ve yol üzerinde sürüş","Yazılı bilgi, görme taraması ve yol üzerinde sürüş","Sefer öncesi muayene, hazmat ile başa çıkma ve hava freni boşaltma","Temel araç kontrolü, seyir defteri denetimi ve yol üzerinde sürüş"],"explanation":"Louisiana'da CDL beceri testinin üç bölümü vardır: sefer öncesi muayene, temel araç kontrol testi ve yol üzerinde sürüş testi. Kaynak: Louisiana CDL el kitabı / Louisiana OMV CDL sayfaları (49 CFR 383.113)."},"88":{"q":"Bir Louisiana başvuru sahibi, ilk Class A veya Class B belgesi için CDL beceri testine girmeden önce hangi eğitimi tamamlamalıdır?","options":["FMCSA'da kayıtlı bir sağlayıcıdan Giriş Düzeyi Sürücü Eğitimi (ELDT)","Bir Louisiana OMV defansif sürüş kursu","Bir DOTD geniş gabarili yük taşıma kursu","Eyalet tarafından yürütülen bir tartı istasyonu muayene semineri"],"explanation":"FMCSA'nın Eğitim Sağlayıcı Sicilinde (Training Provider Registry) listelenen bir okul tarafından verilen Giriş Düzeyi Sürücü Eğitimi (ELDT), ilk CDL için beceri testine girmeden (ve hazmat bilgi testinden) önce tamamlanmalıdır. Kaynak: Louisiana OMV 'New CDL' sayfası (49 CFR Part 380 Subpart F)."},"89":{"q":"Test öncesinde, bir Louisiana CDL başvuru sahibinin Ticari Öğrenci Ehliyeti almaya hak kazanmak için geçmesi gereken ilk test nedir?","options":["Genel bilgi yazılı (bilgi) testi","Yol üzerinde sürüş beceri testi","Temel araç kontrol testi","Sefer öncesi muayene testi"],"explanation":"Başvuru sahipleri, bir CLP almak için genel bilgi testiyle başlayarak gerekli yazılı bilgi testlerini geçmelidir; beceri testleri daha sonra, CLP tutulduktan sonra gelir. Kaynak: Louisiana CDL el kitabı / OMV CDL sayfaları."},"90":{"q":"50 soruluk Louisiana CDL genel bilgi yazılı testinde, geçmek için gereken asgari puan nedir?","options":["%80 (50 sorudan 40'ı doğru)","%70 (50 sorudan 35'i doğru)","%75 (50 sorudan 38'i doğru)","%90 (50 sorudan 45'i doğru)"],"explanation":"Genel bilgi testinde 50 çoktan seçmeli soru bulunur ve federal CDL standardıyla tutarlı olarak geçmek için %80 (50 sorudan 40'ı) puan gerekir. Kaynak: Louisiana CDL el kitabı / OMV test materyalleri (49 CFR 383.135)."},"91":{"q":"Eyalet içi (intrastate) işletmeyle sınırlı bir Louisiana CDL'si almak için asgari yaş nedir?","options":["18 yaş","21 yaş","19 yaş","16 yaş"],"explanation":"Bir başvuru sahibi, eyalet içi işletmeyle sınırlı bir Louisiana CDL'si tutmak için en az 18 yaşında olmalıdır; eyaletler arası sürüş ve tehlikeli madde taşımacılığı için 21 yaş gereklidir. Kaynak: Louisiana OMV CDL sayfaları (49 CFR 383.3 / 391.11)."},"92":{"q":"Bir Louisiana CDL başvuru sahibi, kimlik ve tıbbi sertifikaya ek olarak, başvuru sırasında hangi belgeyi sağlamalıdır?","options":["Louisiana ikametgah kanıtı (örneğin fatura belgeleri veya bir kira sözleşmesi)","Noter onaylı bir işveren sponsorluk mektubu","Amaçlanan kargo için bir DOTD güzergah etüdü","Taşıyıcının USDOT işletme yetkisinin bir kopyası"],"explanation":"Louisiana, CDL Ek Formu (DPSMV2211) ve Tıbbi Muayene Sertifikası ile birlikte Louisiana ikametgah kanıtı (örneğin fatura belgeleri, kira sözleşmesi, seçmen kaydı) gerektirir. Kaynak: Louisiana OMV 'New CDL' sayfası."},"93":{"q":"Bir Louisiana CDL'si, yenilenmesi gerekmeden önce normalde kaç yıl geçerlidir?","options":["6 yıl","4 yıl","8 yıl","5 yıl"],"explanation":"Bir Louisiana CDL'si genellikle 6 yıl geçerlidir. İşletme türü öz beyanı ve (non-excepted sürücüler için) güncel bir tıbbi sertifika, bu süre boyunca sürdürülmelidir. Kaynak: Louisiana OMV CDL yenileme bilgileri."},"94":{"q":"Üçüncü taraf bir muayene uzmanı tarafından yürütülen Louisiana CDL beceri testinin ücretiyle ilgili olarak, hangi ifade en doğru süreç tanımıdır?","options":["Beceri testi, onaylı üçüncü taraf muayene uzmanları aracılığıyla yapılabilir ve kesin ücret test eden tarafından belirlenir ve değişebilir; bu nedenle başvuru sahipleri güncel tutarı doğrulamalıdır","Beceri testi, herhangi bir OMV ofisinde yapıldığında her zaman ücretsizdir","Beceri testi ücreti federal yasayla sabitlenmiştir ve her eyalette aynıdır","Başvuru sahibi kendi aracını getirirse, asla bir beceri testi ücreti alınamaz"],"explanation":"Louisiana, beceri testinin onaylı üçüncü taraf muayene uzmanları tarafından yapılmasına izin verir ve ücret test eden tarafından belirlenir ve değişebilir; bu nedenle başvuru sahipleri sabit bir rakama güvenmek yerine güncel tutarı doğrulamalıdır. Kaynak: Louisiana OMV CDL sayfaları (üçüncü taraf test programı)."}},"es":{"0":{"q":"En las carreteras de Luisiana, ¿cuál es el ancho máximo legal de un vehículo comercial, sin contar los dispositivos de seguridad?","options":["96 inches","98 inches","102 inches","108 inches"],"explanation":"La ley Louisiana RS 32:380 establece el ancho máximo del vehículo en 102 inches (8 feet 6 inches), sin contar dispositivos de seguridad como los espejos. Fuente: Louisiana Revised Statutes 32:380."},"1":{"q":"¿Cuál es la altura máxima legal de un vehículo en Luisiana en carreteras distintas al sistema interestatal (Interstate)?","options":["13 feet","13 feet 6 inches","14 feet","14 feet 6 inches"],"explanation":"Conforme a la ley Louisiana RS 32:381, un vehículo y su carga no pueden exceder los 13 feet 6 inches de altura en carreteras que no sean del sistema interestatal (Interstate). Fuente: Louisiana Revised Statutes 32:381."},"2":{"q":"¿Cuál es la altura máxima legal de un vehículo en Luisiana para un vehículo que opera exclusivamente en el sistema de carreteras interestatales (Interstate)?","options":["13 feet 6 inches","14 feet","14 feet 6 inches","15 feet"],"explanation":"La ley Louisiana RS 32:381 permite una altura máxima de 14 feet para un vehículo y su carga que operen exclusivamente en el sistema de carreteras interestatales (Interstate), en comparación con los 13 feet 6 inches permitidos en otros lugares. Fuente: Louisiana Revised Statutes 32:381."},"3":{"q":"En Luisiana, ¿cuál es la longitud máxima legal de un vehículo individual (como un camión rígido o un autobús)?","options":["40 feet","45 feet","53 feet","59 feet 6 inches"],"explanation":"La ley Louisiana RS 32:382 limita un vehículo individual a una longitud máxima de 45 feet. Fuente: Louisiana Revised Statutes 32:382."},"4":{"q":"¿Cuál es la longitud máxima legal de la porción de semirremolque de una combinación tractocamión-semirremolque en Luisiana?","options":["48 feet","53 feet","57 feet","59 feet 6 inches"],"explanation":"La ley Louisiana RS 32:382 permite que la porción de semirremolque de una combinación tractocamión-semirremolque mida hasta 59 feet 6 inches; no existe un límite separado para la longitud total de la combinación en esta configuración. Fuente: Louisiana Revised Statutes 32:382."},"5":{"q":"¿Cuánto puede sobresalir una carga más allá del ancho de la carrocería en un vehículo de Luisiana?","options":["No más de 6 inches","No más de 12 inches","No más de 18 inches","No más de 24 inches"],"explanation":"La ley Louisiana RS 32:380 dispone que una carga no debe sobresalir más de 12 inches más allá del ancho de la carrocería del vehículo. Fuente: Louisiana Revised Statutes 32:380."},"6":{"q":"¿Cuál es el peso bruto máximo permitido para cualquier vehículo o combinación de vehículos en las carreteras de Luisiana sin un permiso?","options":["73,280 pounds","80,000 pounds","88,000 pounds","90,000 pounds"],"explanation":"La ley Louisiana RS 32:386 limita el peso bruto total de cualquier vehículo o combinación de vehículos a 80,000 pounds. Fuente: Louisiana Revised Statutes 32:386."},"7":{"q":"En Luisiana, ¿cuál es el peso bruto máximo permitido sobre un eje individual equipado con llantas neumáticas de baja presión?","options":["18,000 pounds","20,000 pounds","22,400 pounds","34,000 pounds"],"explanation":"La ley Louisiana RS 32:386 limita un eje individual equipado con llantas neumáticas de baja presión a 20,000 pounds. Fuente: Louisiana Revised Statutes 32:386."},"8":{"q":"¿Cuál es el peso bruto máximo permitido sobre un eje tándem en Luisiana bajo el límite legal general?","options":["32,000 pounds","34,000 pounds","37,000 pounds","40,000 pounds"],"explanation":"La ley Louisiana RS 32:386 limita un eje tándem equipado con llantas neumáticas de baja presión a 34,000 pounds. Fuente: Louisiana Revised Statutes 32:386."},"9":{"q":"Luisiana otorga una tolerancia de peso mayor para el eje tándem en vehículos que transportan productos forestales en su estado natural. ¿Cuál es ese límite y dónde NO aplica?","options":["37,000 pounds, excepto en el sistema interestatal (Interstate)","37,000 pounds, incluyendo el sistema interestatal (Interstate)","40,000 pounds, excepto en el sistema interestatal (Interstate)","34,000 pounds, aplica en todas partes"],"explanation":"La ley Louisiana RS 32:386 permite 37,000 pounds por eje tándem para vehículos que transportan productos forestales en su estado natural, excepto en el sistema interestatal (Interstate), donde aplica el límite estándar de 34,000 pounds. Fuente: Louisiana Revised Statutes 32:386."},"10":{"q":"Conforme a la ley Louisiana RS 32:386, ¿cuánto peso máximo por pulgada de ancho de llanta puede ejercer cualquier llanta de cualquier eje sobre la superficie de la carretera?","options":["500 pounds por pulgada","600 pounds por pulgada","650 pounds por pulgada","700 pounds por pulgada"],"explanation":"La ley Louisiana RS 32:386 establece que ninguna llanta debe ejercer sobre la superficie de la carretera un peso mayor a 650 pounds por pulgada de ancho de llanta. Fuente: Louisiana Revised Statutes 32:386."},"11":{"q":"¿Qué fórmula aplica Luisiana en el sistema interestatal (Interstate) para determinar el peso bruto máximo permitido sobre cualquier grupo de dos o más ejes consecutivos?","options":["La Federal Bridge Formula W = 500(LN/(N-1) + 12N + 36)","Un límite fijo de 80,000 pounds sin importar el espaciamiento de los ejes","La regla del eje individual de 20,000 pounds multiplicada por el número de ejes","Un peso igual a 650 pounds multiplicado por la distancia entre ejes en pulgadas"],"explanation":"La ley Louisiana RS 32:386 incorpora la Federal Bridge Formula, W = 500(LN/(N-1) + 12N + 36), para limitar el peso sobre ejes consecutivos en la Interstate, donde L es el espaciamiento de los ejes en feet y N es el número de ejes. Fuente: Louisiana Revised Statutes 32:386 (Federal Bridge Formula)."},"12":{"q":"En la Federal Bridge Formula utilizada en Luisiana, W = 500(LN/(N-1) + 12N + 36), ¿qué representan las variables L y N?","options":["L es la carga en toneladas; N es el número de llantas","L es la distancia en feet entre los ejes externos de un grupo; N es el número de ejes en ese grupo","L es la velocidad legal; N es el peso del eje","L es el ancho del carril; N es el número de remolques"],"explanation":"En la Federal Bridge Formula tal como la aplica la ley Louisiana RS 32:386, L es la distancia en feet entre los ejes extremos (externos) de cualquier grupo, y N es el número de ejes en ese grupo. Fuente: Louisiana Revised Statutes 32:386 / Federal Bridge Formula."},"13":{"q":"Un transportista de carga en Luisiana debe obtener un permiso por exceso de tamaño o peso cuando un vehículo o carga excede los límites legales. ¿Qué agencia emite estos permisos?","options":["La Oficina de Vehículos Motorizados de Luisiana (OMV)","El Louisiana Department of Transportation and Development (DOTD)","Solo la Policía Estatal de Luisiana","La oficina del alguacil (sheriff) de la parroquia local"],"explanation":"Los permisos por exceso de tamaño o peso en Luisiana son emitidos por el Department of Transportation and Development (DOTD) a través de su Truck Permit Office y el sistema electrónico de rutas PERBA. Fuente: Louisiana DOTD, Oversize and Overweight Truck Permits; LAC Title 73."},"14":{"q":"¿En qué momento debe obtenerse un permiso de Luisiana por exceso de tamaño o peso en relación con el desplazamiento?","options":["Dentro de las 24 horas posteriores a completar el desplazamiento","En cualquier estación de pesaje al borde de la carretera durante el viaje","Antes de que el vehículo o carga con exceso de tamaño o peso se desplace dentro de Luisiana o ingrese al estado","Solo después de que se emita una citación"],"explanation":"Se debe solicitar y obtener un permiso antes de que el vehículo o carga con exceso de tamaño o peso se desplace dentro del estado de Luisiana o ingrese a él. Fuente: reglas de permisos de exceso de tamaño/peso del Louisiana DOTD; LAC Title 73, Part I."},"15":{"q":"Un permiso anual de Luisiana por exceso de tamaño o peso (a diferencia de un permiso de viaje único) es válido para circular en ¿cuáles carreteras?","options":["Solo carreteras interestatales (Interstate)","Solo carreteras que no son interestatales (no Interstate)","Todas las carreteras estatales e interestatales (Interstate)","Solo caminos de la parroquia"],"explanation":"Los permisos anuales de Luisiana son válidos por un año y autorizan la circulación únicamente en carreteras que no son interestatales (no Interstate); los desplazamientos por la Interstate requieren un permiso de viaje único. Fuente: Louisiana DOTD Annual Permits; LAC Title 73, Part I, Chapter 3."},"16":{"q":"¿Qué monto mínimo de fianza o certificado de seguro exige Luisiana para un permiso de viaje único por exceso de tamaño o peso?","options":["$50,000","$100,000","$250,000","$500,000"],"explanation":"Luisiana exige una fianza o certificado de seguro de al menos $100,000 para un permiso de viaje único (y $250,000 para un permiso anual). Fuente: requisitos de permisos por exceso de tamaño/peso del Louisiana DOTD."},"17":{"q":"Luisiana ofrece un permiso especial para transportar productos agrícolas en su estado natural que excedan los límites legales de peso por eje o de peso bruto durante la cosecha. ¿Cómo se conoce comúnmente este permiso?","options":["Un permiso de temporada de cosecha (harvest season permit)","Un permiso de arrendamiento de viaje (trip lease permit)","Un permiso de tonelaje de hazmat","Un permiso de reciprocidad"],"explanation":"El Louisiana DOTD emite permisos de temporada de cosecha (harvest season permits) para vehículos que transportan productos agrícolas en su estado natural que exceden los límites legales de peso bruto o por eje; la tarifa anual es de $100. Fuente: Louisiana DOTD Harvest Season / Annual Permits; LAC Title 73, Part I."},"18":{"q":"Bajo los requisitos del permiso de transporte de caña de azúcar de Luisiana, ¿qué configuración de ejes debe tener la combinación de vehículo y remolque?","options":["Un mínimo de cuatro ejes en total","Un total de seis ejes, con un eje individual adicional que soporte carga en el remolque de caña de azúcar","Solo un eje tándem trasero","Un total de ocho ejes con todos los ejes elevables (lift axles) levantados"],"explanation":"Las disposiciones del permiso de cosecha de caña de azúcar de Luisiana exigen un total de seis ejes para la combinación de vehículo y remolque, incluido un eje individual adicional con llantas dobles en el remolque de caña de azúcar que se baja y funciona como eje que soporta carga. Fuente: disposiciones de permisos de cosecha del Louisiana DOTD; LAC Title 73, Part I."},"19":{"q":"En Luisiana, ¿qué clase de Licencia de Conducir Comercial (CDL) se requiere para operar una combinación de vehículos con un peso bruto combinado nominal (GCWR) de 26,001 pounds o más, donde el GVWR de la unidad remolcada es mayor a 10,000 pounds?","options":["Class B","Class A","Class C","Class D"],"explanation":"La ley Louisiana R.S. 32:408 B.(2)(a) define la CDL Class 'A' (Vehículos Combinados) como aquella que permite cualquier combinación de vehículos con un GCWR de 26,001 pounds o más, siempre que el GVWR de la(s) unidad(es) remolcada(s) sea superior a 10,000 pounds. Fuente: Louisiana CDL Manual (OMV), sección de clases."},"20":{"q":"Según las reglas de Luisiana, una CDL Class B autoriza la operación de cualquier vehículo individual con un GVWR de 26,001 pounds o más, con la opción de remolcar una unidad que no exceda ¿qué peso?","options":["5,000 pounds GVWR","15,000 pounds GVWR","26,001 pounds GVWR","10,000 pounds GVWR"],"explanation":"La ley Louisiana R.S. 32:408 B.(2)(b) define la CDL Class 'B' (Vehículo Rígido Pesado) como cualquier vehículo individual con un GVWR de 26,001 pounds o más, o ese mismo vehículo remolcando una unidad que no exceda 10,000 pounds GVWR. Remolcar más de 10,000 lbs pasa al conductor a la Class A. Fuente: Louisiana CDL Manual (OMV)."},"21":{"q":"Un conductor de Luisiana opera un camión rígido individual con una capacidad nominal de 24,000 pounds GVWR que lleva placas (placards) por materiales peligrosos. ¿Cuál es la clase mínima de CDL requerida?","options":["Class B","Class A","Class D","Class C"],"explanation":"La ley Louisiana R.S. 32:408 B.(2)(c) define la CDL Class 'C' (Vehículo Ligero) para vehículos individuales de menos de 26,001 pounds GVWR que estén diseñados para transportar 16 o más pasajeros (incluido el conductor) o que se usen para transportar cantidades de materiales peligrosos que requieren placas (placards). Un camión rígido de 24,000 lbs con placas de HazMat requiere la Class C más el endoso H. Fuente: Louisiana CDL Manual (OMV)."},"22":{"q":"En una CDL de Luisiana, ¿qué código de endoso autoriza la operación de remolques dobles y triples?","options":["N","X","T","H"],"explanation":"La ley Louisiana R.S. 32:408(3) enumera el endoso 'T' para Remolques Dobles/Triples. (N = Tanque, H = Materiales Peligrosos, X = combinación de Tanque y HazMat.) Fuente: Louisiana CDL Manual (OMV), sección de endosos."},"23":{"q":"¿Cuál es la edad mínima para obtener una CDL de Luisiana solo para conducir de manera INTRAESTATAL (dentro del estado)?","options":["21 años","19 años","17 años","18 años"],"explanation":"La ley Louisiana R.S. 32:408 establece el requisito de edad para las CDL Class A, B y C en 18 años o más para conducción intraestatal y 21 años o más para conducción interestatal. Fuente: Louisiana CDL Manual (OMV), sección de clases."},"24":{"q":"Una persona de 19 años tiene una CDL de Luisiana válida. ¿Qué operación se le permite realizar?","options":["Conducir un CMV en comercio interestatal","Transportar materiales peligrosos con placas (placards)","Conducir un CMV en comercio intraestatal dentro de Luisiana","Tener un endoso H (HazMat)"],"explanation":"Luisiana fija la edad para la CDL en 18 años para conducción intraestatal pero en 21 años para interestatal, y el endoso H (HazMat) se 'emite únicamente a personas de 21 años de edad o más'. Una persona de 19 años solo puede conducir de manera intraestatal y no puede obtener un endoso de HazMat. Fuente: Louisiana CDL Manual (OMV), R.S. 32:408."},"25":{"q":"En Luisiana, el endoso H (Materiales Peligrosos) solo puede emitirse a solicitantes que tengan al menos ¿qué edad?","options":["18 años","25 años","19 años","21 años"],"explanation":"La lista de endosos del Louisiana CDL Manual (R.S. 32:408(3)) indica que el endoso 'H' de Materiales Peligrosos se 'emite únicamente a personas de 21 años de edad o más', en consonancia con la naturaleza exclusivamente interestatal del transporte de HazMat con placas (placards). Fuente: Louisiana CDL Manual (OMV)."},"26":{"q":"Antes de que se emita un endoso de HazMat (H) de Luisiana, un solicitante debe aprobar ¿cuál evaluación adicional?","options":["Un reexamen únicamente de la vista","Un curso de manejo defensivo en aula de 36 horas","Una prueba de manejo en un vehículo cisterna","Una evaluación de amenazas a la seguridad de la TSA que incluye toma de huellas dactilares y verificación de antecedentes"],"explanation":"El Louisiana CDL Manual (Sección 1.2.6) indica que un endoso de HazMat requiere presentar huellas dactilares y una verificación de antecedentes; se le niega a un solicitante si la Transportation Security Administration (TSA) lo considera una amenaza para la seguridad. La verificación de antecedentes mediante huellas dactilares debe realizarse dentro de los 180 days más recientes. Fuente: Louisiana CDL Manual (OMV), TSA / 49 CFR 1572."},"27":{"q":"A un solicitante de un endoso de HazMat de Luisiana se le NEGARÁ el endoso bajo ¿cuál de las siguientes condiciones?","options":["Tiene menos de dos años de experiencia con la CDL","Es menor de 25 años de edad","No es residente permanente legal de los Estados Unidos","No tiene una CDL Class A"],"explanation":"Según el Louisiana CDL Manual Sección 1.2.6, se le negará o perderá el endoso de HazMat si no es residente permanente legal de los EE. UU., renuncia a la ciudadanía estadounidense, está requerido/bajo acusación formal o condenado por ciertos delitos graves, ha sido declarado deficiente mental, o la TSA lo considera una amenaza para la seguridad. Fuente: Louisiana CDL Manual (OMV); regla HME de la TSA."},"28":{"q":"Un endoso de vehículo cisterna (N) de Luisiana se requiere cuando un vehículo que necesita una CDL Class A o B transporta líquidos/gases en un tanque de carga montado permanentemente con una capacidad nominal mínima de ¿cuánto?","options":["119 gallons o más","100 gallons o más","500 gallons o más","1,000 gallons o más"],"explanation":"El Louisiana CDL Manual (Sección 8, Vehículos Cisterna) indica que se requiere un endoso de tanque si su vehículo necesita una CDL Class A o B y usted transporta un líquido o gas en un tanque de carga montado permanentemente con una capacidad nominal de 119 gallons o más, O un tanque portátil con una capacidad nominal de 1,000 gallons o más. Fuente: Louisiana CDL Manual (OMV)."},"29":{"q":"Para el endoso de tanque (N) de Luisiana, un tanque PORTÁTIL activa el requisito del endoso cuando tiene una capacidad nominal mínima de ¿cuánto?","options":["119 gallons o más","1,000 gallons o más","660 gallons o más","2,000 gallons o más"],"explanation":"El Louisiana CDL Manual especifica que el endoso de tanque aplica a un tanque portátil con una capacidad nominal de 1,000 gallons o más (frente a 119 gallons o más para un tanque de carga montado permanentemente). Fuente: Louisiana CDL Manual (OMV), sección de Vehículos Cisterna."},"30":{"q":"¿Qué código de endoso en una CDL de Luisiana representa la COMBINACIÓN de Vehículos Cisterna Y Materiales Peligrosos?","options":["T","X","N","H"],"explanation":"La ley Louisiana R.S. 32:408(3) enumera el endoso 'X' como la combinación de Vehículos Cisterna y Materiales Peligrosos. (N = solo Tanque, H = solo HazMat, T = Dobles/Triples.) Fuente: Louisiana CDL Manual (OMV), sección de endosos."},"31":{"q":"¿Qué endoso de la CDL de Luisiana se requiere específicamente para conducir un autobús escolar?","options":["S","P","T","N"],"explanation":"La ley Louisiana R.S. 32:408(3) enumera el endoso 'S' para Autobús Escolar. El endoso 'P' (Pasajeros) cubre los autobuses en general y también es obligatorio, pero el endoso específico para autobús escolar es la 'S'. Fuente: Louisiana CDL Manual (OMV), sección de endosos."},"32":{"q":"Bajo el estándar federal aplicado en Luisiana, después de que se emite por primera vez un Permiso de Aprendiz Comercial (CLP), ¿cuánto tiempo como mínimo debe esperar el titular antes de poder presentar la prueba de habilidades de la CDL?","options":["14 days","7 days","30 days","10 days"],"explanation":"Conforme a 49 CFR 383.25(e), adoptado en Luisiana, el titular de un CLP no es elegible para presentar la prueba de habilidades de la CDL dentro de los primeros 14 days después de la emisión inicial del CLP. Este período de espera de 14 days brinda tiempo para practicar al volante. Fuente: 49 CFR 383.25(e); requisitos de CDL de la Louisiana OMV."},"33":{"q":"Mientras practica en un CMV con un CLP de Luisiana, el titular del permiso debe estar acompañado en todo momento por ¿quién?","options":["Cualquier conductor con licencia Class E mayor de 21 años","Un titular de CDL con la clase y los endosos adecuados sentado en el asiento delantero","Únicamente un examinador certificado de un tercero","No se requiere supervisión una vez aprobada la prueba de conocimientos"],"explanation":"Las reglas del CLP de la Louisiana OMV (conforme a 49 CFR 383.25) exigen que el titular del CLP esté acompañado por un titular válido de CDL que posea la clase y los endosos adecuados, sentado en el asiento delantero (cabina) del vehículo, durante toda la operación al volante. Fuente: página New CDL de la Louisiana OMV; 49 CFR 383.25."},"34":{"q":"Además de los solicitantes por primera vez de las Class A y Class B, el ELDT se requiere en Luisiana para los solicitantes por primera vez que buscan ¿cuáles endosos?","options":["Materiales Peligrosos (H), Pasajeros (P) y Autobús Escolar (S)","Solo Tanque (N) y Dobles/Triples (T)","Solo Motocicleta (M) y Pasajeros (P)","Todos los endosos sin excepción"],"explanation":"El ELDT de la FMCSA (vigente desde el 7 de febrero de 2022, aplicado en Luisiana) cubre a los solicitantes por primera vez de una CDL Class A o B, las actualizaciones de B a A, y a los solicitantes por primera vez de los endosos de Materiales Peligrosos (H), Pasajeros (P) y Autobús Escolar (S). Los endosos de Tanque (N) y Dobles/Triples (T) no están cubiertos por el ELDT. Fuente: FMCSA Training Provider Registry / Aplicabilidad del ELDT."},"35":{"q":"En Luisiana, ¿cuál es la concentración máxima de alcohol en la sangre (BAC) que puede tener un conductor mientras opera un vehículo motorizado comercial (CMV) antes de ser considerado legalmente intoxicado para fines de la CDL?","options":["0.04 percent","0.08 percent","0.02 percent","0.10 percent"],"explanation":"La ley de Luisiana establece el límite de BAC en CMV en 0.04 percent, la mitad del límite de 0.08 percent para conductores no comerciales. Un titular de CDL que opera un CMV con 0.04 percent o más se considera bajo los efectos del alcohol. Fuente: La. R.S. 32:414.2 y el Louisiana CDL Manual (Sección 1.2, Descalificaciones)."},"36":{"q":"Al tener una CDL de Luisiana y operar un vehículo comercial, ¿qué se considera automáticamente que el conductor ha aceptado hacer?","options":["Someterse a pruebas químicas de aliento, sangre u orina cuando se le solicite legalmente","Llevar en todo momento una copia del registro federal de horas de servicio","Renunciar al derecho a una audiencia judicial sobre cualquier multa de tránsito","Pagar todas las tarifas de peaje electrónicamente en lugar de en efectivo"],"explanation":"Bajo la ley de consentimiento implícito de Luisiana, se considera que toda persona que opera un CMV ha consentido a una prueba química de aliento, sangre u orina para determinar la presencia de alcohol o drogas cuando un oficial tiene causa razonable. Fuente: La. R.S. 32:414.2 (consentimiento implícito) y el Louisiana CDL Manual."},"37":{"q":"¿Por cuánto tiempo se descalifica a un titular de CDL de Luisiana por una primera infracción mayor, como operar un CMV con un BAC de 0.04 percent o más?","options":["1 year","60 days","6 months","3 years"],"explanation":"Una primera infracción mayor (incluyendo DUI, BAC de 0.04 percent o más en un CMV, negarse a una prueba o abandonar la escena) resulta en una descalificación de 1 year bajo la ley de Luisiana, lo cual refleja la regla 49 CFR 383.51. Fuente: La. R.S. 32:414.2 y el Louisiana CDL Manual."},"38":{"q":"Si un titular de CDL de Luisiana comete una primera infracción mayor mientras opera un CMV que lleva placas (placards) por materiales peligrosos, el período de descalificación aumenta a:","options":["3 years","1 year","2 years","De por vida"],"explanation":"Cuando una primera infracción mayor ocurre en un CMV que debe llevar placas (placards) por materiales peligrosos, la descalificación se extiende de 1 year a 3 years. Fuente: La. R.S. 32:414.2 y 49 CFR 383.51, según se adoptan en el Louisiana CDL Manual."},"39":{"q":"¿Cuál es el período de descalificación para un titular de CDL de Luisiana que es condenado por una segunda infracción mayor (por ejemplo, un segundo DUI en un CMV)?","options":["Descalificación de por vida","Descalificación de 10 years","Descalificación de 5 years","Descalificación de 3 years"],"explanation":"Una segunda condena por cualquier combinación de infracciones mayores resulta en una descalificación de la CDL de por vida en Luisiana, en concordancia con 49 CFR 383.51. (Bajo las reglas federales puede existir un mínimo de 10 years para la reinstalación.) Fuente: La. R.S. 32:414.2 y el Louisiana CDL Manual."},"40":{"q":"A un titular de CDL de Luisiana se le solicita legalmente someterse a una prueba química y se niega. ¿Cuál es la consecuencia para la CDL?","options":["Descalificación de al menos 1 year, igual que una condena por DUI","Solo una advertencia en la primera negativa","Descalificación de 60 days","Ninguna consecuencia para la CDL si se desestiman los cargos penales"],"explanation":"Negarse a una prueba química bajo la ley de consentimiento implícito de Luisiana resulta en una descalificación de la CDL de al menos 1 year, igual que una infracción mayor, y esto aplica independientemente del resultado de cualquier caso penal. Fuente: La. R.S. 32:414.2 y el Louisiana CDL Manual."},"41":{"q":"¿Cuál de las siguientes se clasifica como una 'infracción de tránsito grave' para un titular de CDL de Luisiana?","options":["Exceso de velocidad de 15 mph o más por encima del límite señalado","Exceso de velocidad de 5 mph por encima del límite señalado","Una infracción de estacionamiento en una zona comercial","Conducir con una calcomanía de registro vencida"],"explanation":"Exceder la velocidad en 15 mph o más por encima del límite señalado es una de las infracciones de tránsito graves listadas para titulares de CDL. Otras incluyen conducción imprudente, cambios de carril indebidos o erráticos, y seguir a otro vehículo demasiado de cerca. Fuente: 49 CFR 383.51 según se adopta en el Louisiana CDL Manual."},"42":{"q":"¿Por cuánto tiempo se descalifica a un titular de CDL de Luisiana por ser condenado por DOS infracciones de tránsito graves dentro de un período de 3 years?","options":["60 days","30 days","120 days","1 year"],"explanation":"Una segunda infracción de tránsito grave dentro de 3 years (en incidentes separados) resulta en una descalificación de 60 days bajo la ley de Luisiana, en concordancia con 49 CFR 383.51. Fuente: La. R.S. 32:414.2 y el Louisiana CDL Manual."},"43":{"q":"¿Por cuánto tiempo se descalifica a un titular de CDL de Luisiana por ser condenado por TRES infracciones de tránsito graves dentro de un período de 3 years?","options":["120 days","60 days","90 days","180 days"],"explanation":"Una tercera infracción de tránsito grave dentro de 3 years (en incidentes separados) resulta en una descalificación de 120 days, cumplida de manera consecutiva a cualquier período previo de 60 days. Fuente: 49 CFR 383.51 según se adopta en el Louisiana CDL Manual y La. R.S. 32:414.2."},"44":{"q":"Usar un teléfono celular de mano mientras se conduce un vehículo motorizado comercial en Luisiana, ¿qué tipo de infracción se considera para fines de la CDL?","options":["Una infracción de tránsito grave que cuenta para la descalificación","Una infracción sin movimiento sin impacto en la CDL","Una infracción mayor automática de 1 year","Una infracción solo si resulta en un accidente"],"explanation":"Usar un teléfono de mano o enviar mensajes de texto mientras se opera un CMV es una infracción de tránsito grave que cuenta para los umbrales de descalificación de 2-en-3-años (60 days) y 3-en-3-años (120 days). Fuente: 49 CFR 383.51 / 392.82 según se adopta en el Louisiana CDL Manual."},"45":{"q":"Enviar mensajes de texto mientras se conduce un CMV también es una infracción grave. La sanción civil federal que puede enfrentar un conductor de CMV por enviar mensajes de texto, según se menciona en las reglas de la CDL aplicadas en Luisiana, puede llegar a ser de aproximadamente:","options":["$2,750","$500","$1,000","$10,000"],"explanation":"Más allá de la descalificación de la CDL, un conductor de CMV que envía mensajes de texto mientras conduce enfrenta una sanción civil federal de hasta aproximadamente $2,750. Fuente: 49 CFR 392.80/392.82, mencionada en el Louisiana CDL Manual."},"46":{"q":"¿Cuál es la descalificación mínima para la PRIMERA condena de un titular de CDL de Luisiana por una infracción en un cruce a nivel de ferrocarril y carretera?","options":["60 days","30 days","120 days","1 year"],"explanation":"Una primera infracción en un cruce a nivel de ferrocarril y carretera (como no detenerse o no tener espacio suficiente para librar el cruce) conlleva una descalificación mínima de 60 days en Luisiana. Fuente: 49 CFR 383.51 según se adopta en el Louisiana CDL Manual."},"47":{"q":"Un titular de CDL de Luisiana comete una SEGUNDA infracción en un cruce a nivel de ferrocarril dentro de un período de 3 years. La descalificación mínima es:","options":["120 days","60 days","90 days","1 year"],"explanation":"Una segunda infracción en un cruce a nivel de ferrocarril dentro de 3 years resulta en una descalificación mínima de 120 days. Fuente: 49 CFR 383.51 según se adopta en el Louisiana CDL Manual."},"48":{"q":"Un titular de CDL de Luisiana comete una TERCERA infracción en un cruce a nivel de ferrocarril dentro de un período de 3 years. La descalificación mínima es:","options":["1 year","120 days","180 days","3 years"],"explanation":"Una tercera infracción en un cruce a nivel de ferrocarril dentro de 3 years resulta en una descalificación mínima de 1 year. Fuente: 49 CFR 383.51 según se adopta en el Louisiana CDL Manual."},"49":{"q":"¿Cuál es el período de descalificación para la PRIMERA condena de un titular de CDL de Luisiana por violar una orden de fuera de servicio (out-of-service) mientras opera un CMV (sin hazmat, sin pasajeros)?","options":["Al menos 180 days, hasta 1 year","Al menos 30 days","Al menos 60 days","De por vida"],"explanation":"Una primera violación de una orden de fuera de servicio (OOS) resulta en una descalificación de al menos 180 days y hasta 1 year para un CMV estándar. Fuente: La. R.S. 32:414.2 y 49 CFR 383.51 según se adoptan en el Louisiana CDL Manual."},"50":{"q":"Un titular de CDL de Luisiana es condenado por una SEGUNDA violación de una orden de fuera de servicio dentro de un período de 10 years. El rango de descalificación es:","options":["2 to 5 years","1 to 2 years","60 to 120 days","De por vida"],"explanation":"Una segunda violación de una orden de fuera de servicio dentro de 10 years resulta en una descalificación de 2 to 5 years para un CMV estándar. Fuente: La. R.S. 32:414.2 y 49 CFR 383.51 según se adoptan en el Louisiana CDL Manual."},"51":{"q":"Para un titular de CDL que transporta materiales peligrosos que requieren placas (placards), una PRIMERA violación de una orden de fuera de servicio conlleva una descalificación de:","options":["Al menos 180 days, hasta 2 years","Al menos 30 days, hasta 60 days","Exactamente 1 year","De por vida"],"explanation":"Cuando la violación de la orden OOS ocurre mientras se transportan materiales peligrosos con placas (placards) o mientras se opera un vehículo diseñado para transportar 16 o más pasajeros, la descalificación por la primera infracción es de al menos 180 days y hasta 2 years. Fuente: 49 CFR 383.51 según se adopta en el Louisiana CDL Manual."},"52":{"q":"¿Cuál de las siguientes describe mejor cómo cuenta Luisiana las infracciones de tránsito graves para la descalificación de la CDL?","options":["Condenas en incidentes separados dentro de un período de 3 years","Solo condenas que ocurren el mismo día","Todas las condenas dentro de un período de 1 year únicamente","Solo infracciones cometidas fuera de servicio"],"explanation":"Las descalificaciones por infracciones de tránsito graves (60 days por una segunda, 120 days por una tercera) se basan en condenas derivadas de incidentes separados dentro de un período de 3 years. Fuente: 49 CFR 383.51 según se adopta en el Louisiana CDL Manual y La. R.S. 32:414.2."},"53":{"q":"Un conductor causa una muerte mientras opera un CMV y es condenado por una infracción de tránsito (como operación negligente o imprudente) relacionada con el fallecimiento. Para fines de la CDL en Luisiana, esto se considera:","options":["Una infracción de tránsito grave que cuenta para la descalificación","Solo un asunto administrativo ajeno a la CDL","Una descalificación automática de por vida","Una infracción en un cruce de ferrocarril"],"explanation":"Una violación de las leyes de control del tránsito cometida en relación con un accidente fatal se incluye en la lista de infracciones de tránsito graves, contando para los umbrales de 60 days y 120 days. (El homicidio involuntario o un delito grave con un CMV es una infracción mayor separada de 1 year.) Fuente: 49 CFR 383.51 según se adopta en el Louisiana CDL Manual."},"54":{"q":"Un titular de CDL de Luisiana usa un CMV para cometer un delito grave que involucra la fabricación o distribución de una sustancia controlada. La descalificación es:","options":["De por vida, sin posibilidad de reinstalación","1 year","3 years","60 days"],"explanation":"Usar un CMV en la comisión de un delito grave que involucra la fabricación, distribución o suministro de una sustancia controlada resulta en una descalificación de por vida sin posibilidad de reinstalación, a diferencia de otras infracciones mayores. Fuente: La. R.S. 32:414.2 y 49 CFR 383.51 según se adoptan en el Louisiana CDL Manual."},"55":{"q":"En una autopista interestatal o de acceso controlado de Luisiana, ¿cuál es el límite de velocidad máximo establecido por la ley (a menos que se indique un límite diferente)?","options":["60 mph","65 mph","70 mph","75 mph"],"explanation":"La ley RS 32:61 de Luisiana fija el máximo legal en 70 mph en autopistas interestatales o de acceso controlado, a menos que se indique lo contrario. Fuente: Louisiana RS 32:61; folleto 'Speed Limit' del Louisiana DOTD."},"56":{"q":"Según la ley de Luisiana, ¿cuál es el límite de velocidad legal en una autopista DIVIDIDA de varios carriles que no es interestatal, a menos que se indique lo contrario?","options":["55 mph","65 mph","70 mph","60 mph"],"explanation":"La RS 32:61 establece que el límite en cualquier autopista de Luisiana no debe exceder las 55 mph, salvo que se trate de una autopista dividida de varios carriles (65 mph) o de una autopista interestatal/de acceso controlado (70 mph). Fuente: Louisiana RS 32:61; folleto 'Speed Limit' del Louisiana DOTD."},"57":{"q":"En una autopista interestatal de Luisiana, ¿cómo se compara el límite de velocidad máximo para un tractocamión con remolque con el límite para un automóvil de pasajeros?","options":["Los camiones deben mantenerse 10 mph por debajo del límite indicado","Los camiones tienen un tope de 5 mph menos que los automóviles","Los camiones tienen el mismo límite máximo que los automóviles","Los camiones están limitados a 55 mph en todo el estado"],"explanation":"Luisiana no tiene un límite de velocidad interestatal inferior por separado para los camiones; la antigua ley de velocidad para camiones RS 32:62 fue derogada (Acts 2010, No. 81) y una propuesta posterior de '10 mph por debajo' no se promulgó. Los límites de la RS 32:61 se aplican a todos los vehículos, a menos que se indique lo contrario. Fuente: Louisiana RS 32:61; RS 32:62 (derogada en 2010)."},"58":{"q":"Un conductor de autobús de Luisiana se acerca a un cruce ferroviario que requiere detenerse. ¿Dónde debe detenerse el autobús con respecto al riel más cercano?","options":["Entre 5 y 25 pies","Entre 15 y 50 pies","Entre 50 y 100 pies","Entre 10 y 40 pies"],"explanation":"El Manual de CDL de Luisiana indica que un autobús debe detenerse entre 15 y 50 pies antes de un cruce ferroviario, y luego mirar y escuchar en ambas direcciones antes de cruzar. Fuente: Louisiana CDL Manual, Sec. 4.3.5 (Railroad-highway Crossing Stops)."},"59":{"q":"Un conductor que transporta materiales peligrosos con carteles (placarded) en Luisiana llega a un cruce ferroviario no exento. ¿A qué distancia del riel más cercano debe detenerse el vehículo?","options":["No más cerca de 15 pies y no más de 50 pies","No más cerca de 10 pies y no más de 25 pies","No más cerca de 25 pies y no más de 75 pies","Exactamente 50 pies, y luego avanzar lentamente"],"explanation":"Los autobuses, los autobuses escolares y los vehículos con carteles deben detener el vehículo a no más de 50 pies, pero no menos de 15 pies del riel más cercano, y luego mirar y escuchar antes de cruzar. Fuente: Louisiana CDL Manual, Sec. 13.1.8 (Railroad Crossing procedures)."},"60":{"q":"Según la RS 32:80 de Luisiana, un conductor que se cruza o adelanta a un autobús escolar detenido con sus señales visuales en funcionamiento debe detenerse a no menos de qué distancia del autobús?","options":["10 pies","20 pies","30 pies","50 pies"],"explanation":"La RS 32:80 exige que los conductores que se aproximen desde cualquier dirección se detengan a no menos de 30 pies de un autobús escolar que esté detenido para recoger o dejar niños mientras sus señales visuales están activadas, y que permanezcan detenidos hasta que el autobús avance o las señales se apaguen. Fuente: Louisiana RS 32:80."},"61":{"q":"En una autopista DIVIDIDA de cuatro carriles con calzadas separadas en Luisiana, un autobús escolar se detiene en la calzada OPUESTA para dejar niños. ¿Qué debe hacer un conductor que viaja en la otra dirección?","options":["Detenerse y esperar hasta que las señales se apaguen","Detenerse solo si hay niños cruzando","No es necesario detenerse; se aplica la excepción de autopista dividida","Reducir la velocidad a 15 mph, pero no es necesario detenerse"],"explanation":"La RS 32:80 establece que un conductor no necesita detenerse por un autobús escolar que se encuentra en una calzada diferente de una autopista dividida con calzadas separadas (o en una autopista de acceso controlado donde el autobús está en una zona de carga). Fuente: Louisiana RS 32:80."},"62":{"q":"En Luisiana, una carretera de dos carriles con un carril en cada sentido más un carril central de giro a la izquierda en ambos sentidos tiene un autobús escolar detenido recogiendo niños. Para la ley de detención de autobuses escolares, esta carretera se considera:","options":["Una autopista dividida, por lo que el tránsito que viene en sentido contrario no necesita detenerse","NO una autopista dividida, por lo que el tránsito que viene en sentido contrario debe detenerse","Una autopista de acceso controlado exenta de detenerse","Una calle de un solo sentido sin obligación de detenerse"],"explanation":"La RS 32:80 establece expresamente que una carretera con un carril en cada dirección y un carril dedicado de giro a la izquierda en ambos sentidos NO se considerará una autopista dividida con calzadas separadas, por lo que los conductores que vienen en sentido contrario igual deben detenerse. Fuente: Louisiana RS 32:80."},"63":{"q":"La ley 'Move Over' (Cámbiese de carril) de Luisiana (RS 32:125) se aplica cuando usted se acerca a un vehículo de emergencia DETENIDO que muestra señales visuales en una autopista con dos o más carriles en su dirección. ¿Cuál es la PRIMERA acción requerida?","options":["Detenerse por completo en su carril","Cambiarse a un carril no adyacente al vehículo estacionado, si es posible","Tocar la bocina y mantener la velocidad","Orillarse al acotamiento derecho y detenerse"],"explanation":"La RS 32:125 exige que los conductores en una vía con dos o más carriles en la misma dirección cedan el paso cambiándose a un carril no adyacente al vehículo de emergencia estacionado, cuando sea posible y prestando la debida atención a la seguridad y al tránsito. Fuente: Louisiana RS 32:125."},"64":{"q":"Según la ley 'Move Over' de Luisiana, si usted NO puede cambiarse de carril de manera segura para alejarse de un vehículo de emergencia detenido (o si se encuentra en una carretera de dos carriles), ¿qué debe hacer?","options":["Detenerse por completo hasta que se despeje la escena","Mantener su velocidad normal y girar a la izquierda","Reducir la velocidad a una razonablemente segura para las condiciones","Acelerar para pasar y despejar la zona rápidamente"],"explanation":"La RS 32:125 establece que si no es posible cambiar de carril o si usted se encuentra en una carretera de dos carriles, debe reducir la velocidad a una razonablemente segura para las condiciones de la vía mientras pasa junto al vehículo de emergencia estacionado. Fuente: Louisiana RS 32:125."},"65":{"q":"Además de la policía, los bomberos y los servicios médicos de emergencia (EMS), ¿qué otros vehículos detenidos que muestran luces de advertencia protege la ley 'Move Over' de Luisiana (RS 32:125)?","options":["Solo unidades policiales identificadas","Camiones grúa/de remolque y vehículos que usan luces ámbar/amarillas intermitentes","Solo ambulancias y camiones de bomberos","Solo vehículos de reparto de correo"],"explanation":"La RS 32:125 cubre cualquier vehículo que muestre legalmente señales visuales autorizadas, incluidas luces de advertencia intermitentes ámbar, amarillas o verdes, lo que extiende la protección a camiones grúa/de remolque y vehículos de servicio similares. Fuente: Louisiana RS 32:125 (modificada por Acts 2021, No. 78)."},"66":{"q":"Ante la aproximación inmediata de un vehículo de emergencia autorizado que hace sonar una sirena y muestra luces, la RS 32:125 de Luisiana exige que el conductor de todo otro vehículo:","options":["Acelere para despejar la intersección que tiene adelante","Se cambie al carril central y reduzca la velocidad","Conduzca hacia el borde derecho o el bordillo, libre de cualquier intersección, y se detenga","Se detenga de inmediato donde sea que esté el vehículo, incluso dentro de una intersección"],"explanation":"La RS 32:125 exige ceder el derecho de paso conduciendo hacia una posición paralela y lo más cerca posible del borde derecho o del bordillo, libre de cualquier intersección, y deteniéndose hasta que el vehículo de emergencia haya pasado. Fuente: Louisiana RS 32:125."},"67":{"q":"En una autopista de varios carriles de Luisiana, un vehículo comercial lento que está obstruyendo a un vehículo más rápido que desea adelantar por el carril izquierdo debe, según la RS 32:71:","options":["Mantener su posición hasta la próxima salida","Incorporarse de inmediato al carril derecho","Reducir aún más la velocidad para dejar que el vehículo lo adelante por la derecha","Pasarse al acotamiento izquierdo"],"explanation":"La RS 32:71 prohíbe usar el carril izquierdo para obstruir o bloquear a un vehículo que adelanta; el vehículo más lento debe incorporarse de inmediato al carril derecho. La multa por la primera infracción es de $150. Fuente: Louisiana RS 32:71."},"68":{"q":"Cuando un vehículo comercial (CMV) de Luisiana está detenido en el acotamiento de una autopista de un solo sentido o dividida, ¿dónde se deben colocar los tres dispositivos de advertencia de emergencia (triángulos)?","options":["A 10 pies, 100 pies y 200 pies hacia el tránsito que se aproxima","A 10 pies, 50 pies y 150 pies hacia el tránsito que se aproxima","A 25 pies, 100 pies y 250 pies hacia el tránsito que se aproxima","A 15 pies, 75 pies y 200 pies hacia el tránsito que se aproxima"],"explanation":"El Manual de CDL de Luisiana (que adopta la norma federal) exige colocar los dispositivos de advertencia a 10 pies, 100 pies y 200 pies hacia el tránsito que se aproxima cuando se está detenido en o junto a una autopista de un solo sentido o dividida. Fuente: Louisiana CDL Manual, Sec. 2.5 (Warning Devices)."},"69":{"q":"Después de detener un CMV en una vía o acotamiento en Luisiana, ¿dentro de cuántos minutos debe el conductor colocar los dispositivos de advertencia de emergencia?","options":["5 minutos","10 minutos","15 minutos","30 minutos"],"explanation":"El Manual de CDL de Luisiana indica que si debe detenerse en una vía o acotamiento, debe colocar sus dispositivos de advertencia de emergencia dentro de los 10 minutos. Fuente: Louisiana CDL Manual, Sec. 2.5 (Warning Devices)."},"70":{"q":"En una carretera de dos carriles de Luisiana con tránsito en ambas direcciones, ¿dónde debe colocar un CMV detenido sus triángulos de advertencia por delante y por detrás del vehículo?","options":["200 pies por delante y 200 pies por detrás","100 pies por delante y 100 pies por detrás","50 pies por delante y 100 pies por detrás","10 pies por delante y 10 pies por detrás"],"explanation":"En una carretera de doble sentido/no dividida, el Manual de CDL de Luisiana exige un dispositivo a no más de 10 pies del vehículo y dispositivos a 100 pies por delante y 100 pies por detrás del mismo. Fuente: Louisiana CDL Manual, Sec. 2.5 (Warning Devices)."},"71":{"q":"Un autobús escolar de Luisiana se acerca a un cruce ferroviario. El Manual de CDL recomienda activar las luces de advertencia de emergencia del autobús aproximadamente a qué distancia antes del cruce?","options":["50 pies","100 pies","200 pies","500 pies"],"explanation":"Los procedimientos para autobuses escolares del Manual de CDL de Luisiana recomiendan activar las luces de emergencia aproximadamente a 200 pies antes del cruce, y luego detenerse a entre 15 y 50 pies del riel más cercano. Fuente: Louisiana CDL Manual, Sec. 10.4.3 (Recommended Procedures)."},"72":{"q":"Un autobús de Luisiana llega a un puente levadizo que NO tiene luz de señalización NI encargado del control de tránsito. ¿A qué distancia mínima antes de la sección móvil del puente debe detenerse el conductor?","options":["15 pies","30 pies","50 pies","100 pies"],"explanation":"El Manual de CDL de Luisiana exige detenerse al menos 50 pies antes de la sección móvil de un puente levadizo que no tiene luz de señalización ni encargado del control de tránsito, y confirmar que la sección móvil esté completamente cerrada antes de cruzar. Fuente: Louisiana CDL Manual, Sec. 4.3.6 (Drawbridges)."},"73":{"q":"Si un conductor de Luisiana comete una infracción en un cruce a nivel ferroviario mientras opera un CMV que lleva CARTELES (placarded) de materiales peligrosos, la descalificación mínima del CDL es de:","options":["60 días","120 días","1 año","3 años"],"explanation":"El Manual de CDL de Luisiana indica que perderá su CDL durante al menos tres años si una infracción en un cruce ferroviario ocurre mientras opera un CMV con carteles de materiales peligrosos (frente a 60/120 días por infracciones graves en cruces sin carteles). Fuente: Louisiana CDL Manual, Sec. 1.2.5 (Railroad-highway Grade Crossing Violations)."},"74":{"q":"Sin un permiso de sobredimensión del Louisiana DOTD, ¿cuál es el ANCHO legal máximo para un vehículo comercial y su carga en las autopistas de Luisiana?","options":["8 feet 0 inches","8 feet 6 inches","9 feet 0 inches","10 feet 0 inches"],"explanation":"Los límites legales de tamaño de Luisiana son 8 feet 6 inches de ancho, 13 feet 6 inches de alto y 80,000 pounds; las cargas que excedan estos valores requieren un permiso de sobredimensión/sobrepeso del DOTD, con el movimiento permitido generalmente restringido desde el amanecer hasta el atardecer. Fuente: Louisiana DOTD Weights & Standards; LAC Title 73, Part I, Chapter 3."},"75":{"q":"¿Qué organismo emite las Licencias de Conducir Comerciales (CDL) en Luisiana?","options":["La Oficina de Vehículos Motorizados de Luisiana (Louisiana OMV)","La Policía Estatal de Luisiana","La Administración Federal de Seguridad de Autotransportes (FMCSA)","El Departamento de Transporte y Desarrollo de Luisiana (DOTD)"],"explanation":"Las CDL en Luisiana son emitidas por la Oficina de Vehículos Motorizados (OMV), que forma parte del Departamento de Seguridad Pública de Luisiana. La FMCSA establece las normas federales, pero no emite licencias; el DOTD se encarga de las carreteras y de los permisos de sobredimensión/sobrepeso, no de las CDL. Fuente: páginas de CDL de la Louisiana OMV (expresslane.la.gov)."},"76":{"q":"Antes de obtener la licencia, todo solicitante de CDL en Luisiana debe obtener primero ¿qué credencial?","options":["Un Permiso de Aprendiz Comercial (CLP)","Un número federal de autoridad para operar interestatal","Un permiso de sobredimensión/sobrepeso del DOTD","Un endoso temporal de chofer"],"explanation":"En Luisiana debe tener un Permiso de Aprendiz Comercial (CLP) antes de poder presentar el examen de destrezas del CDL y obtener la licencia. El CLP le permite practicar en vías públicas acompañado por un titular de CDL. Fuente: página 'New CDL' de la Louisiana OMV."},"77":{"q":"¿Cuánto tiempo debe esperar el titular de un CLP de Luisiana después de la emisión inicial del permiso antes de poder presentar el examen de destrezas del CDL?","options":["14 días","30 días","10 días","60 días"],"explanation":"Luisiana aplica el período de espera federal de 14 días: el titular de un CLP no puede presentar el examen de destrezas del CDL durante los primeros 14 días posteriores a la emisión inicial del CLP. Fuente: página 'New CDL' de la Louisiana OMV (49 CFR 383.25)."},"78":{"q":"¿Cuál es el período máximo durante el cual un CLP de Luisiana puede permanecer vigente, contando su plazo inicial más la prórroga permitida?","options":["360 días (180 días más una prórroga de 180 días)","180 días sin prórroga permitida","1 año (365 días)","90 días más una prórroga de 90 días"],"explanation":"Un CLP de Luisiana se emite por hasta 180 días y puede prorrogarse una vez por 180 días adicionales, para un máximo de 360 días. Fuente: página 'New CDL' de la Louisiana OMV (49 CFR 383.25)."},"79":{"q":"¿Entre cuántas categorías distintas de autocertificación debe elegir un solicitante de CDL/CLP de Luisiana respecto al tipo de comercio en el que va a operar?","options":["Cuatro","Dos","Tres","Cinco"],"explanation":"Existen cuatro categorías de autocertificación: Interestatal No Exenta (NI), Interestatal Exenta (EI), Intraestatal No Exenta (NA) e Intraestatal Exenta (EA). Fuente: materiales de autocertificación de CDL de la Louisiana OMV (49 CFR 383.71)."},"80":{"q":"¿Cuáles son las dos categorías de autocertificación que exigen que el titular de un CDL de Luisiana tenga y mantenga en archivo un Certificado de Examinador Médico?","options":["Interestatal No Exenta e Intraestatal No Exenta","Interestatal Exenta e Intraestatal Exenta","Interestatal No Exenta e Interestatal Exenta","Intraestatal Exenta e Intraestatal No Exenta"],"explanation":"Los conductores que se autocertifican como Interestatal No Exenta (NI) o Intraestatal No Exenta (NA) deben cumplir con las normas de calificación médica y mantener en archivo un Certificado de Examinador Médico vigente. Las categorías 'exentas' (EI, EA) no están obligadas a hacerlo. Fuente: materiales de autocertificación de la Louisiana OMV (49 CFR 383.71)."},"81":{"q":"Un conductor que transporta carga únicamente dentro de Luisiana con fines comerciales y que debe cumplir con las normas médicas debe autocertificarse bajo ¿qué categoría?","options":["Intraestatal No Exenta (NA)","Interestatal No Exenta (NI)","Interestatal Exenta (EI)","Intraestatal Exenta (EA)"],"explanation":"Operar comercialmente solo dentro de Luisiana ('intraestatal') y estar sujeto a las normas de calificación médica corresponde a la categoría Intraestatal No Exenta (NA). Las categorías interestatales aplican al cruce de líneas estatales. Fuente: definiciones de autocertificación de la Louisiana OMV (49 CFR 383.71)."},"82":{"q":"¿Qué formulario médico debe presentar como prueba de calificación médica un solicitante de CDL de Luisiana que se autocertifica como no exento?","options":["El Certificado de Examinador Médico (formulario MCSA-5876)","Una exención médica de sobredimensión/sobrepeso del DOTD","El Formulario Suplementario de CDL (DPSMV2211)","Una declaración jurada de aptitud de la Policía Estatal de Luisiana"],"explanation":"Los solicitantes de CDL no exentos deben presentar un Certificado de Examinador Médico vigente (formulario MCSA-5876) completado por un examinador certificado. El DPSMV2211 es el formulario suplementario de la solicitud de CDL, no el certificado médico. Fuente: páginas 'New CDL' / 'Submit CDL Medical Certificate' de la Louisiana OMV."},"83":{"q":"¿Quién está autorizado para realizar el examen físico que respalda un Certificado de Examinador Médico de CDL de Luisiana?","options":["Un examinador médico inscrito en el Registro Nacional de Examinadores Médicos Certificados de la FMCSA","Cualquier médico con licencia elegido por el conductor","Un médico empleado por la Louisiana OMV","Cualquier enfermero especializado con licencia, sin importar su estado de registro"],"explanation":"El examen físico debe ser realizado por un examinador médico certificado e inscrito en el Registro Nacional de Examinadores Médicos Certificados de la FMCSA. Fuente: páginas 'New CDL' / de información del certificado médico de CDL de la Louisiana OMV."},"84":{"q":"¿Mediante cuál de los siguientes métodos acepta la Louisiana OMV un Certificado de Examinador Médico de CDL?","options":["Por correo electrónico, fax o correo postal estándar a la OMV","Solo presentándose en persona en una oficina regional de la OMV","Solo a través de que el examinador lo cargue a la FMCSA","Solo por correo certificado con una carátula notariada"],"explanation":"La Louisiana OMV acepta el Certificado de Examinador Médico por correo electrónico (OMV_CDL_Medical@dps.la.gov), fax o correo postal estándar. Fuente: página 'Submit CDL Medical Certificate' de la Louisiana OMV."},"85":{"q":"¿Con cuánta anticipación al vencimiento del certificado médico del titular de un CDL envía la Louisiana OMV un aviso solicitando un nuevo examen médico?","options":["60 días antes del vencimiento","30 días antes del vencimiento","90 días antes del vencimiento","10 días antes del vencimiento"],"explanation":"La Louisiana OMV genera un aviso al cliente 60 días antes del vencimiento del certificado médico en archivo, solicitando un nuevo formulario de examen y certificado. Fuente: página de información del certificado médico de CDL de la Louisiana OMV."},"86":{"q":"Si el titular de un CDL de Luisiana no presenta un nuevo certificado médico, ¿cuándo se marca al conductor como 'médicamente no certificado'?","options":["10 días después de que vence el certificado médico en archivo","De inmediato, en la fecha de vencimiento","60 días después de que vence el certificado","30 días después de que vence el certificado"],"explanation":"El incumplimiento de los requisitos de autocertificación/médicos hace que el conductor sea marcado como 'médicamente no certificado' 10 días después de que vence el certificado médico en archivo; el CDL se cancela posteriormente si el incumplimiento continúa. Fuente: página de información del certificado médico de CDL de la Louisiana OMV."},"87":{"q":"El examen de destrezas del CDL de Luisiana se compone de ¿cuáles tres partes, realizadas en orden?","options":["Inspección previa al viaje, control básico del vehículo y conducción en carretera","Conocimiento escrito, examen de la vista y conducción en carretera","Inspección previa al viaje, manejo de materiales peligrosos y purga de los frenos de aire","Control básico del vehículo, auditoría de la bitácora y conducción en carretera"],"explanation":"El examen de destrezas del CDL en Luisiana tiene tres partes: la inspección previa al viaje, el examen de control básico del vehículo y el examen de conducción en carretera. Fuente: Manual de CDL de Luisiana / páginas de CDL de la Louisiana OMV (49 CFR 383.113)."},"88":{"q":"¿Qué capacitación debe completar un solicitante de Luisiana antes de presentar el examen de destrezas del CDL para una primera licencia de Clase A o Clase B?","options":["Capacitación para Conductores Principiantes (ELDT) de un proveedor registrado ante la FMCSA","Un curso de manejo defensivo de la Louisiana OMV","Un curso de manejo de cargas de sobredimensión del DOTD","Un seminario estatal de inspección en estaciones de pesaje"],"explanation":"La Capacitación para Conductores Principiantes (ELDT), impartida por una escuela inscrita en el Registro de Proveedores de Capacitación de la FMCSA, debe completarse antes de presentar el examen de destrezas para un CDL inicial (y antes del examen de conocimientos de materiales peligrosos). Fuente: página 'New CDL' de la Louisiana OMV (49 CFR Part 380 Subpart F)."},"89":{"q":"Antes de las pruebas, ¿cuál es el primer examen que un solicitante de CDL de Luisiana debe aprobar para calificar para un Permiso de Aprendiz Comercial?","options":["El examen escrito de conocimientos generales","El examen de destrezas de conducción en carretera","El examen de control básico del vehículo","El examen de inspección previa al viaje"],"explanation":"Los solicitantes deben aprobar los exámenes escritos de conocimientos requeridos, comenzando con el examen de conocimientos generales, para que se les emita un CLP; los exámenes de destrezas vienen después, una vez que se tiene el CLP. Fuente: Manual de CDL de Luisiana / páginas de CDL de la OMV."},"90":{"q":"En el examen escrito de conocimientos generales del CDL de Luisiana, de 50 preguntas, ¿qué puntaje mínimo se requiere para aprobar?","options":["80% (40 de 50 correctas)","70% (35 de 50 correctas)","75% (38 de 50 correctas)","90% (45 de 50 correctas)"],"explanation":"El examen de conocimientos generales tiene 50 preguntas de opción múltiple, y se requiere un puntaje del 80% (40 de 50) para aprobar, en concordancia con la norma federal de CDL. Fuente: Manual de CDL de Luisiana / materiales de pruebas de la OMV (49 CFR 383.135)."},"91":{"q":"¿Cuál es la edad mínima para obtener un CDL de Luisiana limitado a la operación intraestatal (dentro del estado)?","options":["18 años","21 años","19 años","16 años"],"explanation":"Un solicitante debe tener al menos 18 años para tener un CDL de Luisiana restringido a la operación intraestatal; se requieren 21 años para la conducción interestatal y para el transporte de materiales peligrosos. Fuente: páginas de CDL de la Louisiana OMV (49 CFR 383.3 / 391.11)."},"92":{"q":"¿Qué documentación, además de la identidad y el certificado médico, debe presentar un solicitante de CDL de Luisiana al momento de la solicitud?","options":["Prueba de residencia en Luisiana (como recibos de servicios públicos o un contrato de arrendamiento)","Una carta de patrocinio notariada del empleador","Un estudio de ruta del DOTD para la carga prevista","Una copia de la autoridad operativa USDOT del transportista"],"explanation":"Luisiana exige una prueba de residencia en Luisiana (por ejemplo, recibos de servicios públicos, contrato de arrendamiento, registro electoral) junto con el Formulario Suplementario de CDL (DPSMV2211) y el Certificado de Examinador Médico. Fuente: página 'New CDL' de la Louisiana OMV."},"93":{"q":"¿Por cuántos años es normalmente válido un CDL de Luisiana antes de que deba renovarse?","options":["6 años","4 años","8 años","5 años"],"explanation":"Un CDL de Luisiana generalmente es válido por 6 años. La autocertificación del tipo de operación y un certificado médico vigente (para conductores no exentos) deben mantenerse durante todo ese período. Fuente: información de renovación de CDL de la Louisiana OMV."},"94":{"q":"Respecto a la tarifa del examen de destrezas del CDL de Luisiana realizado por un examinador externo (third-party), ¿cuál afirmación es la descripción más precisa del proceso?","options":["El examen de destrezas se puede realizar a través de examinadores externos aprobados, y la tarifa exacta la establece el examinador y puede cambiar, por lo que los solicitantes deben confirmar el monto vigente","El examen de destrezas siempre es gratuito cuando se realiza en cualquier oficina de la OMV","La tarifa del examen de destrezas está fijada por la ley federal y es idéntica en todos los estados","Nunca se puede cobrar una tarifa del examen de destrezas si el solicitante lleva su propio vehículo"],"explanation":"Luisiana permite que el examen de destrezas sea administrado por examinadores externos aprobados, y la tarifa la establece el examinador y está sujeta a cambios, por lo que los solicitantes deben verificar el monto vigente en lugar de basarse en una cifra fija. Fuente: páginas de CDL de la Louisiana OMV (programa de pruebas con terceros)."}},"hi":{"0":{"q":"लुइसियाना के राजमार्गों पर, सुरक्षा उपकरणों को छोड़कर, किसी वाणिज्यिक वाहन की अधिकतम कानूनी चौड़ाई कितनी है?","options":["96 inches","98 inches","102 inches","108 inches"],"explanation":"Louisiana RS 32:380 वाहन की अधिकतम चौड़ाई 102 inches (8 feet 6 inches) निर्धारित करता है, जिसमें दर्पण जैसे सुरक्षा उपकरण शामिल नहीं हैं। स्रोत: Louisiana Revised Statutes 32:380।"},"1":{"q":"लुइसियाना में Interstate प्रणाली के अलावा अन्य राजमार्गों पर वाहन की अधिकतम कानूनी ऊँचाई कितनी है?","options":["13 feet","13 feet 6 inches","14 feet","14 feet 6 inches"],"explanation":"Louisiana RS 32:381 के तहत, गैर-Interstate राजमार्गों पर किसी वाहन और उसके भार की ऊँचाई 13 feet 6 inches से अधिक नहीं हो सकती। स्रोत: Louisiana Revised Statutes 32:381।"},"2":{"q":"लुइसियाना में केवल Interstate राजमार्ग प्रणाली पर चलने वाले वाहन के लिए अधिकतम कानूनी ऊँचाई कितनी है?","options":["13 feet 6 inches","14 feet","14 feet 6 inches","15 feet"],"explanation":"Louisiana RS 32:381 केवल Interstate राजमार्ग प्रणाली पर चलने वाले वाहन और उसके भार के लिए अधिकतम 14 feet की ऊँचाई की अनुमति देता है, जबकि अन्य स्थानों पर यह 13 feet 6 inches है। स्रोत: Louisiana Revised Statutes 32:381।"},"3":{"q":"लुइसियाना में किसी एकल वाहन (जैसे स्ट्रेट ट्रक या बस) की अधिकतम कानूनी लंबाई कितनी है?","options":["40 feet","45 feet","53 feet","59 feet 6 inches"],"explanation":"Louisiana RS 32:382 किसी एकल वाहन की अधिकतम लंबाई 45 feet तक सीमित करता है। स्रोत: Louisiana Revised Statutes 32:382।"},"4":{"q":"लुइसियाना में ट्रैक्टर-सेमीट्रेलर संयोजन के सेमीट्रेलर हिस्से की अधिकतम कानूनी लंबाई कितनी है?","options":["48 feet","53 feet","57 feet","59 feet 6 inches"],"explanation":"Louisiana RS 32:382 ट्रैक्टर-सेमीट्रेलर संयोजन के सेमीट्रेलर हिस्से को 59 feet 6 inches तक की अनुमति देता है; इस विन्यास के लिए कोई अलग समग्र संयोजन लंबाई सीमा नहीं है। स्रोत: Louisiana Revised Statutes 32:382।"},"5":{"q":"लुइसियाना के किसी वाहन पर भार उसके बॉडी की चौड़ाई से कितनी दूर तक बाहर निकल सकता है?","options":["6 inches से अधिक नहीं","12 inches से अधिक नहीं","18 inches से अधिक नहीं","24 inches से अधिक नहीं"],"explanation":"Louisiana RS 32:380 प्रावधान करता है कि भार वाहन की बॉडी की चौड़ाई से 12 inches से अधिक बाहर नहीं निकलना चाहिए। स्रोत: Louisiana Revised Statutes 32:380।"},"6":{"q":"लुइसियाना के राजमार्गों पर बिना परमिट के किसी वाहन या वाहनों के संयोजन के लिए अनुमत अधिकतम सकल भार कितना है?","options":["73,280 pounds","80,000 pounds","88,000 pounds","90,000 pounds"],"explanation":"Louisiana RS 32:386 किसी वाहन या वाहनों के संयोजन के कुल सकल भार को 80,000 pounds तक सीमित करता है। स्रोत: Louisiana Revised Statutes 32:386।"},"7":{"q":"लुइसियाना में, लो-प्रेशर न्यूमेटिक टायरों से सुसज्जित एकल एक्सल पर अनुमत अधिकतम सकल भार कितना है?","options":["18,000 pounds","20,000 pounds","22,400 pounds","34,000 pounds"],"explanation":"Louisiana RS 32:386 लो-प्रेशर न्यूमेटिक टायरों से सुसज्जित एकल एक्सल को 20,000 pounds तक सीमित करता है। स्रोत: Louisiana Revised Statutes 32:386।"},"8":{"q":"सामान्य वैधानिक सीमा के तहत लुइसियाना में टैंडम एक्सल पर अनुमत अधिकतम सकल भार कितना है?","options":["32,000 pounds","34,000 pounds","37,000 pounds","40,000 pounds"],"explanation":"Louisiana RS 32:386 लो-प्रेशर न्यूमेटिक टायरों से सुसज्जित टैंडम एक्सल को 34,000 pounds तक सीमित करता है। स्रोत: Louisiana Revised Statutes 32:386।"},"9":{"q":"लुइसियाना अपनी प्राकृतिक अवस्था में वन उत्पाद ले जाने वाले वाहनों के लिए उच्चतर टैंडम-एक्सल भार भत्ता प्रदान करता है। वह सीमा क्या है, और यह कहाँ लागू नहीं होती?","options":["37,000 pounds, Interstate प्रणाली को छोड़कर","37,000 pounds, Interstate प्रणाली सहित","40,000 pounds, Interstate प्रणाली को छोड़कर","34,000 pounds, हर जगह लागू"],"explanation":"Louisiana RS 32:386 अपनी प्राकृतिक अवस्था में वन उत्पाद ढोने वाले वाहनों के लिए प्रति टैंडम एक्सल 37,000 pounds की अनुमति देता है, Interstate प्रणाली को छोड़कर, जहाँ मानक 34,000-pound सीमा लागू होती है। स्रोत: Louisiana Revised Statutes 32:386।"},"10":{"q":"Louisiana RS 32:386 के तहत, किसी भी एक्सल पर कोई टायर राजमार्ग की सतह पर प्रति इंच टायर चौड़ाई के हिसाब से कितने से अधिक भार नहीं डाल सकता?","options":["500 pounds per inch","600 pounds per inch","650 pounds per inch","700 pounds per inch"],"explanation":"Louisiana RS 32:386 बताता है कि कोई टायर राजमार्ग की सतह पर प्रति इंच टायर चौड़ाई 650 pounds per inch से अधिक भार नहीं डालेगा। स्रोत: Louisiana Revised Statutes 32:386।"},"11":{"q":"Interstate प्रणाली पर दो या अधिक लगातार एक्सलों के किसी समूह पर अधिकतम अनुमेय सकल भार निर्धारित करने के लिए लुइसियाना कौन-सा सूत्र लागू करता है?","options":["Federal Bridge Formula W = 500(LN/(N-1) + 12N + 36)","एक्सल अंतराल की परवाह किए बिना एक समान 80,000-pound सीमा","एकल-एक्सल 20,000-pound नियम को एक्सल संख्या से गुणा करना","650 pounds को इंच में व्हीलबेस से गुणा करने के बराबर भार"],"explanation":"Louisiana RS 32:386 Interstate पर लगातार एक्सलों पर भार की सीमा निर्धारित करने के लिए Federal Bridge Formula, W = 500(LN/(N-1) + 12N + 36) को शामिल करता है, जहाँ L एक्सल अंतराल feet में है और N एक्सलों की संख्या है। स्रोत: Louisiana Revised Statutes 32:386 (Federal Bridge Formula)।"},"12":{"q":"लुइसियाना में प्रयुक्त Federal Bridge Formula, W = 500(LN/(N-1) + 12N + 36) में, चर L और N किसका प्रतिनिधित्व करते हैं?","options":["L टनों में भार है; N टायरों की संख्या है","L किसी समूह के बाहरी एक्सलों के बीच feet में दूरी है; N उस समूह में एक्सलों की संख्या है","L कानूनी गति है; N एक्सल भार है","L लेन की चौड़ाई है; N ट्रेलरों की संख्या है"],"explanation":"Louisiana RS 32:386 द्वारा लागू Federal Bridge Formula में, L किसी समूह के चरम (बाहरी) एक्सलों के बीच feet में दूरी है, और N उस समूह में एक्सलों की संख्या है। स्रोत: Louisiana Revised Statutes 32:386 / Federal Bridge Formula।"},"13":{"q":"लुइसियाना में एक मोटर वाहक को तब ओवरसाइज़/ओवरवेट परमिट प्राप्त करना होता है जब कोई वाहन या भार कानूनी सीमाओं से अधिक हो। ये परमिट कौन-सी एजेंसी जारी करती है?","options":["Louisiana Office of Motor Vehicles (OMV)","Louisiana Department of Transportation and Development (DOTD)","केवल Louisiana State Police","स्थानीय पैरिश शेरिफ का कार्यालय"],"explanation":"लुइसियाना में ओवरसाइज़/ओवरवेट परमिट Department of Transportation and Development (DOTD) द्वारा अपने Truck Permit Office और PERBA इलेक्ट्रॉनिक रूटिंग प्रणाली के माध्यम से जारी किए जाते हैं। स्रोत: Louisiana DOTD, Oversize and Overweight Truck Permits; LAC Title 73।"},"14":{"q":"मूवमेंट के संबंध में लुइसियाना का ओवरसाइज़/ओवरवेट परमिट कब प्राप्त किया जाना चाहिए?","options":["मूवमेंट पूरा होने के 24 hours के भीतर","यात्रा के दौरान किसी भी सड़क किनारे वजन स्टेशन पर","ओवरसाइज़/ओवरवेट वाहन या भार के लुइसियाना के भीतर चलने या प्रवेश करने से पहले","केवल चालान जारी होने के बाद"],"explanation":"ओवरसाइज़/ओवरवेट वाहन या भार के लुइसियाना राज्य के भीतर चलने या प्रवेश करने से पहले परमिट के लिए आवेदन किया जाना चाहिए और उसे प्राप्त किया जाना चाहिए। स्रोत: Louisiana DOTD oversize/overweight permit rules; LAC Title 73, Part I।"},"15":{"q":"लुइसियाना का वार्षिक ओवरसाइज़/ओवरवेट परमिट (सिंगल-ट्रिप परमिट के विपरीत) किन सड़कों पर यात्रा के लिए मान्य है?","options":["केवल Interstate राजमार्ग","केवल गैर-Interstate राजमार्ग","सभी राज्य और Interstate राजमार्ग","केवल पैरिश सड़कें"],"explanation":"लुइसियाना के वार्षिक परमिट एक वर्ष के लिए मान्य होते हैं और केवल गैर-Interstate राजमार्गों पर यात्रा को अधिकृत करते हैं; Interstate पर मूवमेंट के लिए सिंगल-ट्रिप परमिट की आवश्यकता होती है। स्रोत: Louisiana DOTD Annual Permits; LAC Title 73, Part I, Chapter 3।"},"16":{"q":"सिंगल-ट्रिप ओवरसाइज़/ओवरवेट परमिट के लिए लुइसियाना न्यूनतम कितनी राशि का बॉन्ड या बीमा प्रमाणपत्र आवश्यक करता है?","options":["$50,000","$100,000","$250,000","$500,000"],"explanation":"लुइसियाना सिंगल-ट्रिप परमिट के लिए कम से कम $100,000 के बॉन्ड या बीमा प्रमाणपत्र की आवश्यकता रखता है (और वार्षिक परमिट के लिए $250,000)। स्रोत: Louisiana DOTD oversize/overweight permit requirements।"},"17":{"q":"लुइसियाना फसल कटाई के दौरान कानूनी एक्सल या सकल भार सीमा से अधिक अपनी प्राकृतिक अवस्था में कृषि उत्पाद ढोने के लिए एक विशेष परमिट प्रदान करता है। इस परमिट को आमतौर पर क्या कहा जाता है?","options":["हार्वेस्ट सीज़न परमिट","ट्रिप लीज़ परमिट","हैज़मैट टनेज परमिट","रेसिप्रोसिटी परमिट"],"explanation":"Louisiana DOTD कानूनी सकल या एक्सल भार सीमा से अधिक अपनी प्राकृतिक अवस्था में कृषि उत्पाद ढोने वाले वाहनों के लिए हार्वेस्ट सीज़न परमिट जारी करता है; वार्षिक शुल्क $100 है। स्रोत: Louisiana DOTD Harvest Season / Annual Permits; LAC Title 73, Part I।"},"18":{"q":"लुइसियाना की गन्ना ढुलाई परमिट आवश्यकताओं के तहत, वाहन-और-ट्रेलर संयोजन में कौन-सा एक्सल विन्यास होना चाहिए?","options":["कुल मिलाकर कम से कम चार एक्सल","कुल छह एक्सल, गन्ना ट्रेलर पर एक अतिरिक्त भार-वहन एकल एक्सल के साथ","केवल एक टैंडम पिछला एक्सल","कुल आठ एक्सल जिसमें सभी लिफ्ट एक्सल उठे हुए हों"],"explanation":"लुइसियाना के गन्ना हार्वेस्ट परमिट प्रावधानों के लिए वाहन-और-ट्रेलर संयोजन हेतु कुल छह एक्सल आवश्यक हैं, जिसमें गन्ना ट्रेलर पर एक अतिरिक्त डुअल-टायर एकल एक्सल शामिल है जो नीचे किया जाता है और भार-वहन एक्सल के रूप में कार्य करता है। स्रोत: Louisiana DOTD harvest permit provisions; LAC Title 73, Part I।"},"19":{"q":"लुइसियाना में, 26,001 pounds या अधिक के सकल संयोजन भार रेटिंग (GCWR) वाले वाहनों के संयोजन को संचालित करने के लिए, जहाँ खींची जाने वाली इकाई का GVWR 10,000 pounds से अधिक हो, किस श्रेणी का Commercial Driver License आवश्यक है?","options":["Class B","Class A","Class C","Class D"],"explanation":"Louisiana R.S. 32:408 B.(2)(a) Class 'A' CDL (Combination Vehicles) को 26,001 pounds या अधिक GCWR वाले वाहनों के किसी भी संयोजन को संचालित करने की अनुमति के रूप में परिभाषित करता है, बशर्ते खींची जाने वाली इकाई का GVWR 10,000 pounds से अधिक हो। स्रोत: Louisiana CDL Manual (OMV), classes section।"},"20":{"q":"लुइसियाना नियमों के तहत, Class B CDL 26,001 pounds या अधिक GVWR वाले किसी भी एकल वाहन के संचालन को अधिकृत करता है, वैकल्पिक रूप से कितने भार से अधिक नहीं वाली एक इकाई को खींचते हुए?","options":["5,000 pounds GVWR","15,000 pounds GVWR","26,001 pounds GVWR","10,000 pounds GVWR"],"explanation":"Louisiana R.S. 32:408 B.(2)(b) Class 'B' CDL (Heavy Straight Vehicle) को 26,001 या अधिक pounds GVWR वाले किसी एकल वाहन, या ऐसे वाहन जो 10,000 pounds GVWR से अधिक न खींचता हो, के रूप में परिभाषित करता है। 10,000 lbs से अधिक खींचने पर चालक Class A में चला जाता है। स्रोत: Louisiana CDL Manual (OMV)।"},"21":{"q":"एक लुइसियाना चालक 24,000 pounds GVWR रेटेड एक एकल स्ट्रेट ट्रक संचालित करता है जो खतरनाक सामग्री के लिए प्लेकार्डेड है। न्यूनतम आवश्यक CDL श्रेणी कौन-सी है?","options":["Class B","Class A","Class D","Class C"],"explanation":"Louisiana R.S. 32:408 B.(2)(c) Class 'C' CDL (Light Vehicle) को 26,001 pounds GVWR से कम वाले एकल वाहनों के लिए परिभाषित करता है जो या तो 16 या अधिक यात्रियों (चालक सहित) को ले जाने के लिए डिज़ाइन किए गए हैं या प्लेकार्डेड मात्रा में खतरनाक सामग्री के परिवहन के लिए उपयोग किए जाते हैं। एक 24,000-lb HazMat-प्लेकार्डेड स्ट्रेट ट्रक को Class C के साथ H एंडोर्समेंट की आवश्यकता है। स्रोत: Louisiana CDL Manual (OMV)।"},"22":{"q":"लुइसियाना CDL पर, कौन-सा एंडोर्समेंट कोड डबल और ट्रिपल ट्रेलरों के संचालन को अधिकृत करता है?","options":["N","X","T","H"],"explanation":"Louisiana R.S. 32:408(3) डबल/ट्रिपल ट्रेलरों के लिए 'T' एंडोर्समेंट सूचीबद्ध करता है। (N = Tank, H = Hazardous Materials, X = संयुक्त Tank और HazMat।) स्रोत: Louisiana CDL Manual (OMV), endorsements section।"},"23":{"q":"केवल INTRASTATE (राज्य के भीतर) ड्राइविंग के लिए लुइसियाना CDL प्राप्त करने की न्यूनतम आयु क्या है?","options":["21 वर्ष","19 वर्ष","17 वर्ष","18 वर्ष"],"explanation":"Louisiana R.S. 32:408 Class A, B, और C CDLs के लिए आयु आवश्यकता को intrastate के लिए 18 वर्ष या अधिक और interstate के लिए 21 वर्ष या अधिक के रूप में सूचीबद्ध करता है। स्रोत: Louisiana CDL Manual (OMV), classes section।"},"24":{"q":"एक 19 वर्षीय व्यक्ति के पास एक वैध लुइसियाना CDL है। उन्हें कौन-सा संचालन करने की अनुमति है?","options":["interstate वाणिज्य में CMV चलाना","प्लेकार्डेड खतरनाक सामग्री का परिवहन","लुइसियाना के भीतर intrastate वाणिज्य में CMV चलाना","H (HazMat) एंडोर्समेंट रखना"],"explanation":"लुइसियाना CDL आयु intrastate के लिए 18 परंतु interstate के लिए 21 निर्धारित करता है, और H (HazMat) एंडोर्समेंट 'केवल 21 वर्ष या उससे अधिक आयु के व्यक्तियों को जारी किया जाता है।' एक 19 वर्षीय व्यक्ति केवल intrastate चला सकता है और HazMat एंडोर्समेंट प्राप्त नहीं कर सकता। स्रोत: Louisiana CDL Manual (OMV), R.S. 32:408।"},"25":{"q":"लुइसियाना में, H (Hazardous Materials) एंडोर्समेंट केवल कम से कम कितनी आयु के आवेदकों को जारी किया जा सकता है?","options":["18 वर्ष","25 वर्ष","19 वर्ष","21 वर्ष"],"explanation":"Louisiana CDL Manual की एंडोर्समेंट सूची (R.S. 32:408(3)) बताती है कि 'H' Hazardous Materials एंडोर्समेंट 'केवल 21 वर्ष या उससे अधिक आयु के व्यक्तियों को जारी किया जाता है,' जो प्लेकार्डेड HazMat परिवहन की interstate-केवल प्रकृति के अनुरूप है। स्रोत: Louisiana CDL Manual (OMV)।"},"26":{"q":"लुइसियाना HazMat (H) एंडोर्समेंट जारी किए जाने से पहले, एक आवेदक को कौन-सी अतिरिक्त जाँच पास करनी होती है?","options":["केवल-दृष्टि पुनः-परीक्षण","36-घंटे का कक्षा रक्षात्मक-ड्राइविंग पाठ्यक्रम","टैंकर वाहन में रोड टेस्ट","फिंगरप्रिंटिंग और पृष्ठभूमि जाँच सहित TSA सुरक्षा खतरा मूल्यांकन"],"explanation":"Louisiana CDL Manual (Section 1.2.6) बताता है कि HazMat एंडोर्समेंट के लिए फिंगरप्रिंट और पृष्ठभूमि जाँच जमा करना आवश्यक है; यदि Transportation Security Administration (TSA) द्वारा सुरक्षा खतरा माना जाता है तो आवेदक को अस्वीकार कर दिया जाता है। फिंगरप्रिंट पृष्ठभूमि जाँच सबसे हाल के 180 days के भीतर होनी चाहिए। स्रोत: Louisiana CDL Manual (OMV), TSA / 49 CFR 1572।"},"27":{"q":"लुइसियाना HazMat एंडोर्समेंट के लिए एक आवेदक को निम्नलिखित में से किस स्थिति के तहत एंडोर्समेंट से अस्वीकार कर दिया जाएगा?","options":["उनके पास दो वर्ष से कम CDL अनुभव है","वे 25 वर्ष से कम आयु के हैं","वे संयुक्त राज्य अमेरिका के वैध स्थायी निवासी नहीं हैं","उनके पास Class A CDL नहीं है"],"explanation":"Louisiana CDL Manual Section 1.2.6 के अनुसार, यदि आप U.S. के वैध स्थायी निवासी नहीं हैं, U.S. नागरिकता त्यागते हैं, वांछित/अभियोग के अधीन हैं या कुछ अपराधों के दोषी हैं, मानसिक रूप से अक्षम घोषित किए गए हैं, या TSA द्वारा सुरक्षा खतरा माने जाते हैं, तो आपको HazMat एंडोर्समेंट से अस्वीकार कर दिया जाएगा या उसे खो देंगे। स्रोत: Louisiana CDL Manual (OMV); TSA HME rule।"},"28":{"q":"लुइसियाना टैंक वाहन (N) एंडोर्समेंट तब आवश्यक होता है जब Class A या B CDL की आवश्यकता वाला वाहन कम से कम कितनी क्षमता रेटेड स्थायी रूप से लगे कार्गो टैंक में तरल/गैस ढोता है?","options":["119 gallons या अधिक","100 gallons या अधिक","500 gallons या अधिक","1,000 gallons या अधिक"],"explanation":"Louisiana CDL Manual (Section 8, Tank Vehicles) बताता है कि टैंक एंडोर्समेंट तब आवश्यक है यदि आपके वाहन को Class A या B CDL की आवश्यकता है और आप 119 gallons या अधिक रेटेड स्थायी रूप से लगे कार्गो टैंक में, या 1,000 gallons या अधिक रेटेड पोर्टेबल टैंक में तरल या गैस ढोते हैं। स्रोत: Louisiana CDL Manual (OMV)।"},"29":{"q":"लुइसियाना टैंक (N) एंडोर्समेंट के लिए, एक PORTABLE टैंक कम से कम कितनी क्षमता रेटेड होने पर एंडोर्समेंट आवश्यकता को सक्रिय करता है?","options":["119 gallons या अधिक","1,000 gallons या अधिक","660 gallons या अधिक","2,000 gallons या अधिक"],"explanation":"Louisiana CDL Manual निर्दिष्ट करता है कि टैंक एंडोर्समेंट 1,000 gallons या अधिक रेटेड पोर्टेबल टैंक पर लागू होता है (बनाम स्थायी रूप से लगे कार्गो टैंक के लिए 119 gallons या अधिक)। स्रोत: Louisiana CDL Manual (OMV), Tank Vehicles section।"},"30":{"q":"लुइसियाना CDL पर कौन-सा एंडोर्समेंट कोड Tank Vehicles और Hazardous Materials के संयोजन का प्रतिनिधित्व करता है?","options":["T","X","N","H"],"explanation":"Louisiana R.S. 32:408(3) 'X' एंडोर्समेंट को Tank Vehicles और Hazardous Materials के संयोजन के रूप में सूचीबद्ध करता है। (N = केवल Tank, H = केवल HazMat, T = Doubles/Triples।) स्रोत: Louisiana CDL Manual (OMV), endorsements section।"},"31":{"q":"स्कूल बस चलाने के लिए विशेष रूप से कौन-सा लुइसियाना CDL एंडोर्समेंट आवश्यक है?","options":["S","P","T","N"],"explanation":"Louisiana R.S. 32:408(3) School Bus के लिए 'S' एंडोर्समेंट सूचीबद्ध करता है। 'P' (Passenger) एंडोर्समेंट सामान्यतः बसों को कवर करता है और यह भी आवश्यक है, परंतु स्कूल-बस-विशिष्ट एंडोर्समेंट 'S' है। स्रोत: Louisiana CDL Manual (OMV), endorsements section।"},"32":{"q":"लुइसियाना में लागू संघीय मानक के तहत, Commercial Learner Permit (CLP) पहली बार जारी होने के बाद, धारक को CDL स्किल्स टेस्ट देने के लिए पात्र होने से पहले कम से कम कितनी प्रतीक्षा करनी होती है?","options":["14 days","7 days","30 days","10 days"],"explanation":"49 CFR 383.25(e) के अनुसार, जो लुइसियाना में अपनाया गया है, CLP धारक CLP के प्रारंभिक जारी होने के बाद पहले 14 days के भीतर CDL स्किल्स टेस्ट देने के लिए पात्र नहीं है। यह 14-दिन की प्रतीक्षा अवधि पहिए के पीछे अभ्यास के लिए समय देती है। स्रोत: 49 CFR 383.25(e); Louisiana OMV CDL requirements।"},"33":{"q":"लुइसियाना CLP पर CMV में अभ्यास करते समय, परमिट धारक के साथ हर समय किसका होना आवश्यक है?","options":["21 वर्ष से अधिक आयु का कोई भी लाइसेंस प्राप्त Class E चालक","आगे की सीट पर बैठा उचित श्रेणी और एंडोर्समेंट वाला CDL धारक","केवल एक प्रमाणित तृतीय-पक्ष परीक्षक","ज्ञान परीक्षा पास होने के बाद किसी पर्यवेक्षण की आवश्यकता नहीं"],"explanation":"Louisiana OMV CLP नियम (49 CFR 383.25 के अनुसार) पहिए के पीछे के सभी संचालन के दौरान CLP धारक के साथ एक वैध CDL धारक होना आवश्यक करते हैं जिसके पास उचित श्रेणी और एंडोर्समेंट हो, और जो वाहन की आगे की सीट (केबिन) में बैठा हो। स्रोत: Louisiana OMV New CDL page; 49 CFR 383.25।"},"34":{"q":"पहली बार Class A और Class B आवेदकों के अतिरिक्त, लुइसियाना में किन एंडोर्समेंट चाहने वाले पहली बार आवेदकों के लिए ELDT आवश्यक है?","options":["Hazardous Materials (H), Passenger (P), और School Bus (S)","केवल Tank (N) और Doubles/Triples (T)","केवल Motorcycle (M) और Passenger (P)","बिना किसी अपवाद के सभी एंडोर्समेंट"],"explanation":"FMCSA ELDT (7 फरवरी, 2022 से प्रभावी, लुइसियाना में लागू) पहली बार Class A या B CDL आवेदकों, B से A अपग्रेड, और Hazardous Materials (H), Passenger (P), और School Bus (S) एंडोर्समेंट के लिए पहली बार आवेदकों को कवर करता है। Tank (N) और Doubles/Triples (T) ELDT-कवर एंडोर्समेंट नहीं हैं। स्रोत: FMCSA Training Provider Registry / ELDT Applicability।"},"35":{"q":"लुइसियाना में, CDL प्रयोजनों के लिए कानूनी रूप से नशे में माने जाने से पहले एक चालक के पास वाणिज्यिक मोटर वाहन (CMV) संचालित करते समय अधिकतम कितनी रक्त अल्कोहल सांद्रता (BAC) हो सकती है?","options":["0.04 percent","0.08 percent","0.02 percent","0.10 percent"],"explanation":"लुइसियाना कानून CMV BAC सीमा को 0.04 percent पर निर्धारित करता है, जो गैर-वाणिज्यिक चालकों की 0.08 percent सीमा का आधा है। 0.04 percent या उससे अधिक पर CMV संचालित करने वाला CDL धारक नशे में माना जाता है। स्रोत: La. R.S. 32:414.2 और Louisiana CDL Manual (Section 1.2, Disqualifications)।"},"36":{"q":"लुइसियाना CDL रखने और एक वाणिज्यिक वाहन संचालित करने से, एक चालक स्वतः ही क्या करने के लिए सहमत माना जाता है?","options":["कानूनी रूप से अनुरोध किए जाने पर साँस, रक्त, या मूत्र की रासायनिक जाँच कराना","हर समय संघीय hours-of-service लॉग की एक प्रति रखना","किसी भी ट्रैफिक टिकट पर अदालती सुनवाई के अधिकार का त्याग करना","सभी टोल शुल्क नकद के बजाय इलेक्ट्रॉनिक रूप से चुकाना"],"explanation":"लुइसियाना के implied-consent कानून के तहत, CMV संचालित करने वाला कोई भी व्यक्ति, जब किसी अधिकारी के पास उचित कारण हो, अल्कोहल या ड्रग उपस्थिति निर्धारित करने के लिए साँस, रक्त, या मूत्र की रासायनिक जाँच के लिए सहमत माना जाता है। स्रोत: La. R.S. 32:414.2 (implied consent) और Louisiana CDL Manual।"},"37":{"q":"किसी पहले प्रमुख अपराध के लिए, जैसे CMV को 0.04 percent या अधिक BAC के साथ संचालित करना, एक लुइसियाना CDL धारक को कितने समय के लिए अयोग्य ठहराया जाता है?","options":["1 year","60 days","6 months","3 years"],"explanation":"एक पहला प्रमुख अपराध (DUI, CMV में 0.04 percent या अधिक BAC, जाँच से इनकार, या घटनास्थल छोड़ना सहित) लुइसियाना कानून के तहत 1-year की अयोग्यता का परिणाम होता है, जो 49 CFR 383.51 के अनुरूप है। स्रोत: La. R.S. 32:414.2 और Louisiana CDL Manual।"},"38":{"q":"यदि कोई लुइसियाना CDL धारक खतरनाक सामग्री के लिए प्लेकार्डेड CMV संचालित करते समय पहला प्रमुख अपराध करता है, तो अयोग्यता अवधि बढ़कर हो जाती है:","options":["3 years","1 year","2 years","आजीवन"],"explanation":"जब खतरनाक सामग्री के लिए प्लेकार्ड किए जाने हेतु आवश्यक CMV में पहला प्रमुख अपराध होता है, तो अयोग्यता 1 year से बढ़ाकर 3 years कर दी जाती है। स्रोत: La. R.S. 32:414.2 और 49 CFR 383.51, जैसा Louisiana CDL Manual में अपनाया गया है।"},"39":{"q":"एक लुइसियाना CDL धारक जो दूसरे प्रमुख अपराध (उदाहरण के लिए, CMV में दूसरा DUI) का दोषी ठहराया जाता है, के लिए अयोग्यता अवधि क्या है?","options":["आजीवन अयोग्यता","10-वर्षीय अयोग्यता","5-वर्षीय अयोग्यता","3-वर्षीय अयोग्यता"],"explanation":"प्रमुख अपराधों के किसी भी संयोजन के लिए दूसरी दोषसिद्धि लुइसियाना में आजीवन CDL अयोग्यता का परिणाम होती है, जो 49 CFR 383.51 के अनुरूप है। (संघीय नियमों के तहत 10-वर्षीय न्यूनतम पुनर्बहाली उपलब्ध हो सकती है।) स्रोत: La. R.S. 32:414.2 और Louisiana CDL Manual।"},"40":{"q":"एक लुइसियाना CDL धारक से कानूनी रूप से रासायनिक जाँच कराने को कहा जाता है, परंतु वह इनकार कर देता है। CDL के लिए इसका परिणाम क्या है?","options":["कम से कम 1 year के लिए अयोग्यता, DUI दोषसिद्धि के समान","पहली बार इनकार पर केवल एक चेतावनी","60 days के लिए अयोग्यता","यदि आपराधिक आरोप खारिज हो जाते हैं तो कोई CDL परिणाम नहीं"],"explanation":"लुइसियाना के implied-consent कानून के तहत रासायनिक जाँच से इनकार करना कम से कम 1 year की CDL अयोग्यता का परिणाम होता है, जो एक प्रमुख अपराध के समान है, और यह किसी भी आपराधिक मामले के परिणाम की परवाह किए बिना लागू होता है। स्रोत: La. R.S. 32:414.2 और Louisiana CDL Manual।"},"41":{"q":"लुइसियाना CDL धारक के लिए निम्नलिखित में से किसे 'गंभीर ट्रैफिक उल्लंघन' के रूप में वर्गीकृत किया जाता है?","options":["निर्धारित सीमा से 15 mph या अधिक तेज गति","निर्धारित सीमा से 5 mph तेज गति","वाणिज्यिक क्षेत्र में पार्किंग उल्लंघन","समाप्त पंजीकरण स्टिकर के साथ ड्राइविंग"],"explanation":"निर्धारित सीमा से 15 mph या अधिक तेज गति CDL धारकों के लिए सूचीबद्ध गंभीर ट्रैफिक उल्लंघनों में से एक है। अन्य में लापरवाह ड्राइविंग, अनुचित या अनियमित लेन परिवर्तन, और बहुत करीब से चलना शामिल हैं। स्रोत: 49 CFR 383.51 जैसा Louisiana CDL Manual में अपनाया गया है।"},"42":{"q":"3-वर्ष की अवधि के भीतर दो गंभीर ट्रैफिक उल्लंघनों का दोषी ठहराए जाने पर एक लुइसियाना CDL धारक को कितने समय के लिए अयोग्य ठहराया जाता है?","options":["60 days","30 days","120 days","1 year"],"explanation":"3 वर्षों के भीतर (अलग-अलग घटनाओं में) दूसरा गंभीर ट्रैफिक उल्लंघन लुइसियाना कानून के तहत 60-day की अयोग्यता का परिणाम होता है, जो 49 CFR 383.51 से मेल खाता है। स्रोत: La. R.S. 32:414.2 और Louisiana CDL Manual।"},"43":{"q":"3-वर्ष की अवधि के भीतर तीन गंभीर ट्रैफिक उल्लंघनों का दोषी ठहराए जाने पर एक लुइसियाना CDL धारक को कितने समय के लिए अयोग्य ठहराया जाता है?","options":["120 days","60 days","90 days","180 days"],"explanation":"3 वर्षों के भीतर (अलग-अलग घटनाओं में) तीसरा गंभीर ट्रैफिक उल्लंघन 120-day की अयोग्यता का परिणाम होता है, जो किसी भी पूर्व 60-day अवधि के बाद क्रमिक रूप से निभाई जाती है। स्रोत: 49 CFR 383.51 जैसा Louisiana CDL Manual और La. R.S. 32:414.2 द्वारा अपनाया गया है।"},"44":{"q":"लुइसियाना में वाणिज्यिक मोटर वाहन चलाते समय हाथ में पकड़े मोबाइल टेलीफोन का उपयोग करना CDL प्रयोजनों के लिए किस प्रकार के अपराध के रूप में माना जाता है?","options":["एक गंभीर ट्रैफिक उल्लंघन जो अयोग्यता की ओर गिना जाता है","कोई CDL प्रभाव न रखने वाला एक गैर-चलित उल्लंघन","एक स्वचालित 1-year प्रमुख अपराध","एक उल्लंघन केवल तभी जब दुर्घटना हो"],"explanation":"CMV संचालित करते समय हाथ में फोन का उपयोग या टेक्स्टिंग एक गंभीर ट्रैफिक उल्लंघन है जो 2-in-3-years (60-day) और 3-in-3-years (120-day) अयोग्यता सीमाओं की ओर गिना जाता है। स्रोत: 49 CFR 383.51 / 392.82 जैसा Louisiana CDL Manual में अपनाया गया है।"},"45":{"q":"CMV चलाते समय टेक्स्टिंग करना भी एक गंभीर उल्लंघन है। लुइसियाना में लागू CDL नियमों में संदर्भित, टेक्स्टिंग के लिए एक CMV चालक को जो संघीय नागरिक दंड का सामना करना पड़ सकता है, वह लगभग कितना अधिक हो सकता है:","options":["$2,750","$500","$1,000","$10,000"],"explanation":"CDL अयोग्यता के अलावा, ड्राइविंग करते समय टेक्स्ट करने वाले एक CMV चालक को लगभग $2,750 तक के संघीय नागरिक दंड का सामना करना पड़ता है। स्रोत: 49 CFR 392.80/392.82, Louisiana CDL Manual में संदर्भित।"},"46":{"q":"एक लुइसियाना CDL धारक की रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन की पहली दोषसिद्धि के लिए न्यूनतम अयोग्यता क्या है?","options":["60 days","30 days","120 days","1 year"],"explanation":"एक पहला रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन (जैसे रुकने में विफल होना या क्रॉसिंग पार करने के लिए पर्याप्त स्थान न होना) लुइसियाना में न्यूनतम 60-day की अयोग्यता वहन करता है। स्रोत: 49 CFR 383.51 जैसा Louisiana CDL Manual द्वारा अपनाया गया है।"},"47":{"q":"एक लुइसियाना CDL धारक 3-वर्ष की अवधि के भीतर दूसरा रेलमार्ग-ग्रेड क्रॉसिंग उल्लंघन करता है। न्यूनतम अयोग्यता है:","options":["120 days","60 days","90 days","1 year"],"explanation":"3 वर्षों के भीतर दूसरा रेलमार्ग-ग्रेड क्रॉसिंग उल्लंघन न्यूनतम 120-day की अयोग्यता का परिणाम होता है। स्रोत: 49 CFR 383.51 जैसा Louisiana CDL Manual द्वारा अपनाया गया है।"},"48":{"q":"एक लुइसियाना CDL धारक 3-वर्ष की अवधि के भीतर तीसरा रेलमार्ग-ग्रेड क्रॉसिंग उल्लंघन करता है। न्यूनतम अयोग्यता है:","options":["1 year","120 days","180 days","3 years"],"explanation":"3 वर्षों के भीतर तीसरा रेलमार्ग-ग्रेड क्रॉसिंग उल्लंघन न्यूनतम 1-year की अयोग्यता का परिणाम होता है। स्रोत: 49 CFR 383.51 जैसा Louisiana CDL Manual द्वारा अपनाया गया है।"},"49":{"q":"CMV संचालित करते समय out-of-service order के उल्लंघन (गैर-hazmat, गैर-यात्री) की पहली दोषसिद्धि के लिए एक लुइसियाना CDL धारक की अयोग्यता अवधि क्या है?","options":["कम से कम 180 days, 1 year तक","कम से कम 30 days","कम से कम 60 days","आजीवन"],"explanation":"एक पहला out-of-service (OOS) order उल्लंघन एक मानक CMV के लिए कम से कम 180 days और 1 year तक की अयोग्यता का परिणाम होता है। स्रोत: La. R.S. 32:414.2 और 49 CFR 383.51 जैसा Louisiana CDL Manual में अपनाया गया है।"},"50":{"q":"एक लुइसियाना CDL धारक 10-वर्ष की अवधि के भीतर दूसरे out-of-service order उल्लंघन का दोषी ठहराया जाता है। अयोग्यता सीमा है:","options":["2 to 5 years","1 to 2 years","60 to 120 days","आजीवन"],"explanation":"10 वर्षों के भीतर दूसरा out-of-service order उल्लंघन एक मानक CMV के लिए 2 to 5 years की अयोग्यता का परिणाम होता है। स्रोत: La. R.S. 32:414.2 और 49 CFR 383.51 जैसा Louisiana CDL Manual में अपनाया गया है।"},"51":{"q":"प्लेकार्ड की आवश्यकता वाली खतरनाक सामग्री ढोने वाले CDL धारक के लिए, एक पहला out-of-service order उल्लंघन कितनी अयोग्यता वहन करता है:","options":["कम से कम 180 days, 2 years तक","कम से कम 30 days, 60 days तक","ठीक 1 year","आजीवन"],"explanation":"जब OOS उल्लंघन प्लेकार्डेड खतरनाक सामग्री के परिवहन के दौरान या 16 या अधिक यात्रियों को ले जाने के लिए डिज़ाइन किए गए वाहन के संचालन के दौरान होता है, तो पहले-अपराध की अयोग्यता कम से कम 180 days और 2 years तक होती है। स्रोत: 49 CFR 383.51 जैसा Louisiana CDL Manual में अपनाया गया है।"},"52":{"q":"निम्नलिखित में से कौन सबसे अच्छा वर्णन करता है कि लुइसियाना CDL अयोग्यता की ओर गंभीर ट्रैफिक उल्लंघनों की गणना कैसे करता है?","options":["3-वर्ष की अवधि के भीतर अलग-अलग घटनाओं में दोषसिद्धियाँ","केवल एक ही दिन होने वाली दोषसिद्धियाँ","केवल 1-वर्ष की अवधि के भीतर सभी दोषसिद्धियाँ","केवल ड्यूटी से बाहर रहते हुए किए गए उल्लंघन"],"explanation":"गंभीर ट्रैफिक उल्लंघन अयोग्यताएँ (दूसरे के लिए 60 days, तीसरे के लिए 120 days) 3-वर्ष की अवधि के भीतर अलग-अलग घटनाओं से उत्पन्न दोषसिद्धियों पर आधारित हैं। स्रोत: 49 CFR 383.51 जैसा Louisiana CDL Manual और La. R.S. 32:414.2 द्वारा अपनाया गया है।"},"53":{"q":"एक चालक CMV संचालित करते समय एक मृत्यु का कारण बनता है और मृत्यु से जुड़े ट्रैफिक अपराध (जैसे लापरवाह या असावधान संचालन) का दोषी ठहराया जाता है। लुइसियाना में CDL प्रयोजनों के लिए, इसे इस रूप में माना जाता है:","options":["एक गंभीर ट्रैफिक उल्लंघन जो अयोग्यता की ओर गिना जाता है","केवल एक गैर-CDL प्रशासनिक मामला","एक स्वचालित आजीवन अयोग्यता","एक रेलमार्ग-क्रॉसिंग उल्लंघन"],"explanation":"किसी घातक दुर्घटना के संबंध में किया गया एक यातायात-नियंत्रण-कानून उल्लंघन गंभीर ट्रैफिक उल्लंघन सूची में शामिल है, जो 60-day और 120-day सीमाओं की ओर गिना जाता है। (गैर-इरादतन हत्या या CMV के साथ एक felony एक अलग 1-year प्रमुख अपराध है।) स्रोत: 49 CFR 383.51 जैसा Louisiana CDL Manual में अपनाया गया है।"},"54":{"q":"एक लुइसियाना CDL धारक किसी नियंत्रित पदार्थ के निर्माण या वितरण से जुड़ा एक felony करने के लिए CMV का उपयोग करता है। अयोग्यता है:","options":["आजीवन, बिना किसी पुनर्बहाली के","1 year","3 years","60 days"],"explanation":"नियंत्रित-पदार्थ के निर्माण, वितरण, या वितरण से जुड़े felony को करने में CMV का उपयोग करना अन्य प्रमुख अपराधों के विपरीत, पुनर्बहाली की किसी संभावना के बिना आजीवन अयोग्यता का परिणाम होता है। स्रोत: La. R.S. 32:414.2 और 49 CFR 383.51 जैसा Louisiana CDL Manual में अपनाया गया है।"},"55":{"q":"लुइसियाना के किसी इंटरस्टेट या नियंत्रित-पहुँच राजमार्ग पर, क़ानून द्वारा निर्धारित अधिकतम पोस्ट की गई गति सीमा क्या है (जब तक कोई अलग सीमा पोस्ट न की गई हो)?","options":["60 mph","65 mph","70 mph","75 mph"],"explanation":"Louisiana RS 32:61 इंटरस्टेट या नियंत्रित-पहुँच राजमार्गों पर क़ानूनी अधिकतम सीमा 70 mph निर्धारित करता है, जब तक अन्यथा पोस्ट न किया गया हो। स्रोत: Louisiana RS 32:61; Louisiana DOTD 'Speed Limit' विवरणिका।"},"56":{"q":"लुइसियाना के क़ानून के तहत, ऐसे बहु-लेन विभाजित (DIVIDED) राजमार्ग पर जो इंटरस्टेट नहीं है, क़ानूनी गति सीमा क्या है, जब तक अन्यथा पोस्ट न किया गया हो?","options":["55 mph","65 mph","70 mph","60 mph"],"explanation":"RS 32:61 के अनुसार किसी भी लुइसियाना राजमार्ग पर सीमा 55 mph से अधिक नहीं होनी चाहिए, जब तक कि वह बहु-लेन विभाजित राजमार्ग (65 mph) या इंटरस्टेट/नियंत्रित-पहुँच राजमार्ग (70 mph) न हो। स्रोत: Louisiana RS 32:61; Louisiana DOTD 'Speed Limit' विवरणिका।"},"57":{"q":"लुइसियाना के किसी इंटरस्टेट पर, ट्रैक्टर-ट्रेलर के लिए अधिकतम गति सीमा यात्री कार की सीमा की तुलना में कैसी है?","options":["ट्रकों को पोस्ट की गई सीमा से 10 mph नीचे रहना चाहिए","ट्रकों की सीमा कारों से 5 mph कम होती है","ट्रकों की अधिकतम सीमा कारों के समान ही होती है","ट्रक पूरे राज्य में 55 mph तक सीमित हैं"],"explanation":"लुइसियाना में ट्रकों के लिए कोई अलग कम इंटरस्टेट गति सीमा नहीं है; पूर्व ट्रक-गति क़ानून RS 32:62 को निरस्त कर दिया गया था (Acts 2010, No. 81) और बाद का '10 mph नीचे' वाला प्रस्ताव लागू नहीं हुआ। RS 32:61 की सीमाएँ सभी वाहनों पर लागू होती हैं, जब तक अन्यथा पोस्ट न किया गया हो। स्रोत: Louisiana RS 32:61; RS 32:62 (2010 में निरस्त)।"},"58":{"q":"एक लुइसियाना बस चालक ऐसे रेलरोड क्रॉसिंग के पास पहुँचता है जहाँ रुकना आवश्यक है। बस को निकटतम रेल के सापेक्ष कहाँ रोका जाना चाहिए?","options":["5 से 25 फ़ीट के बीच","15 से 50 फ़ीट के बीच","50 से 100 फ़ीट के बीच","10 से 40 फ़ीट के बीच"],"explanation":"Louisiana CDL Manual कहता है कि बस को रेलरोड क्रॉसिंग से पहले 15 से 50 फ़ीट के बीच रुकना चाहिए, फिर पार करने से पहले दोनों दिशाओं में देखना और सुनना चाहिए। स्रोत: Louisiana CDL Manual, Sec. 4.3.5 (Railroad-highway Crossing Stops)।"},"59":{"q":"लुइसियाना में प्लेकार्ड लगे ख़तरनाक पदार्थ ढोने वाला एक चालक किसी ग़ैर-छूट प्राप्त रेलरोड क्रॉसिंग पर पहुँचता है। वाहन को निकटतम रेल से कितनी दूरी पर रुकना चाहिए?","options":["15 फ़ीट से अधिक पास नहीं और 50 फ़ीट से अधिक दूर नहीं","10 फ़ीट से अधिक पास नहीं और 25 फ़ीट से अधिक दूर नहीं","25 फ़ीट से अधिक पास नहीं और 75 फ़ीट से अधिक दूर नहीं","ठीक 50 फ़ीट, फिर धीरे-धीरे आगे बढ़ें"],"explanation":"बसों, स्कूल बसों और प्लेकार्ड लगे वाहनों को निकटतम रेल से 50 फ़ीट के भीतर लेकिन 15 फ़ीट से कम नहीं की दूरी पर वाहन रोकना चाहिए, फिर पार करने से पहले देखना और सुनना चाहिए। स्रोत: Louisiana CDL Manual, Sec. 13.1.8 (Railroad Crossing procedures)।"},"60":{"q":"Louisiana RS 32:80 के तहत, ऐसी रुकी हुई स्कूल बस से मिलते या उसे ओवरटेक करते समय जिसके दृश्य संकेत चालू हैं, चालक को बस से कितनी दूरी से अधिक पास नहीं रुकना चाहिए?","options":["10 फ़ीट","20 फ़ीट","30 फ़ीट","50 फ़ीट"],"explanation":"RS 32:80 के अनुसार किसी भी दिशा से आने वाले चालकों को ऐसी स्कूल बस से कम से कम 30 फ़ीट की दूरी पर रुकना चाहिए जो बच्चों को चढ़ाने या उतारने के लिए अपने दृश्य संकेत चालू करके रुकी है, और बस के चलने या संकेत बंद होने तक रुके रहना चाहिए। स्रोत: Louisiana RS 32:80।"},"61":{"q":"लुइसियाना में अलग-अलग सड़कमार्गों वाले चार-लेन विभाजित (DIVIDED) राजमार्ग पर, एक स्कूल बस बच्चों को उतारने के लिए विपरीत (OPPOSITE) सड़कमार्ग पर रुकती है। दूसरी दिशा में यात्रा करने वाले चालक को क्या करना चाहिए?","options":["रुकें और संकेत बंद होने तक प्रतीक्षा करें","केवल तभी रुकें जब बच्चे पार कर रहे हों","रुकने की ज़रूरत नहीं; विभाजित-राजमार्ग अपवाद लागू होता है","15 mph तक धीमा करें लेकिन रुकने की ज़रूरत नहीं"],"explanation":"RS 32:80 के अनुसार अलग-अलग सड़कमार्गों वाले विभाजित राजमार्ग के किसी भिन्न सड़कमार्ग पर (या किसी नियंत्रित-पहुँच राजमार्ग पर जहाँ बस लोडिंग ज़ोन में है) स्कूल बस के लिए चालक को रुकने की ज़रूरत नहीं है। स्रोत: Louisiana RS 32:80।"},"62":{"q":"लुइसियाना में, प्रत्येक दिशा में एक लेन और साथ में एक केंद्रीय दो-तरफ़ा बाएँ-मुड़ने वाली लेन वाली दो-लेन सड़क पर एक रुकी हुई स्कूल बस बच्चों को चढ़ा रही है। स्कूल-बस रुकने के क़ानून के लिए, इस सड़क को माना जाता है:","options":["एक विभाजित राजमार्ग, इसलिए आने वाले ट्रैफ़िक को रुकने की ज़रूरत नहीं","विभाजित राजमार्ग नहीं, इसलिए आने वाले ट्रैफ़िक को रुकना चाहिए","एक नियंत्रित-पहुँच राजमार्ग जो रुकने से छूट प्राप्त है","एक एकतरफ़ा सड़क जिसमें रुकने का कोई कर्तव्य नहीं"],"explanation":"RS 32:80 स्पष्ट रूप से बताता है कि प्रत्येक दिशा में एक लेन और एक समर्पित दो-तरफ़ा बाएँ-मुड़ने वाली लेन वाले राजमार्ग को अलग-अलग सड़कमार्गों वाला विभाजित राजमार्ग नहीं माना जाएगा, इसलिए आने वाले चालकों को फिर भी रुकना चाहिए। स्रोत: Louisiana RS 32:80।"},"63":{"q":"लुइसियाना का Move Over क़ानून (RS 32:125) तब लागू होता है जब आप किसी राजमार्ग पर अपनी दिशा में दो या अधिक लेन होने पर दृश्य संकेत दिखाती रुकी हुई आपातकालीन वाहन के पास पहुँचते हैं। पहली आवश्यक कार्रवाई क्या है?","options":["अपनी लेन में पूरी तरह रुक जाएँ","यदि संभव हो तो खड़े वाहन से सटी हुई लेन के अलावा किसी लेन में बदलें","अपना हॉर्न बजाएँ और गति बनाए रखें","दाहिने किनारे (shoulder) पर जाकर रुकें"],"explanation":"RS 32:125 के अनुसार समान दिशा में दो या अधिक लेन वाली सड़क पर चालकों को रास्ता देने के लिए, जब सुरक्षा और ट्रैफ़िक को ध्यान में रखते हुए संभव हो, खड़े आपातकालीन वाहन से सटी हुई लेन के अलावा किसी लेन में बदलना चाहिए। स्रोत: Louisiana RS 32:125।"},"64":{"q":"लुइसियाना के Move Over क़ानून के तहत, यदि आप किसी रुकी हुई आपातकालीन वाहन से सुरक्षित रूप से लेन बदलकर दूर नहीं हट सकते (या आप दो-लेन सड़क पर हैं), तो आपको क्या करना चाहिए?","options":["दृश्य साफ़ होने तक पूरी तरह रुकें","अपनी सामान्य गति बनाए रखें और बाएँ ओर मुड़ें","परिस्थितियों के लिए उचित रूप से सुरक्षित गति तक धीमा करें","क्षेत्र को जल्दी पार करने के लिए तेज़ी से आगे बढ़ें"],"explanation":"RS 32:125 के अनुसार यदि लेन बदलना संभव नहीं है या आप दो-लेन सड़क पर हैं, तो खड़े आपातकालीन वाहन के पास से गुज़रते समय आपको सड़क की परिस्थितियों के लिए उचित रूप से सुरक्षित गति तक धीमा करना चाहिए। स्रोत: Louisiana RS 32:125।"},"65":{"q":"पुलिस, अग्निशमन और EMS के अलावा, लुइसियाना का Move Over क़ानून (RS 32:125) चेतावनी रोशनी दिखाती किन अन्य रुकी हुई वाहनों की सुरक्षा करता है?","options":["केवल चिह्नित क़ानून-प्रवर्तन इकाइयाँ","टो ट्रक/रेकर और एम्बर/पीली चमकती रोशनी का उपयोग करने वाले वाहन","केवल एम्बुलेंस और अग्निशमन उपकरण","केवल डाक-वितरण वाहन"],"explanation":"RS 32:125 में अधिकृत दृश्य संकेतों को क़ानूनी रूप से दिखाने वाला कोई भी वाहन शामिल है, जिसमें बारी-बारी से चमकती एम्बर, पीली या हरी चेतावनी रोशनी शामिल है, जो इस सुरक्षा को टो ट्रक/रेकर और समान सेवा वाहनों तक बढ़ाता है। स्रोत: Louisiana RS 32:125 (Acts 2021, No. 78 द्वारा संशोधित)।"},"66":{"q":"सायरन बजाती और रोशनी दिखाती किसी अधिकृत आपातकालीन वाहन के तुरंत पास आने पर, Louisiana RS 32:125 हर दूसरे वाहन के चालक से अपेक्षा करता है कि वह:","options":["आगे के चौराहे को साफ़ करने के लिए गति बढ़ाएँ","केंद्रीय लेन में जाएँ और धीमा करें","किसी भी चौराहे से दूर, दाहिने किनारे या कर्ब की ओर चलाएँ, और रुकें","वाहन जहाँ भी हो वहीं तुरंत रुक जाएँ, चौराहे में भी"],"explanation":"RS 32:125 के अनुसार रास्ता देने के लिए दाहिने किनारे या कर्ब के समानांतर और जितना संभव हो उतना पास, किसी भी चौराहे से दूर स्थिति में चलाना चाहिए, और आपातकालीन वाहन के गुज़रने तक रुकना चाहिए। स्रोत: Louisiana RS 32:125।"},"67":{"q":"लुइसियाना के किसी बहु-लेन राजमार्ग पर, एक धीमा वाणिज्यिक वाहन जो बाईं लेन में आगे निकलना चाहते तेज़ वाहन को बाधित कर रहा है, उसे RS 32:71 के तहत:","options":["अगले निकास तक अपनी स्थिति बनाए रखनी चाहिए","शीघ्रता से दाईं लेन में विलीन हो जाना चाहिए","और धीमा करके वाहन को दाईं ओर से गुज़रने देना चाहिए","बाईं किनारे (shoulder) पर चले जाना चाहिए"],"explanation":"RS 32:71 बाईं लेन का उपयोग करके किसी ओवरटेक करने वाले वाहन को बाधित या अवरुद्ध करने पर रोक लगाता है; धीमे वाहन को शीघ्रता से दाईं लेन में विलीन हो जाना चाहिए। पहले अपराध का जुर्माना $150 है। स्रोत: Louisiana RS 32:71।"},"68":{"q":"जब कोई लुइसियाना CMV एकतरफ़ा या विभाजित राजमार्ग के किनारे (shoulder) पर रुका हो, तो तीनों आपातकालीन चेतावनी उपकरण (त्रिकोण) कहाँ रखे जाने चाहिए?","options":["आने वाले ट्रैफ़िक की ओर 10 फ़ीट, 100 फ़ीट और 200 फ़ीट","आने वाले ट्रैफ़िक की ओर 10 फ़ीट, 50 फ़ीट और 150 फ़ीट","आने वाले ट्रैफ़िक की ओर 25 फ़ीट, 100 फ़ीट और 250 फ़ीट","आने वाले ट्रैफ़िक की ओर 15 फ़ीट, 75 फ़ीट और 200 फ़ीट"],"explanation":"Louisiana CDL Manual (संघीय नियम को अपनाते हुए) के अनुसार किसी एकतरफ़ा या विभाजित राजमार्ग पर या उसके किनारे रुकने पर आने वाले ट्रैफ़िक की ओर 10 फ़ीट, 100 फ़ीट और 200 फ़ीट पर चेतावनी उपकरण रखना आवश्यक है। स्रोत: Louisiana CDL Manual, Sec. 2.5 (Warning Devices)।"},"69":{"q":"लुइसियाना में किसी सड़कमार्ग या किनारे (shoulder) पर CMV रोकने के बाद, चालक को कितने मिनट के भीतर आपातकालीन चेतावनी उपकरण लगाने चाहिए?","options":["5 मिनट","10 मिनट","15 मिनट","30 मिनट"],"explanation":"Louisiana CDL Manual कहता है कि यदि आपको किसी सड़क या किनारे पर रुकना पड़े तो आपको 10 मिनट के भीतर अपने आपातकालीन चेतावनी उपकरण लगाने चाहिए। स्रोत: Louisiana CDL Manual, Sec. 2.5 (Warning Devices)।"},"70":{"q":"लुइसियाना की दो-लेन सड़क पर जो दोनों दिशाओं में ट्रैफ़िक ले जाती है, किसी रुके हुए CMV को वाहन के आगे और पीछे अपने चेतावनी त्रिकोण कहाँ रखने चाहिए?","options":["200 फ़ीट आगे और 200 फ़ीट पीछे","100 फ़ीट आगे और 100 फ़ीट पीछे","50 फ़ीट आगे और 100 फ़ीट पीछे","10 फ़ीट आगे और 10 फ़ीट पीछे"],"explanation":"किसी दो-तरफ़ा/अविभाजित सड़क पर Louisiana CDL Manual के अनुसार वाहन के 10 फ़ीट के भीतर एक उपकरण और उसके 100 फ़ीट आगे तथा 100 फ़ीट पीछे उपकरण रखना आवश्यक है। स्रोत: Louisiana CDL Manual, Sec. 2.5 (Warning Devices)।"},"71":{"q":"एक लुइसियाना स्कूल बस किसी रेलरोड क्रॉसिंग के पास पहुँचती है। CDL Manual क्रॉसिंग से लगभग कितनी दूरी पहले बस की ख़तरा चेतावनी रोशनी चालू करने की सलाह देता है?","options":["50 फ़ीट","100 फ़ीट","200 फ़ीट","500 फ़ीट"],"explanation":"Louisiana CDL Manual की स्कूल-बस प्रक्रियाएँ क्रॉसिंग से लगभग 200 फ़ीट पहले ख़तरा रोशनी चालू करने की सलाह देती हैं, फिर निकटतम रेल से 15 से 50 फ़ीट पर रुकने की। स्रोत: Louisiana CDL Manual, Sec. 10.4.3 (Recommended Procedures)।"},"72":{"q":"एक लुइसियाना बस ऐसे ड्रॉब्रिज पर पहुँचती है जिसमें कोई संकेत रोशनी नहीं और कोई ट्रैफ़िक-नियंत्रण परिचारक नहीं है। चालक को पुल के draw से कम से कम कितनी दूर पहले रुकना चाहिए?","options":["15 फ़ीट","30 फ़ीट","50 फ़ीट","100 फ़ीट"],"explanation":"Louisiana CDL Manual के अनुसार ऐसे ड्रॉब्रिज के draw से कम से कम 50 फ़ीट पहले रुकना आवश्यक है जिसमें कोई संकेत रोशनी या ट्रैफ़िक-नियंत्रण परिचारक नहीं है, और पार करने से पहले यह पुष्टि करनी चाहिए कि draw पूरी तरह बंद है। स्रोत: Louisiana CDL Manual, Sec. 4.3.6 (Drawbridges)।"},"73":{"q":"यदि कोई लुइसियाना चालक ऐसे CMV को चलाते समय रेलरोड-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन करता है जिस पर ख़तरनाक पदार्थों के लिए प्लेकार्ड लगा है, तो न्यूनतम CDL अयोग्यता है:","options":["60 दिन","120 दिन","1 वर्ष","3 वर्ष"],"explanation":"Louisiana CDL Manual कहता है कि यदि कोई रेलरोड-क्रॉसिंग उल्लंघन ख़तरनाक पदार्थों के लिए प्लेकार्ड लगे CMV को चलाते समय होता है तो आप अपना CDL कम से कम तीन वर्ष के लिए खो देंगे (बनाम बिना-प्लेकार्ड वाले गंभीर क्रॉसिंग उल्लंघनों के लिए 60/120 दिन)। स्रोत: Louisiana CDL Manual, Sec. 1.2.5 (Railroad-highway Grade Crossing Violations)।"},"74":{"q":"Louisiana DOTD से ओवरसाइज़ परमिट के बिना, लुइसियाना राजमार्गों पर किसी वाणिज्यिक वाहन और भार के लिए अधिकतम क़ानूनी चौड़ाई (WIDTH) क्या है?","options":["8 फ़ीट 0 इंच","8 फ़ीट 6 इंच","9 फ़ीट 0 इंच","10 फ़ीट 0 इंच"],"explanation":"लुइसियाना की क़ानूनी आकार सीमाएँ 8 फ़ीट 6 इंच चौड़ी, 13 फ़ीट 6 इंच ऊँची और 80,000 पाउंड हैं; इनसे अधिक भार के लिए DOTD ओवरसाइज़/ओवरवेट परमिट आवश्यक है, और अनुमत आवाजाही आम तौर पर सूर्योदय से सूर्यास्त तक सीमित होती है। स्रोत: Louisiana DOTD Weights & Standards; LAC Title 73, Part I, Chapter 3।"},"75":{"q":"लुइसियाना में वाणिज्यिक चालक लाइसेंस (CDL) कौन-सी एजेंसी जारी करती है?","options":["Louisiana Office of Motor Vehicles (OMV)","Louisiana State Police","Federal Motor Carrier Safety Administration (FMCSA)","Louisiana Department of Transportation and Development (DOTD)"],"explanation":"लुइसियाना में CDL, Office of Motor Vehicles (OMV) द्वारा जारी किए जाते हैं, जो Louisiana Department of Public Safety का हिस्सा है। FMCSA संघीय मानक तय करता है लेकिन लाइसेंस जारी नहीं करता; DOTD सड़कों और ओवरसाइज़/ओवरवेट परमिट का काम संभालता है, CDL का नहीं। स्रोत: Louisiana OMV CDL पृष्ठ (expresslane.la.gov)।"},"76":{"q":"लाइसेंस प्राप्त करने से पहले, हर लुइसियाना CDL आवेदक को सबसे पहले कौन-सा प्रमाणपत्र प्राप्त करना चाहिए?","options":["एक Commercial Learner's Permit (CLP)","एक संघीय इंटरस्टेट संचालन प्राधिकरण संख्या","एक DOTD ओवरसाइज़/ओवरवेट परमिट","एक अस्थायी शोफ़र समर्थन (endorsement)"],"explanation":"लुइसियाना में CDL कौशल परीक्षा देने और लाइसेंस प्राप्त करने से पहले आपके पास Commercial Learner's Permit (CLP) होना चाहिए। CLP आपको किसी CDL धारक के साथ रहते हुए सार्वजनिक सड़कों पर अभ्यास करने देता है। स्रोत: Louisiana OMV 'New CDL' पृष्ठ।"},"77":{"q":"लुइसियाना CLP धारक को परमिट पहली बार जारी होने के बाद CDL कौशल परीक्षा देने के लिए पात्र होने से पहले कितने समय तक प्रतीक्षा करनी चाहिए?","options":["14 दिन","30 दिन","10 दिन","60 दिन"],"explanation":"लुइसियाना संघीय 14-दिन की प्रतीक्षा लागू करता है: CLP धारक CLP के प्रारंभिक जारी होने के बाद पहले 14 दिनों के दौरान CDL कौशल परीक्षा देने के लिए पात्र नहीं है। स्रोत: Louisiana OMV 'New CDL' पृष्ठ (49 CFR 383.25)।"},"78":{"q":"लुइसियाना CLP की प्रारंभिक अवधि और अनुमत विस्तार को मिलाकर, यह अधिकतम कितनी अवधि तक वैध रह सकता है?","options":["360 दिन (180 दिन और एक 180-दिन का विस्तार)","180 दिन, बिना किसी विस्तार के","1 वर्ष (365 दिन)","90 दिन और एक 90-दिन का विस्तार"],"explanation":"लुइसियाना CLP अधिकतम 180 दिनों के लिए जारी किया जाता है और इसे एक बार अतिरिक्त 180 दिनों के लिए बढ़ाया जा सकता है, अधिकतम 360 दिनों के लिए। स्रोत: Louisiana OMV 'New CDL' पृष्ठ (49 CFR 383.25)।"},"79":{"q":"किस प्रकार के व्यापार में वे संचालन करेंगे, इसके संबंध में एक लुइसियाना CDL/CLP आवेदक को कितनी अलग-अलग स्व-प्रमाणन श्रेणियों में से चुनना होगा?","options":["चार","दो","तीन","पाँच"],"explanation":"चार स्व-प्रमाणन श्रेणियाँ हैं: Non-Excepted Interstate (NI), Excepted Interstate (EI), Non-Excepted Intrastate (NA), और Excepted Intrastate (EA)। स्रोत: Louisiana OMV CDL स्व-प्रमाणन सामग्री (49 CFR 383.71)।"},"80":{"q":"किन दो स्व-प्रमाणन श्रेणियों के लिए एक लुइसियाना CDL धारक को फ़ाइल पर Medical Examiner's Certificate रखना और बनाए रखना आवश्यक है?","options":["Non-Excepted Interstate और Non-Excepted Intrastate","Excepted Interstate और Excepted Intrastate","Non-Excepted Interstate और Excepted Interstate","Excepted Intrastate और Non-Excepted Intrastate"],"explanation":"जो चालक Non-Excepted Interstate (NI) या Non-Excepted Intrastate (NA) के रूप में स्व-प्रमाणित करते हैं, उन्हें चिकित्सा योग्यता मानकों को पूरा करना चाहिए और एक वर्तमान Medical Examiner's Certificate फ़ाइल पर रखना चाहिए। 'excepted' श्रेणियों (EI, EA) के लिए यह आवश्यक नहीं है। स्रोत: Louisiana OMV स्व-प्रमाणन सामग्री (49 CFR 383.71)।"},"81":{"q":"जो चालक केवल लुइसियाना के भीतर किराए पर माल ढोता है और जिसे चिकित्सा मानकों को पूरा करना होता है, उसे किस श्रेणी के तहत स्व-प्रमाणित करना चाहिए?","options":["Non-Excepted Intrastate (NA)","Non-Excepted Interstate (NI)","Excepted Interstate (EI)","Excepted Intrastate (EA)"],"explanation":"केवल लुइसियाना के भीतर वाणिज्यिक रूप से संचालन ('intrastate') करना और चिकित्सा योग्यता मानकों के अधीन होना Non-Excepted Intrastate (NA) श्रेणी है। इंटरस्टेट श्रेणियाँ राज्य की सीमाएँ पार करने पर लागू होती हैं। स्रोत: Louisiana OMV स्व-प्रमाणन परिभाषाएँ (49 CFR 383.71)।"},"82":{"q":"गैर-छूट प्राप्त (non-excepted) के रूप में स्व-प्रमाणित करने वाले एक लुइसियाना CDL आवेदक को चिकित्सा योग्यता के प्रमाण के रूप में कौन-सा चिकित्सा फ़ॉर्म जमा करना चाहिए?","options":["Medical Examiner's Certificate (फ़ॉर्म MCSA-5876)","एक DOTD ओवरसाइज़/ओवरवेट चिकित्सा छूट (waiver)","CDL Supplemental Form (DPSMV2211)","एक Louisiana State Police फ़िटनेस हलफ़नामा"],"explanation":"गैर-छूट प्राप्त CDL आवेदकों को किसी प्रमाणित परीक्षक द्वारा पूर्ण किया गया वर्तमान Medical Examiner's Certificate (फ़ॉर्म MCSA-5876) जमा करना चाहिए। DPSMV2211 CDL अनुपूरक आवेदन फ़ॉर्म है, चिकित्सा प्रमाणपत्र नहीं। स्रोत: Louisiana OMV 'New CDL' / 'Submit CDL Medical Certificate' पृष्ठ।"},"83":{"q":"लुइसियाना CDL Medical Examiner's Certificate के आधार बनी शारीरिक जाँच करने के लिए कौन अधिकृत है?","options":["FMCSA National Registry of Certified Medical Examiners में सूचीबद्ध एक चिकित्सा परीक्षक","चालक द्वारा चुना गया कोई भी लाइसेंस प्राप्त चिकित्सक","Louisiana OMV द्वारा नियोजित एक चिकित्सक","रजिस्ट्री स्थिति की परवाह किए बिना कोई भी लाइसेंस प्राप्त नर्स प्रैक्टिशनर"],"explanation":"शारीरिक जाँच FMCSA National Registry of Certified Medical Examiners में प्रमाणित और सूचीबद्ध किसी चिकित्सा परीक्षक द्वारा की जानी चाहिए। स्रोत: Louisiana OMV 'New CDL' / CDL चिकित्सा प्रमाणपत्र सूचना पृष्ठ।"},"84":{"q":"निम्नलिखित में से किन तरीक़ों से Louisiana OMV एक CDL Medical Examiner's Certificate स्वीकार करता है?","options":["OMV को ईमेल, फ़ैक्स या मानक डाक द्वारा","केवल किसी OMV फ़ील्ड कार्यालय में व्यक्तिगत रूप से उपस्थित होकर","केवल परीक्षक द्वारा इसे FMCSA पर अपलोड करने के माध्यम से","केवल नोटरीकृत कवर शीट के साथ प्रमाणित डाक द्वारा"],"explanation":"Louisiana OMV, Medical Examiner's Certificate को ईमेल (OMV_CDL_Medical@dps.la.gov), फ़ैक्स या मानक डाक द्वारा स्वीकार करता है। स्रोत: Louisiana OMV 'Submit CDL Medical Certificate' पृष्ठ।"},"85":{"q":"किसी CDL धारक के चिकित्सा प्रमाणपत्र की समाप्ति से कितना पहले Louisiana OMV एक नई चिकित्सा जाँच का अनुरोध करते हुए सूचना भेजता है?","options":["समाप्ति से 60 दिन पहले","समाप्ति से 30 दिन पहले","समाप्ति से 90 दिन पहले","समाप्ति से 10 दिन पहले"],"explanation":"Louisiana OMV, फ़ाइल पर मौजूद चिकित्सा प्रमाणपत्र की समाप्ति से 60 दिन पहले ग्राहक को एक नया जाँच फ़ॉर्म और प्रमाणपत्र माँगते हुए सूचना उत्पन्न करता है। स्रोत: Louisiana OMV CDL चिकित्सा प्रमाणपत्र सूचना पृष्ठ।"},"86":{"q":"यदि कोई लुइसियाना CDL धारक नया चिकित्सा प्रमाणपत्र जमा नहीं करता, तो चालक को कब 'medically not certified' चिह्नित किया जाता है?","options":["फ़ाइल पर मौजूद चिकित्सा प्रमाणपत्र की समाप्ति के 10 दिन बाद","समाप्ति तिथि पर तुरंत","प्रमाणपत्र की समाप्ति के 60 दिन बाद","प्रमाणपत्र की समाप्ति के 30 दिन बाद"],"explanation":"स्व-प्रमाणन/चिकित्सा आवश्यकताओं को पूरा करने में विफलता के परिणामस्वरूप चालक को फ़ाइल पर मौजूद चिकित्सा प्रमाणपत्र की समाप्ति के 10 दिन बाद 'medically not certified' चिह्नित किया जाता है; यदि अनुपालन न करना जारी रहता है तो बाद में CDL रद्द कर दिया जाता है। स्रोत: Louisiana OMV CDL चिकित्सा प्रमाणपत्र सूचना पृष्ठ।"},"87":{"q":"लुइसियाना CDL कौशल परीक्षा किन तीन भागों से बनी है, जो क्रम में किए जाते हैं?","options":["Pre-trip निरीक्षण, बुनियादी वाहन नियंत्रण, और सड़क पर ड्राइविंग","लिखित ज्ञान, दृष्टि जाँच, और सड़क पर ड्राइविंग","Pre-trip निरीक्षण, hazmat संचालन, और एयर-ब्रेक bleed-down","बुनियादी वाहन नियंत्रण, लॉग-बुक ऑडिट, और सड़क पर ड्राइविंग"],"explanation":"लुइसियाना में CDL कौशल परीक्षा के तीन भाग हैं: pre-trip निरीक्षण, बुनियादी वाहन नियंत्रण परीक्षा, और सड़क पर ड्राइविंग परीक्षा। स्रोत: Louisiana CDL manual / Louisiana OMV CDL पृष्ठ (49 CFR 383.113)।"},"88":{"q":"पहली Class A या Class B लाइसेंस के लिए CDL कौशल परीक्षा देने से पहले एक लुइसियाना आवेदक को कौन-सा प्रशिक्षण पूरा करना चाहिए?","options":["किसी FMCSA-पंजीकृत प्रदाता से Entry-Level Driver Training (ELDT)","एक Louisiana OMV रक्षात्मक-ड्राइविंग पाठ्यक्रम","एक DOTD ओवरसाइज़-लोड संचालन पाठ्यक्रम","एक राज्य-संचालित वज़न-स्टेशन निरीक्षण सेमिनार"],"explanation":"FMCSA की Training Provider Registry में सूचीबद्ध किसी स्कूल द्वारा प्रदान किया गया Entry-Level Driver Training (ELDT), प्रारंभिक CDL के लिए कौशल परीक्षा देने से पहले (और hazmat ज्ञान परीक्षा से पहले) पूरा किया जाना चाहिए। स्रोत: Louisiana OMV 'New CDL' पृष्ठ (49 CFR Part 380 Subpart F)।"},"89":{"q":"परीक्षा से पहले, Commercial Learner's Permit के लिए योग्य होने हेतु एक लुइसियाना CDL आवेदक को कौन-सी पहली परीक्षा उत्तीर्ण करनी चाहिए?","options":["सामान्य ज्ञान लिखित (ज्ञान) परीक्षा","सड़क पर ड्राइविंग कौशल परीक्षा","बुनियादी वाहन नियंत्रण परीक्षा","Pre-trip निरीक्षण परीक्षा"],"explanation":"CLP जारी होने के लिए आवेदकों को आवश्यक लिखित ज्ञान परीक्षाएँ उत्तीर्ण करनी चाहिए, जिसकी शुरुआत सामान्य ज्ञान परीक्षा से होती है; कौशल परीक्षाएँ बाद में, CLP रखने के बाद होती हैं। स्रोत: Louisiana CDL manual / OMV CDL पृष्ठ।"},"90":{"q":"50 प्रश्नों की लुइसियाना CDL सामान्य ज्ञान लिखित परीक्षा में उत्तीर्ण होने के लिए न्यूनतम कितना स्कोर आवश्यक है?","options":["80% (50 में से 40 सही)","70% (50 में से 35 सही)","75% (50 में से 38 सही)","90% (50 में से 45 सही)"],"explanation":"सामान्य ज्ञान परीक्षा में 50 बहुविकल्पीय प्रश्न होते हैं, और उत्तीर्ण होने के लिए 80% (50 में से 40) का स्कोर आवश्यक है, जो संघीय CDL मानक के अनुरूप है। स्रोत: Louisiana CDL manual / OMV परीक्षण सामग्री (49 CFR 383.135)।"},"91":{"q":"intrastate (राज्य के भीतर) संचालन तक सीमित लुइसियाना CDL प्राप्त करने के लिए न्यूनतम आयु क्या है?","options":["18 वर्ष","21 वर्ष","19 वर्ष","16 वर्ष"],"explanation":"intrastate संचालन तक सीमित लुइसियाना CDL रखने के लिए आवेदक की आयु कम से कम 18 वर्ष होनी चाहिए; इंटरस्टेट ड्राइविंग और ख़तरनाक-पदार्थ परिवहन के लिए 21 वर्ष आवश्यक है। स्रोत: Louisiana OMV CDL पृष्ठ (49 CFR 383.3 / 391.11)।"},"92":{"q":"पहचान और चिकित्सा प्रमाणपत्र के अलावा, एक लुइसियाना CDL आवेदक को आवेदन के समय कौन-सा दस्तावेज़ प्रदान करना चाहिए?","options":["लुइसियाना निवास का प्रमाण (जैसे उपयोगिता विवरण या पट्टा)","एक नोटरीकृत नियोक्ता प्रायोजन पत्र","इच्छित माल के लिए एक DOTD मार्ग सर्वेक्षण","वाहक के USDOT संचालन प्राधिकरण की एक प्रति"],"explanation":"लुइसियाना में CDL Supplemental Form (DPSMV2211) और Medical Examiner's Certificate के साथ-साथ लुइसियाना निवास का प्रमाण (जैसे उपयोगिता विवरण, पट्टा, मतदाता पंजीकरण) आवश्यक है। स्रोत: Louisiana OMV 'New CDL' पृष्ठ।"},"93":{"q":"एक लुइसियाना CDL को नवीनीकृत किए जाने से पहले सामान्यतः कितने वर्षों तक वैध रहता है?","options":["6 वर्ष","4 वर्ष","8 वर्ष","5 वर्ष"],"explanation":"एक लुइसियाना CDL आम तौर पर 6 वर्षों के लिए वैध होता है। संचालन प्रकार का स्व-प्रमाणन और एक वर्तमान चिकित्सा प्रमाणपत्र (गैर-छूट प्राप्त चालकों के लिए) पूरे समय बनाए रखना चाहिए। स्रोत: Louisiana OMV CDL नवीनीकरण सूचना।"},"94":{"q":"किसी तृतीय-पक्ष परीक्षक द्वारा संचालित लुइसियाना CDL कौशल परीक्षा के शुल्क के संबंध में, कौन-सा कथन सबसे सटीक प्रक्रिया विवरण है?","options":["कौशल परीक्षण अनुमोदित तृतीय-पक्ष परीक्षकों के माध्यम से किया जा सकता है, और सटीक शुल्क परीक्षक द्वारा तय किया जाता है तथा बदल सकता है, इसलिए आवेदकों को वर्तमान राशि की पुष्टि करनी चाहिए","किसी भी OMV कार्यालय में लिए जाने पर कौशल परीक्षा हमेशा निःशुल्क होती है","कौशल परीक्षा शुल्क संघीय क़ानून द्वारा निश्चित है और हर राज्य में समान है","यदि आवेदक अपना वाहन लाता है तो कभी भी कोई कौशल परीक्षा शुल्क नहीं लिया जा सकता"],"explanation":"लुइसियाना कौशल परीक्षा को अनुमोदित तृतीय-पक्ष परीक्षकों द्वारा संचालित करने की अनुमति देता है, और शुल्क परीक्षक द्वारा तय किया जाता है तथा बदलने के अधीन है, इसलिए आवेदकों को किसी निश्चित आँकड़े पर भरोसा करने के बजाय वर्तमान राशि की पुष्टि करनी चाहिए। स्रोत: Louisiana OMV CDL पृष्ठ (तृतीय-पक्ष परीक्षण कार्यक्रम)।"}},"ar":{"0":{"q":"على الطرق السريعة في لويزيانا، ما هو الحد الأقصى القانوني لعرض المركبة التجارية، باستثناء أجهزة السلامة؟","options":["96 inches","98 inches","102 inches","108 inches"],"explanation":"تحدد المادة Louisiana RS 32:380 الحد الأقصى لعرض المركبة بـ 102 inches (8 feet 6 inches)، باستثناء أجهزة السلامة مثل المرايا. المصدر: Louisiana Revised Statutes 32:380."},"1":{"q":"ما هو الحد الأقصى القانوني لارتفاع المركبة في لويزيانا على الطرق السريعة غير التابعة لنظام الطرق السريعة بين الولايات (Interstate)؟","options":["13 feet","13 feet 6 inches","14 feet","14 feet 6 inches"],"explanation":"بموجب المادة Louisiana RS 32:381، لا يجوز أن يتجاوز ارتفاع المركبة وحمولتها 13 feet 6 inches على الطرق السريعة غير التابعة لنظام Interstate. المصدر: Louisiana Revised Statutes 32:381."},"2":{"q":"ما هو الحد الأقصى القانوني لارتفاع المركبة في لويزيانا بالنسبة لمركبة تعمل حصرياً على نظام الطرق السريعة بين الولايات (Interstate)؟","options":["13 feet 6 inches","14 feet","14 feet 6 inches","15 feet"],"explanation":"تسمح المادة Louisiana RS 32:381 بحد أقصى للارتفاع يبلغ 14 feet للمركبة وحمولتها التي تعمل حصرياً على نظام الطرق السريعة بين الولايات (Interstate)، مقارنةً بـ 13 feet 6 inches في الأماكن الأخرى. المصدر: Louisiana Revised Statutes 32:381."},"3":{"q":"في لويزيانا، ما هو الحد الأقصى القانوني لطول المركبة المفردة (مثل شاحنة مستقيمة أو حافلة)؟","options":["40 feet","45 feet","53 feet","59 feet 6 inches"],"explanation":"تحدد المادة Louisiana RS 32:382 الطول الأقصى للمركبة المفردة بـ 45 feet. المصدر: Louisiana Revised Statutes 32:382."},"4":{"q":"ما هو الحد الأقصى القانوني لطول جزء نصف المقطورة من تركيبة الجرار ونصف المقطورة في لويزيانا؟","options":["48 feet","53 feet","57 feet","59 feet 6 inches"],"explanation":"تسمح المادة Louisiana RS 32:382 بأن يصل طول جزء نصف المقطورة من تركيبة الجرار ونصف المقطورة إلى 59 feet 6 inches؛ ولا يوجد حد منفصل للطول الإجمالي للتركيبة بالنسبة لهذا التكوين. المصدر: Louisiana Revised Statutes 32:382."},"5":{"q":"إلى أي مدى يجوز أن تبرز الحمولة خارج عرض هيكلها على مركبة في لويزيانا؟","options":["Not more than 6 inches","Not more than 12 inches","Not more than 18 inches","Not more than 24 inches"],"explanation":"تنص المادة Louisiana RS 32:380 على أنه لا يجوز أن تبرز الحمولة أكثر من 12 inches خارج عرض هيكل المركبة. المصدر: Louisiana Revised Statutes 32:380."},"6":{"q":"ما هو الحد الأقصى للوزن الإجمالي المسموح به لأي مركبة أو تركيبة من المركبات على الطرق السريعة في لويزيانا دون تصريح؟","options":["73,280 pounds","80,000 pounds","88,000 pounds","90,000 pounds"],"explanation":"تحدد المادة Louisiana RS 32:386 الوزن الإجمالي الكلي لأي مركبة أو تركيبة من المركبات بـ 80,000 pounds. المصدر: Louisiana Revised Statutes 32:386."},"7":{"q":"في لويزيانا، ما هو الحد الأقصى للوزن الإجمالي المسموح به على محور مفرد مزود بإطارات هوائية منخفضة الضغط؟","options":["18,000 pounds","20,000 pounds","22,400 pounds","34,000 pounds"],"explanation":"تحدد المادة Louisiana RS 32:386 وزن المحور المفرد المزود بإطارات هوائية منخفضة الضغط بـ 20,000 pounds. المصدر: Louisiana Revised Statutes 32:386."},"8":{"q":"ما هو الحد الأقصى للوزن الإجمالي المسموح به على محور مزدوج (tandem) في لويزيانا بموجب الحد القانوني العام؟","options":["32,000 pounds","34,000 pounds","37,000 pounds","40,000 pounds"],"explanation":"تحدد المادة Louisiana RS 32:386 وزن المحور المزدوج (tandem) المزود بإطارات هوائية منخفضة الضغط بـ 34,000 pounds. المصدر: Louisiana Revised Statutes 32:386."},"9":{"q":"توفر لويزيانا حداً أعلى للوزن المسموح به على المحور المزدوج (tandem) للمركبات التي تنقل المنتجات الحرجية في حالتها الطبيعية. ما هو ذلك الحد، وأين لا ينطبق؟","options":["37,000 pounds, except on the Interstate system","37,000 pounds, including the Interstate system","40,000 pounds, except on the Interstate system","34,000 pounds, applies everywhere"],"explanation":"تسمح المادة Louisiana RS 32:386 بوزن 37,000 pounds لكل محور مزدوج (tandem) للمركبات التي تنقل المنتجات الحرجية في حالتها الطبيعية، باستثناء نظام Interstate، حيث ينطبق الحد القياسي البالغ 34,000-pound. المصدر: Louisiana Revised Statutes 32:386."},"10":{"q":"بموجب المادة Louisiana RS 32:386، لا يجوز لأي إطار على أي محور أن يفرض على سطح الطريق السريع وزناً أكبر من أي مقدار لكل إنش من عرض الإطار؟","options":["500 pounds per inch","600 pounds per inch","650 pounds per inch","700 pounds per inch"],"explanation":"تنص المادة Louisiana RS 32:386 على أنه لا يجوز لأي إطار أن يفرض على سطح الطريق السريع وزناً أكبر من 650 pounds per inch من عرض الإطار. المصدر: Louisiana Revised Statutes 32:386."},"11":{"q":"ما هي الصيغة التي تطبقها لويزيانا على نظام Interstate لتحديد الحد الأقصى المسموح به للوزن الإجمالي على أي مجموعة من محورين متتاليين أو أكثر؟","options":["The Federal Bridge Formula W = 500(LN/(N-1) + 12N + 36)","A flat 80,000-pound limit regardless of axle spacing","The single-axle 20,000-pound rule multiplied by axle count","A weight equal to 650 pounds times the wheelbase in inches"],"explanation":"تعتمد المادة Louisiana RS 32:386 صيغة الجسر الفيدرالية، W = 500(LN/(N-1) + 12N + 36)، لتحديد سقف الوزن على المحاور المتتالية على نظام Interstate، حيث L هي المسافة بين المحاور بالأقدام و N هو عدد المحاور. المصدر: Louisiana Revised Statutes 32:386 (Federal Bridge Formula)."},"12":{"q":"في صيغة الجسر الفيدرالية المستخدمة في لويزيانا، W = 500(LN/(N-1) + 12N + 36)، ماذا يمثل المتغيران L و N؟","options":["L is the load in tons; N is the number of tires","L is the distance in feet between the outer axles of a group; N is the number of axles in that group","L is the legal speed; N is the axle weight","L is the lane width; N is the number of trailers"],"explanation":"في صيغة الجسر الفيدرالية كما تطبقها المادة Louisiana RS 32:386، L هي المسافة بالأقدام بين المحورين الطرفيين (الخارجيين) لأي مجموعة، و N هو عدد المحاور في تلك المجموعة. المصدر: Louisiana Revised Statutes 32:386 / Federal Bridge Formula."},"13":{"q":"يجب على ناقل بري في لويزيانا الحصول على تصريح الحجم الزائد/الوزن الزائد عندما تتجاوز المركبة أو الحمولة الحدود القانونية. ما هي الجهة التي تصدر هذه التصاريح؟","options":["The Louisiana Office of Motor Vehicles (OMV)","The Louisiana Department of Transportation and Development (DOTD)","The Louisiana State Police only","The local parish sheriff's office"],"explanation":"تصدر تصاريح الحجم الزائد/الوزن الزائد في لويزيانا من قبل Department of Transportation and Development (DOTD) عبر مكتب تصاريح الشاحنات التابع لها ونظام التوجيه الإلكتروني PERBA. المصدر: Louisiana DOTD, Oversize and Overweight Truck Permits; LAC Title 73."},"14":{"q":"متى يجب الحصول على تصريح الحجم الزائد/الوزن الزائد في لويزيانا بالنسبة لعملية النقل؟","options":["Within 24 hours after the move is completed","At any roadside weigh station during the trip","Before the oversize/overweight vehicle or load moves within or enters Louisiana","Only after a citation is issued"],"explanation":"يجب التقدم بطلب الحصول على التصريح والحصول عليه قبل أن تتحرك المركبة أو الحمولة ذات الحجم الزائد/الوزن الزائد داخل ولاية لويزيانا أو تدخل إليها. المصدر: Louisiana DOTD oversize/overweight permit rules; LAC Title 73, Part I."},"15":{"q":"تصريح الحجم الزائد/الوزن الزائد السنوي في لويزيانا (مقابل تصريح الرحلة الواحدة) صالح للسفر على أي من الطرق؟","options":["Interstate highways only","Non-Interstate highways only","All state and Interstate highways","Parish roads only"],"explanation":"التصاريح السنوية في لويزيانا صالحة لمدة سنة واحدة وتسمح بالسفر فقط على الطرق السريعة غير التابعة لنظام Interstate؛ أما التنقلات على نظام Interstate فتتطلب تصريح رحلة واحدة. المصدر: Louisiana DOTD Annual Permits; LAC Title 73, Part I, Chapter 3."},"16":{"q":"ما هو الحد الأدنى لمبلغ السند أو شهادة التأمين الذي تشترطه لويزيانا لتصريح الحجم الزائد/الوزن الزائد لرحلة واحدة؟","options":["$50,000","$100,000","$250,000","$500,000"],"explanation":"تشترط لويزيانا سنداً أو شهادة تأمين بقيمة لا تقل عن $100,000 لتصريح الرحلة الواحدة (و $250,000 للتصريح السنوي). المصدر: Louisiana DOTD oversize/overweight permit requirements."},"17":{"q":"تقدم لويزيانا تصريحاً خاصاً لنقل المنتجات الزراعية في حالتها الطبيعية التي تتجاوز الحدود القانونية لوزن المحور أو الوزن الإجمالي خلال موسم الحصاد. ما هو الاسم الشائع لهذا التصريح؟","options":["A harvest season permit","A trip lease permit","A hazmat tonnage permit","A reciprocity permit"],"explanation":"تصدر Louisiana DOTD تصاريح موسم الحصاد للمركبات التي تنقل المنتجات الزراعية في حالتها الطبيعية والتي تتجاوز الحدود القانونية للوزن الإجمالي أو وزن المحور؛ والرسوم السنوية هي $100. المصدر: Louisiana DOTD Harvest Season / Annual Permits; LAC Title 73, Part I."},"18":{"q":"بموجب متطلبات تصريح نقل قصب السكر في لويزيانا، ما هو تكوين المحاور الذي يجب أن تتوافر عليه تركيبة المركبة والمقطورة؟","options":["A minimum of four axles total","A total of six axles, with an additional load-bearing single axle on the sugarcane trailer","Only a tandem rear axle","A total of eight axles with all lift axles raised"],"explanation":"تتطلب أحكام تصريح حصاد قصب السكر في لويزيانا ما مجموعه six axles لتركيبة المركبة والمقطورة، بما في ذلك محور مفرد إضافي مزود بإطارات مزدوجة على مقطورة قصب السكر يكون منخفضاً ويعمل كمحور حامل للحمولة. المصدر: Louisiana DOTD harvest permit provisions; LAC Title 73, Part I."},"19":{"q":"في لويزيانا، ما هي فئة رخصة القيادة التجارية (Commercial Driver License) المطلوبة لتشغيل تركيبة من المركبات بتصنيف وزن إجمالي مركّب (GCWR) قدره 26,001 pounds أو أكثر، حيث يتجاوز تصنيف الوزن الإجمالي للمركبة (GVWR) للوحدة المقطورة 10,000 pounds؟","options":["Class B","Class A","Class C","Class D"],"explanation":"تعرّف المادة Louisiana R.S. 32:408 B.(2)(a) رخصة CDL من الفئة 'A' (المركبات المركّبة) بأنها تسمح بأي تركيبة من المركبات بتصنيف GCWR قدره 26,001 pounds أو أكثر، شريطة أن يتجاوز تصنيف GVWR للوحدة (الوحدات) المقطورة 10,000 pounds. المصدر: Louisiana CDL Manual (OMV)، قسم الفئات."},"20":{"q":"بموجب قواعد لويزيانا، تخوّل رخصة CDL من الفئة B تشغيل أي مركبة مفردة بتصنيف GVWR قدره 26,001 pounds أو أكثر، مع إمكانية قطر وحدة لا يتجاوز وزنها أي قيمة؟","options":["5,000 pounds GVWR","15,000 pounds GVWR","26,001 pounds GVWR","10,000 pounds GVWR"],"explanation":"تعرّف المادة Louisiana R.S. 32:408 B.(2)(b) رخصة CDL من الفئة 'B' (المركبة المستقيمة الثقيلة) بأنها أي مركبة مفردة بتصنيف GVWR قدره 26,001 pounds أو أكثر، أو مثل هذه المركبة وهي تقطر مركبة لا يتجاوز تصنيف GVWR لها 10,000 pounds. قطر أكثر من 10,000 lbs ينقل السائق إلى الفئة A. المصدر: Louisiana CDL Manual (OMV)."},"21":{"q":"يشغّل سائق في لويزيانا شاحنة مستقيمة مفردة بتصنيف 24,000 pounds GVWR وعليها لافتات للمواد الخطرة. ما هي الفئة الدنيا المطلوبة من رخصة CDL؟","options":["Class B","Class A","Class D","Class C"],"explanation":"تعرّف المادة Louisiana R.S. 32:408 B.(2)(c) رخصة CDL من الفئة 'C' (المركبة الخفيفة) للمركبات المفردة التي يقل تصنيف GVWR لها عن 26,001 pounds والتي إما أنها مصممة لنقل 16 راكباً أو أكثر (بما في ذلك السائق) أو تُستخدم لنقل كميات من المواد الخطرة تتطلب لافتات. تحتاج شاحنة مستقيمة بوزن 24,000-lb تحمل لافتات HazMat إلى الفئة C بالإضافة إلى تظهير H. المصدر: Louisiana CDL Manual (OMV)."},"22":{"q":"على رخصة CDL في لويزيانا، أي رمز تظهير يخوّل تشغيل المقطورات المزدوجة والثلاثية؟","options":["N","X","T","H"],"explanation":"تدرج المادة Louisiana R.S. 32:408(3) تظهير 'T' للمقطورات المزدوجة/الثلاثية. (N = الخزان، H = المواد الخطرة، X = الخزان والمواد الخطرة معاً.) المصدر: Louisiana CDL Manual (OMV)، قسم التظهيرات."},"23":{"q":"ما هو الحد الأدنى للعمر للحصول على رخصة CDL في لويزيانا للقيادة داخل الولاية (INTRASTATE) فقط؟","options":["21 years old","19 years old","17 years old","18 years old"],"explanation":"تدرج المادة Louisiana R.S. 32:408 شرط العمر لرخص CDL من الفئات A و B و C بأنه 18 years أو أكثر للقيادة داخل الولاية و 21 years أو أكثر للقيادة بين الولايات. المصدر: Louisiana CDL Manual (OMV)، قسم الفئات."},"24":{"q":"يحمل شخص عمره 19 عاماً رخصة CDL سارية في لويزيانا. أي عملية يُسمح له بأدائها؟","options":["Drive a CMV in interstate commerce","Transport placarded hazardous materials","Drive a CMV in intrastate commerce within Louisiana","Hold an H (HazMat) endorsement"],"explanation":"تحدد لويزيانا عمر رخصة CDL بـ 18 للقيادة داخل الولاية ولكن 21 للقيادة بين الولايات، ويُصدر تظهير H (المواد الخطرة) 'فقط للأشخاص البالغين 21 عاماً أو أكثر.' يجوز لشخص عمره 19 عاماً القيادة داخل الولاية فقط ولا يمكنه الحصول على تظهير HazMat. المصدر: Louisiana CDL Manual (OMV)، R.S. 32:408."},"25":{"q":"في لويزيانا، لا يجوز إصدار تظهير المواد الخطرة H (Hazardous Materials) إلا لمقدمي الطلبات الذين لا يقل عمرهم عن أي عمر؟","options":["18 years old","25 years old","19 years old","21 years old"],"explanation":"تنص قائمة التظهيرات في Louisiana CDL Manual (R.S. 32:408(3)) على أن تظهير المواد الخطرة 'H' يُصدر 'فقط للأشخاص البالغين 21 عاماً أو أكثر،' بما يتوافق مع الطبيعة الخاصة بالقيادة بين الولايات فقط لنقل المواد الخطرة التي تتطلب لافتات. المصدر: Louisiana CDL Manual (OMV)."},"26":{"q":"قبل إصدار تظهير المواد الخطرة (H) في لويزيانا، يجب على مقدم الطلب اجتياز أي فحص إضافي؟","options":["A vision-only re-examination","A 36-hour classroom defensive-driving course","A road test in a tanker vehicle","A TSA security threat assessment including fingerprinting and a background check"],"explanation":"ينص Louisiana CDL Manual (Section 1.2.6) على أن تظهير المواد الخطرة يتطلب تقديم بصمات الأصابع وإجراء فحص للسجل الجنائي؛ ويُرفض مقدم الطلب إذا اعتُبر تهديداً أمنياً من قِبل Transportation Security Administration (TSA). يجب أن يكون فحص السجل الجنائي عبر بصمات الأصابع قد جرى خلال آخر 180 days. المصدر: Louisiana CDL Manual (OMV)، TSA / 49 CFR 1572."},"27":{"q":"سيُرفض منح تظهير المواد الخطرة في لويزيانا لمقدم الطلب بموجب أي من الحالات التالية؟","options":["They have fewer than two years of CDL experience","They are under 25 years of age","They are not a lawful permanent resident of the United States","They do not hold a Class A CDL"],"explanation":"وفقاً لـ Louisiana CDL Manual Section 1.2.6، سيُرفض منحك تظهير المواد الخطرة أو ستفقده إذا لم تكن مقيماً دائماً قانونياً في الولايات المتحدة، أو تخليت عن الجنسية الأمريكية، أو كنت مطلوباً/قيد الاتهام أو مُداناً بجنايات معينة، أو حُكم عليك بأنك معتل عقلياً، أو اعتُبرت تهديداً أمنياً من قِبل TSA. المصدر: Louisiana CDL Manual (OMV)؛ TSA HME rule."},"28":{"q":"يُطلب تظهير مركبة الخزان (N) في لويزيانا عندما تنقل مركبة تحتاج إلى رخصة CDL من الفئة A أو B سوائل/غازات في خزان شحن مثبّت بشكل دائم بسعة لا تقل عن أي حد أدنى؟","options":["119 gallons or more","100 gallons or more","500 gallons or more","1,000 gallons or more"],"explanation":"ينص Louisiana CDL Manual (Section 8, Tank Vehicles) على أن تظهير الخزان مطلوب إذا كانت مركبتك تحتاج إلى رخصة CDL من الفئة A أو B وكنت تنقل سائلاً أو غازاً في خزان شحن مثبّت بشكل دائم بسعة 119 gallons or more، أو خزان نقّال بسعة 1,000 gallons or more. المصدر: Louisiana CDL Manual (OMV)."},"29":{"q":"بالنسبة لتظهير الخزان (N) في لويزيانا، يستوجب الخزان النقّال (PORTABLE) متطلب التظهير عندما تكون سعته لا تقل عن أي حد أدنى؟","options":["119 gallons or more","1,000 gallons or more","660 gallons or more","2,000 gallons or more"],"explanation":"يحدد Louisiana CDL Manual أن تظهير الخزان ينطبق على خزان نقّال بسعة 1,000 gallons or more (مقابل 119 gallons or more لخزان شحن مثبّت بشكل دائم). المصدر: Louisiana CDL Manual (OMV)، قسم Tank Vehicles."},"30":{"q":"أي رمز تظهير على رخصة CDL في لويزيانا يمثل الجمع بين مركبات الخزان (Tank Vehicles) والمواد الخطرة (Hazardous Materials)؟","options":["T","X","N","H"],"explanation":"تدرج المادة Louisiana R.S. 32:408(3) تظهير 'X' بوصفه الجمع بين مركبات الخزان والمواد الخطرة. (N = الخزان فقط، H = المواد الخطرة فقط، T = المزدوجة/الثلاثية.) المصدر: Louisiana CDL Manual (OMV)، قسم التظهيرات."},"31":{"q":"أي تظهير على رخصة CDL في لويزيانا مطلوب تحديداً لقيادة حافلة مدرسية؟","options":["S","P","T","N"],"explanation":"تدرج المادة Louisiana R.S. 32:408(3) تظهير 'S' للحافلة المدرسية. ويغطي تظهير 'P' (الركاب) الحافلات بشكل عام وهو مطلوب أيضاً، لكن التظهير الخاص بالحافلة المدرسية هو 'S.' المصدر: Louisiana CDL Manual (OMV)، قسم التظهيرات."},"32":{"q":"بموجب المعيار الفيدرالي المطبّق في لويزيانا، بعد إصدار تصريح المتعلم التجاري (CLP) لأول مرة، كم يجب على حامله الانتظار كحد أدنى قبل أن يصبح مؤهلاً لإجراء اختبار مهارات CDL؟","options":["14 days","7 days","30 days","10 days"],"explanation":"وفقاً لـ 49 CFR 383.25(e)، المعتمد في لويزيانا، لا يكون حامل CLP مؤهلاً لإجراء اختبار مهارات CDL خلال أول 14 days بعد الإصدار الأولي لـ CLP. تتيح فترة الانتظار هذه البالغة 14-day وقتاً للتدريب العملي على القيادة. المصدر: 49 CFR 383.25(e)؛ Louisiana OMV CDL requirements."},"33":{"q":"أثناء التدرب على قيادة مركبة تجارية (CMV) بموجب تصريح CLP في لويزيانا، يجب أن يكون حامل التصريح في جميع الأوقات برفقة من؟","options":["Any licensed Class E driver over age 21","A CDL holder with the proper class and endorsements seated in the front seat","A certified third-party examiner only","No supervision is required once the knowledge test is passed"],"explanation":"تشترط قواعد CLP الخاصة بـ Louisiana OMV (وفقاً لـ 49 CFR 383.25) أن يكون حامل CLP برفقة حامل رخصة CDL سارية يمتلك الفئة والتظهيرات المناسبة، جالساً في المقعد الأمامي (المقصورة) للمركبة، أثناء جميع عمليات القيادة العملية. المصدر: Louisiana OMV New CDL page؛ 49 CFR 383.25."},"34":{"q":"بالإضافة إلى مقدمي الطلبات لأول مرة للفئة A والفئة B، يُشترط تدريب ELDT في لويزيانا لمقدمي الطلبات لأول مرة الساعين للحصول على أي من التظهيرات؟","options":["Hazardous Materials (H), Passenger (P), and School Bus (S)","Tank (N) and Doubles/Triples (T) only","Motorcycle (M) and Passenger (P) only","All endorsements without exception"],"explanation":"يغطي تدريب FMCSA ELDT (الساري اعتباراً من Feb 7, 2022، المطبّق في لويزيانا) مقدمي الطلبات لأول مرة للحصول على رخصة CDL من الفئة A أو B، والترقيات من B إلى A، ومقدمي الطلبات لأول مرة لتظهيرات المواد الخطرة (H) والركاب (P) والحافلة المدرسية (S). أما تظهيرا الخزان (N) والمزدوجة/الثلاثية (T) فليسا من التظهيرات المشمولة بـ ELDT. المصدر: FMCSA Training Provider Registry / ELDT Applicability."},"35":{"q":"في لويزيانا، ما هو الحد الأقصى لتركيز الكحول في الدم (BAC) الذي يجوز أن يكون لدى السائق أثناء تشغيل مركبة تجارية (CMV) قبل أن يُعتبر مخموراً قانونياً لأغراض رخصة CDL؟","options":["0.04 percent","0.08 percent","0.02 percent","0.10 percent"],"explanation":"يحدد قانون لويزيانا حد BAC للمركبة التجارية (CMV) بـ 0.04 percent، أي نصف حد 0.08 percent المقرر للسائقين غير التجاريين. يُعتبر حامل رخصة CDL الذي يشغّل مركبة CMV بنسبة 0.04 percent أو أكثر تحت تأثير الكحول. المصدر: La. R.S. 32:414.2 و Louisiana CDL Manual (Section 1.2, Disqualifications)."},"36":{"q":"بمجرد حمل رخصة CDL في لويزيانا وتشغيل مركبة تجارية، يُعتبر السائق تلقائياً قد وافق على فعل ماذا؟","options":["Submit to chemical testing of breath, blood, or urine when lawfully requested","Carry a copy of the federal hours-of-service log at all times","Waive the right to a court hearing on any traffic ticket","Pay all toll fees electronically rather than in cash"],"explanation":"بموجب قانون الموافقة الضمنية في لويزيانا، يُعتبر أي شخص يشغّل مركبة CMV قد وافق على إجراء فحص كيميائي للنفس أو الدم أو البول لتحديد وجود الكحول أو المخدرات عندما يكون لدى الضابط سبب معقول. المصدر: La. R.S. 32:414.2 (implied consent) و Louisiana CDL Manual."},"37":{"q":"كم تبلغ مدة استبعاد حامل رخصة CDL في لويزيانا عن أول مخالفة كبرى، مثل تشغيل مركبة CMV بنسبة BAC قدرها 0.04 percent أو أكثر؟","options":["1 year","60 days","6 months","3 years"],"explanation":"تؤدي أول مخالفة كبرى (بما في ذلك القيادة تحت تأثير الكحول، أو BAC قدره 0.04 percent أو أكثر في مركبة CMV، أو رفض الفحص، أو مغادرة موقع الحادث) إلى استبعاد لمدة 1 year بموجب قانون لويزيانا، وهو ما يطابق 49 CFR 383.51. المصدر: La. R.S. 32:414.2 و Louisiana CDL Manual."},"38":{"q":"إذا ارتكب حامل رخصة CDL في لويزيانا أول مخالفة كبرى أثناء تشغيل مركبة CMV تحمل لافتات للمواد الخطرة، فإن مدة الاستبعاد تزيد إلى:","options":["3 years","1 year","2 years","Lifetime"],"explanation":"عندما تقع أول مخالفة كبرى في مركبة CMV يُشترط أن تحمل لافتات للمواد الخطرة، يُمدّد الاستبعاد من 1 year إلى 3 years. المصدر: La. R.S. 32:414.2 و 49 CFR 383.51، كما هو معتمد في Louisiana CDL Manual."},"39":{"q":"ما هي مدة الاستبعاد لحامل رخصة CDL في لويزيانا الذي يُدان بمخالفة كبرى ثانية (على سبيل المثال، قيادة ثانية تحت تأثير الكحول في مركبة CMV)؟","options":["Lifetime disqualification","10-year disqualification","5-year disqualification","3-year disqualification"],"explanation":"تؤدي الإدانة الثانية بأي مجموعة من المخالفات الكبرى إلى استبعاد رخصة CDL مدى الحياة في لويزيانا، بما يتوافق مع 49 CFR 383.51. (قد يتوفر حد أدنى لإعادة الإصدار بعد 10 سنوات بموجب القواعد الفيدرالية.) المصدر: La. R.S. 32:414.2 و Louisiana CDL Manual."},"40":{"q":"طُلب من حامل رخصة CDL في لويزيانا قانونياً الخضوع لفحص كيميائي فرفض. ما هي العاقبة على رخصة CDL؟","options":["Disqualification for at least 1 year, the same as a DUI conviction","A warning only on the first refusal","Disqualification for 60 days","No CDL consequence if criminal charges are dismissed"],"explanation":"يؤدي رفض الفحص الكيميائي بموجب قانون الموافقة الضمنية في لويزيانا إلى استبعاد رخصة CDL لمدة لا تقل عن 1 year، تماماً كالمخالفة الكبرى، وينطبق ذلك بصرف النظر عن نتيجة أي قضية جنائية. المصدر: La. R.S. 32:414.2 و Louisiana CDL Manual."},"41":{"q":"أي مما يلي يُصنّف بأنه 'مخالفة مرورية خطيرة' (serious traffic violation) لحامل رخصة CDL في لويزيانا؟","options":["Speeding 15 mph or more over the posted limit","Speeding 5 mph over the posted limit","A parking violation in a commercial zone","Driving with an expired registration sticker"],"explanation":"تجاوز السرعة بمقدار 15 mph أو أكثر فوق الحد المعلن هو إحدى المخالفات المرورية الخطيرة المدرجة لحاملي رخص CDL. وتشمل الأخرى القيادة المتهورة، وتغيير المسارات بشكل غير سليم أو متقلب، والاقتراب الشديد من المركبة الأمامية. المصدر: 49 CFR 383.51 كما هو معتمد في Louisiana CDL Manual."},"42":{"q":"كم تبلغ مدة استبعاد حامل رخصة CDL في لويزيانا عند الإدانة بمخالفتين مروريتين خطيرتين خلال فترة 3 سنوات؟","options":["60 days","30 days","120 days","1 year"],"explanation":"تؤدي المخالفة المرورية الخطيرة الثانية خلال 3 سنوات (في حوادث منفصلة) إلى استبعاد لمدة 60 days بموجب قانون لويزيانا، بما يطابق 49 CFR 383.51. المصدر: La. R.S. 32:414.2 و Louisiana CDL Manual."},"43":{"q":"كم تبلغ مدة استبعاد حامل رخصة CDL في لويزيانا عند الإدانة بثلاث مخالفات مرورية خطيرة خلال فترة 3 سنوات؟","options":["120 days","60 days","90 days","180 days"],"explanation":"تؤدي المخالفة المرورية الخطيرة الثالثة خلال 3 سنوات (في حوادث منفصلة) إلى استبعاد لمدة 120 days، تُنفّذ بالتتابع مع أي فترة سابقة قدرها 60 days. المصدر: 49 CFR 383.51 كما هو معتمد في Louisiana CDL Manual و La. R.S. 32:414.2."},"44":{"q":"يُعامَل استخدام هاتف محمول باليد أثناء قيادة مركبة تجارية في لويزيانا على أنه أي نوع من المخالفات لأغراض رخصة CDL؟","options":["A serious traffic violation that counts toward disqualification","A non-moving violation with no CDL impact","An automatic 1-year major offense","A violation only if an accident results"],"explanation":"استخدام هاتف محمول باليد أو إرسال الرسائل النصية أثناء تشغيل مركبة CMV هو مخالفة مرورية خطيرة تُحتسب ضمن عتبات الاستبعاد لمخالفتين خلال 3 سنوات (60 days) وثلاث مخالفات خلال 3 سنوات (120 days). المصدر: 49 CFR 383.51 / 392.82 كما هو معتمد في Louisiana CDL Manual."},"45":{"q":"إرسال الرسائل النصية أثناء قيادة مركبة CMV هو أيضاً مخالفة خطيرة. العقوبة المدنية الفيدرالية التي قد يواجهها سائق مركبة CMV بسبب إرسال الرسائل النصية، كما هو مشار إليه في قواعد CDL المطبّقة في لويزيانا، يمكن أن تصل إلى ما يقارب:","options":["$2,750","$500","$1,000","$10,000"],"explanation":"إلى جانب استبعاد رخصة CDL، يواجه سائق مركبة CMV الذي يرسل رسائل نصية أثناء القيادة عقوبة مدنية فيدرالية تصل إلى نحو $2,750. المصدر: 49 CFR 392.80/392.82، المشار إليه في Louisiana CDL Manual."},"46":{"q":"ما هو الحد الأدنى للاستبعاد لحامل رخصة CDL في لويزيانا عند أول إدانة بمخالفة معبر السكة الحديدية مع الطريق السريع (railroad-highway grade crossing)؟","options":["60 days","30 days","120 days","1 year"],"explanation":"تترتب على أول مخالفة لمعبر السكة الحديدية مع الطريق السريع (مثل عدم التوقف أو عدم وجود مساحة كافية للعبور) مدة استبعاد دنيا قدرها 60 days في لويزيانا. المصدر: 49 CFR 383.51 كما هو معتمد في Louisiana CDL Manual."},"47":{"q":"يرتكب حامل رخصة CDL في لويزيانا مخالفة ثانية لمعبر السكة الحديدية خلال فترة 3 سنوات. الحد الأدنى للاستبعاد هو:","options":["120 days","60 days","90 days","1 year"],"explanation":"تؤدي المخالفة الثانية لمعبر السكة الحديدية خلال 3 سنوات إلى استبعاد بحد أدنى قدره 120 days. المصدر: 49 CFR 383.51 كما هو معتمد في Louisiana CDL Manual."},"48":{"q":"يرتكب حامل رخصة CDL في لويزيانا مخالفة ثالثة لمعبر السكة الحديدية خلال فترة 3 سنوات. الحد الأدنى للاستبعاد هو:","options":["1 year","120 days","180 days","3 years"],"explanation":"تؤدي المخالفة الثالثة لمعبر السكة الحديدية خلال 3 سنوات إلى استبعاد بحد أدنى قدره 1 year. المصدر: 49 CFR 383.51 كما هو معتمد في Louisiana CDL Manual."},"49":{"q":"ما هي مدة الاستبعاد لحامل رخصة CDL في لويزيانا عند أول إدانة بمخالفة أمر إخراج من الخدمة (out-of-service order) أثناء تشغيل مركبة CMV (غير حاملة لمواد خطرة، وغير ناقلة للركاب)؟","options":["At least 180 days, up to 1 year","At least 30 days","At least 60 days","Lifetime"],"explanation":"تؤدي أول مخالفة لأمر الإخراج من الخدمة (OOS) إلى استبعاد لمدة لا تقل عن 180 days وتصل إلى 1 year بالنسبة لمركبة CMV قياسية. المصدر: La. R.S. 32:414.2 و 49 CFR 383.51 كما هو معتمد في Louisiana CDL Manual."},"50":{"q":"يُدان حامل رخصة CDL في لويزيانا بمخالفة ثانية لأمر الإخراج من الخدمة خلال فترة 10 سنوات. نطاق الاستبعاد هو:","options":["2 to 5 years","1 to 2 years","60 to 120 days","Lifetime"],"explanation":"تؤدي المخالفة الثانية لأمر الإخراج من الخدمة خلال 10 سنوات إلى استبعاد لمدة 2 to 5 years بالنسبة لمركبة CMV قياسية. المصدر: La. R.S. 32:414.2 و 49 CFR 383.51 كما هو معتمد في Louisiana CDL Manual."},"51":{"q":"بالنسبة لحامل رخصة CDL الذي ينقل مواد خطرة تتطلب لافتات، فإن أول مخالفة لأمر الإخراج من الخدمة تترتب عليها مدة استبعاد قدرها:","options":["At least 180 days, up to 2 years","At least 30 days, up to 60 days","Exactly 1 year","Lifetime"],"explanation":"عندما تقع مخالفة OOS أثناء نقل مواد خطرة تحمل لافتات أو أثناء تشغيل مركبة مصممة لنقل 16 راكباً أو أكثر، يكون استبعاد المخالفة الأولى لمدة لا تقل عن 180 days وتصل إلى 2 years. المصدر: 49 CFR 383.51 كما هو معتمد في Louisiana CDL Manual."},"52":{"q":"أي مما يلي يصف بشكل أفضل كيفية احتساب لويزيانا للمخالفات المرورية الخطيرة لأغراض استبعاد رخصة CDL؟","options":["Convictions in separate incidents within a 3-year period","Only convictions occurring on the same day","All convictions within a 1-year period only","Only violations committed while off duty"],"explanation":"تستند حالات استبعاد المخالفات المرورية الخطيرة (60 days للمخالفة الثانية، 120 days للمخالفة الثالثة) إلى الإدانات الناشئة عن حوادث منفصلة خلال فترة 3 سنوات. المصدر: 49 CFR 383.51 كما هو معتمد في Louisiana CDL Manual و La. R.S. 32:414.2."},"53":{"q":"يتسبب سائق في حالة وفاة أثناء تشغيل مركبة CMV ويُدان بمخالفة مرورية (مثل التشغيل بإهمال أو تهور) مرتبطة بالوفاة. لأغراض رخصة CDL في لويزيانا، يُعامَل هذا على أنه:","options":["A serious traffic violation counting toward disqualification","A non-CDL administrative matter only","An automatic lifetime disqualification","A railroad-crossing violation"],"explanation":"تُدرَج مخالفة قانون التحكم المروري المرتكبة فيما يتصل بحادث مميت ضمن قائمة المخالفات المرورية الخطيرة، وتُحتسب ضمن عتبتي 60 days و 120 days. (أما القتل غير العمد أو ارتكاب جناية بمركبة CMV فهو مخالفة كبرى منفصلة مدتها 1 year.) المصدر: 49 CFR 383.51 كما هو معتمد في Louisiana CDL Manual."},"54":{"q":"يستخدم حامل رخصة CDL في لويزيانا مركبة CMV لارتكاب جناية تتعلق بتصنيع أو توزيع مادة خاضعة للرقابة. الاستبعاد هو:","options":["Lifetime, with no reinstatement available","1 year","3 years","60 days"],"explanation":"يؤدي استخدام مركبة CMV في ارتكاب جناية تتعلق بتصنيع أو توزيع أو صرف مادة خاضعة للرقابة إلى استبعاد مدى الحياة دون أي إمكانية لإعادة الإصدار، على خلاف المخالفات الكبرى الأخرى. المصدر: La. R.S. 32:414.2 و 49 CFR 383.51 كما هو معتمد في Louisiana CDL Manual."},"55":{"q":"على طريق سريع بين الولايات أو طريق ذي وصول محدود في لويزيانا، ما هو الحد الأقصى لسرعة القيادة المعلن المحدد بموجب القانون (ما لم يُعلن عن حد مختلف)؟","options":["60 mph","65 mph","70 mph","75 mph"],"explanation":"تحدد المادة Louisiana RS 32:61 الحد الأقصى القانوني عند 70 mph على الطرق السريعة بين الولايات أو الطرق ذات الوصول المحدود ما لم يُعلن خلاف ذلك. المصدر: Louisiana RS 32:61؛ كُتيّب 'Speed Limit' الصادر عن Louisiana DOTD."},"56":{"q":"بموجب قانون لويزيانا، ما هو حد السرعة القانوني على طريق سريع مُقَسَّم متعدد الحارات وليس طريقاً بين الولايات، ما لم يُعلن خلاف ذلك؟","options":["55 mph","65 mph","70 mph","60 mph"],"explanation":"تنص المادة RS 32:61 على أن الحد على أي طريق سريع في لويزيانا يجب ألا يتجاوز 55 mph ما لم يكن طريقاً سريعاً مُقَسَّماً متعدد الحارات (65 mph) أو طريقاً سريعاً بين الولايات/ذا وصول محدود (70 mph). المصدر: Louisiana RS 32:61؛ كُتيّب 'Speed Limit' الصادر عن Louisiana DOTD."},"57":{"q":"على طريق سريع بين الولايات في لويزيانا، كيف يُقارن الحد الأقصى لسرعة شاحنة القاطرة-المقطورة بالحد المقرر لسيارة الركاب؟","options":["يجب أن تبقى الشاحنات أدنى من الحد المعلن بمقدار 10 mph","يُحدّد سقف سرعة الشاحنات عند مستوى أقل من السيارات بمقدار 5 mph","للشاحنات نفس الحد الأقصى المقرر للسيارات","تُحدّد سرعة الشاحنات بـ 55 mph على مستوى الولاية"],"explanation":"ليس لدى لويزيانا حد سرعة منفصل أدنى للشاحنات على الطرق بين الولايات؛ فقد أُلغيت المادة السابقة الخاصة بسرعة الشاحنات RS 32:62 (Acts 2010, No. 81)، ولم يُسَنّ اقتراح لاحق بفرض حد 'أدنى بمقدار 10 mph'. وتنطبق حدود المادة RS 32:61 على جميع المركبات ما لم يُعلن خلاف ذلك. المصدر: Louisiana RS 32:61؛ RS 32:62 (مُلغاة عام 2010)."},"58":{"q":"يقترب سائق حافلة في لويزيانا من مَعبر سكة حديد يستوجب التوقف. أين يجب أن تتوقف الحافلة بالنسبة لأقرب قضيب سكة؟","options":["بين 5 و25 قدماً","بين 15 و50 قدماً","بين 50 و100 قدم","بين 10 و40 قدماً"],"explanation":"ينص دليل Louisiana CDL على أنه يجب أن تتوقف الحافلة بين 15 و50 قدماً قبل مَعبر سكة الحديد، ثم تنظر وتُنصت في كلا الاتجاهين قبل العبور. المصدر: دليل Louisiana CDL، القسم 4.3.5 (Railroad-highway Crossing Stops)."},"59":{"q":"يصل سائق ينقل مواد خطرة موسومة بلوحات في لويزيانا إلى مَعبر سكة حديد غير مُعفى. على أي مسافة من أقرب قضيب سكة يجب أن تتوقف المركبة؟","options":["ليس أقرب من 15 قدماً وليس أبعد من 50 قدماً","ليس أقرب من 10 أقدام وليس أبعد من 25 قدماً","ليس أقرب من 25 قدماً وليس أبعد من 75 قدماً","بالضبط 50 قدماً، ثم التقدم زحفاً"],"explanation":"يجب على الحافلات والحافلات المدرسية والمركبات الموسومة بلوحات أن توقف المركبة ضمن 50 قدماً ولكن ليس أقل من 15 قدماً من أقرب قضيب سكة، ثم تنظر وتُنصت قبل العبور. المصدر: دليل Louisiana CDL، القسم 13.1.8 (Railroad Crossing procedures)."},"60":{"q":"بموجب المادة Louisiana RS 32:80، يجب على السائق الذي يلتقي أو يتجاوز حافلة مدرسية متوقفة وإشاراتها الضوئية تعمل أن يتوقف على مسافة لا تقل عن أي مسافة من الحافلة؟","options":["10 أقدام","20 قدماً","30 قدماً","50 قدماً"],"explanation":"تستوجب المادة RS 32:80 على السائقين المقتربين من أي اتجاه أن يتوقفوا على مسافة لا تقل عن 30 قدماً من الحافلة المدرسية المتوقفة لتحميل الأطفال أو إنزالهم أثناء تشغيل إشاراتها الضوئية، وأن يبقوا متوقفين حتى تتحرك الحافلة أو تتوقف الإشارات. المصدر: Louisiana RS 32:80."},"61":{"q":"على طريق سريع مُقَسَّم بأربع حارات وذي مسارات منفصلة في لويزيانا، تتوقف حافلة مدرسية على المسار المقابل لإنزال الأطفال. ماذا يجب على السائق المتجه في الاتجاه الآخر أن يفعل؟","options":["أن يتوقف وينتظر حتى تنطفئ الإشارات","أن يتوقف فقط إذا كان الأطفال يعبرون","لا حاجة للتوقف؛ ينطبق استثناء الطريق المُقَسَّم","أن يبطئ إلى 15 mph لكن لا حاجة للتوقف"],"explanation":"تنص المادة RS 32:80 على أنه لا حاجة لأن يتوقف السائق للحافلة المدرسية الموجودة على مسار مختلف من طريق سريع مُقَسَّم ذي مسارات منفصلة (أو طريق ذي وصول محدود تكون فيه الحافلة في منطقة تحميل). المصدر: Louisiana RS 32:80."},"62":{"q":"في لويزيانا، طريق بحارتين بحارة واحدة في كل اتجاه إضافة إلى حارة وسطى لانعطاف يساري ثنائي الاتجاه، عليه حافلة مدرسية متوقفة لتحميل الأطفال. بالنسبة لقانون التوقف للحافلات المدرسية، يُعامَل هذا الطريق على أنه:","options":["طريق مُقَسَّم، لذا لا حاجة لتوقف حركة المرور المقابلة","ليس طريقاً مُقَسَّماً، لذا يجب أن تتوقف حركة المرور المقابلة","طريق ذو وصول محدود مُعفى من التوقف","شارع باتجاه واحد لا يترتب عليه واجب التوقف"],"explanation":"تنص المادة RS 32:80 صراحةً على أن الطريق السريع الذي به حارة واحدة في كل اتجاه وحارة مخصصة لانعطاف يساري ثنائي الاتجاه لا يُعتبر طريقاً سريعاً مُقَسَّماً ذا مسارات منفصلة، لذا يجب على السائقين المقابلين التوقف. المصدر: Louisiana RS 32:80."},"63":{"q":"ينطبق قانون 'التنحّي' في لويزيانا (RS 32:125) عندما تقترب من مركبة طوارئ متوقفة تعرض إشارات ضوئية على طريق سريع بحارتين أو أكثر في اتجاهك. ما هو الإجراء الأول المطلوب؟","options":["أن تتوقف توقفاً تاماً في حارتك","أن تنتقل إلى حارة غير ملاصقة للمركبة المتوقفة، إن أمكن","أن تُطلق بوقك وتحافظ على السرعة","أن تنحرف إلى الكتف الأيمن وتتوقف"],"explanation":"تستوجب المادة RS 32:125 على السائقين على طريق به حارتان أو أكثر في الاتجاه نفسه أن يُفسحوا الطريق بتغيير الحارة إلى حارة غير ملاصقة لمركبة الطوارئ المتوقفة، عند الإمكان مع مراعاة السلامة وحركة المرور. المصدر: Louisiana RS 32:125."},"64":{"q":"بموجب قانون 'التنحّي' في لويزيانا، إذا لم تتمكن من تغيير الحارة بأمان بعيداً عن مركبة طوارئ متوقفة (أو كنت على طريق بحارتين)، ماذا يجب أن تفعل؟","options":["أن تتوقف توقفاً تاماً حتى يُخلى موقع الحادث","أن تحافظ على سرعتك المعتادة وتنحرف يساراً","أن تُبطئ إلى سرعة آمنة بشكل معقول وفق الظروف","أن تُسرّع لتجاوز المنطقة بسرعة"],"explanation":"تنص المادة RS 32:125 على أنه إذا تعذّر تغيير الحارة أو كنت على طريق بحارتين، فيجب أن تُبطئ إلى سرعة آمنة بشكل معقول وفق ظروف الطريق أثناء مرورك بمركبة الطوارئ المتوقفة. المصدر: Louisiana RS 32:125."},"65":{"q":"بالإضافة إلى الشرطة والإطفاء وخدمات الطوارئ الطبية، أي المركبات المتوقفة الأخرى التي تعرض أضواء تحذير يحميها قانون 'التنحّي' في لويزيانا (RS 32:125)؟","options":["وحدات إنفاذ القانون المُعلَّمة فقط","شاحنات القطر/الونش والمركبات التي تستخدم أضواء كهرمانية/صفراء وامضة","سيارات الإسعاف وآليات الإطفاء فقط","مركبات توصيل البريد فقط"],"explanation":"تشمل المادة RS 32:125 أي مركبة تعرض بشكل قانوني إشارات ضوئية مصرّحاً بها، بما في ذلك الأضواء التحذيرية الوامضة بالتناوب بالألوان الكهرماني أو الأصفر أو الأخضر، مما يمدّ الحماية لتشمل شاحنات القطر/الونش والمركبات الخدمية المماثلة. المصدر: Louisiana RS 32:125 (المعدّلة بموجب Acts 2021, No. 78)."},"66":{"q":"عند الاقتراب الفوري لمركبة طوارئ مصرّح بها تُطلق صفّارة وتعرض أضواءً، تستوجب المادة Louisiana RS 32:125 على سائق كل مركبة أخرى أن:","options":["يُسرّع لإخلاء التقاطع الذي أمامه","ينتقل إلى الحارة الوسطى ويُبطئ","ينحرف إلى الحافة اليمنى أو الرصيف، بعيداً عن أي تقاطع، ويتوقف","يتوقف فوراً أينما كانت المركبة، بما في ذلك داخل تقاطع"],"explanation":"تستوجب المادة RS 32:125 إفساح الطريق بالتوجه إلى موضع موازٍ وأقرب ما يمكن للحافة اليمنى أو الرصيف، بعيداً عن أي تقاطع، والتوقف حتى تمر مركبة الطوارئ. المصدر: Louisiana RS 32:125."},"67":{"q":"على طريق سريع متعدد الحارات في لويزيانا، يجب على المركبة التجارية البطيئة التي تعيق مركبة أسرع ترغب في التجاوز في الحارة اليسرى، بموجب المادة RS 32:71، أن:","options":["تحافظ على موضعها حتى المخرج التالي","تندمج بسرعة في الحارة اليمنى","تُبطئ أكثر للسماح للمركبة بالتجاوز من اليمين","تنتقل إلى الكتف الأيسر"],"explanation":"تحظر المادة RS 32:71 استخدام الحارة اليسرى لإعاقة أو إغلاق الطريق أمام مركبة متجاوِزة؛ فيجب على المركبة الأبطأ أن تندمج بسرعة في الحارة اليمنى. وغرامة المخالفة الأولى هي $150. المصدر: Louisiana RS 32:71."},"68":{"q":"عندما تتوقف مركبة تجارية CMV في لويزيانا على كتف طريق سريع باتجاه واحد أو مُقَسَّم، أين يجب وضع أجهزة التحذير الطارئة الثلاثة (المثلثات)؟","options":["على بُعد 10 أقدام و100 قدم و200 قدم باتجاه حركة المرور المقتربة","على بُعد 10 أقدام و50 قدماً و150 قدماً باتجاه حركة المرور المقتربة","على بُعد 25 قدماً و100 قدم و250 قدماً باتجاه حركة المرور المقتربة","على بُعد 15 قدماً و75 قدماً و200 قدم باتجاه حركة المرور المقتربة"],"explanation":"يستوجب دليل Louisiana CDL (المتبنّي للقاعدة الفيدرالية) وضع أجهزة التحذير على بُعد 10 أقدام و100 قدم و200 قدم باتجاه حركة المرور المقتربة عند التوقف على طريق سريع باتجاه واحد أو مُقَسَّم أو بجانبه. المصدر: دليل Louisiana CDL، القسم 2.5 (Warning Devices)."},"69":{"q":"بعد توقف مركبة CMV على طريق أو كتف في لويزيانا، خلال كم دقيقة يجب على السائق أن يضع أجهزة التحذير الطارئة؟","options":["5 دقائق","10 دقائق","15 دقيقة","30 دقيقة"],"explanation":"ينص دليل Louisiana CDL على أنه إذا اضطررت للتوقف على طريق أو كتف، فيجب أن تضع أجهزة التحذير الطارئة خلال 10 دقائق. المصدر: دليل Louisiana CDL، القسم 2.5 (Warning Devices)."},"70":{"q":"على طريق بحارتين في لويزيانا يحمل حركة مرور في كلا الاتجاهين، أين يجب أن تضع مركبة CMV متوقفة مثلثات التحذير الخاصة بها أمام المركبة وخلفها؟","options":["200 قدم أماماً و200 قدم خلفاً","100 قدم أماماً و100 قدم خلفاً","50 قدماً أماماً و100 قدم خلفاً","10 أقدام أماماً و10 أقدام خلفاً"],"explanation":"على طريق ثنائي الاتجاه/غير مُقَسَّم، يستوجب دليل Louisiana CDL وضع جهاز ضمن 10 أقدام من المركبة وأجهزة على بُعد 100 قدم أمامها و100 قدم خلفها. المصدر: دليل Louisiana CDL، القسم 2.5 (Warning Devices)."},"71":{"q":"تقترب حافلة مدرسية في لويزيانا من مَعبر سكة حديد. يوصي دليل CDL بتشغيل أضواء التحذير الطارئة للحافلة على بُعد أي مسافة تقريباً قبل المَعبر؟","options":["50 قدماً","100 قدم","200 قدم","500 قدم"],"explanation":"توصي إجراءات الحافلات المدرسية في دليل Louisiana CDL بتشغيل أضواء التحذير على بُعد 200 قدم تقريباً قبل المَعبر، ثم التوقف على مسافة 15 إلى 50 قدماً من أقرب قضيب سكة. المصدر: دليل Louisiana CDL، القسم 10.4.3 (Recommended Procedures)."},"72":{"q":"تصل حافلة في لويزيانا إلى جسر متحرك ليس فيه ضوء إشارة ولا موظف للتحكم بالمرور. يجب على السائق أن يتوقف على مسافة لا تقل عن أي مسافة قبل الجزء المتحرك من الجسر؟","options":["15 قدماً","30 قدماً","50 قدماً","100 قدم"],"explanation":"يستوجب دليل Louisiana CDL التوقف على مسافة لا تقل عن 50 قدماً قبل الجزء المتحرك من الجسر المتحرك الذي ليس فيه ضوء إشارة أو موظف للتحكم بالمرور، والتأكد من أن الجزء المتحرك مغلق تماماً قبل العبور. المصدر: دليل Louisiana CDL، القسم 4.3.6 (Drawbridges)."},"73":{"q":"إذا ارتكب سائق في لويزيانا مخالفة عند مَعبر سكة حديد بمستوى الطريق أثناء قيادة مركبة CMV موسومة بلوحات للمواد الخطرة، فإن الحد الأدنى لإسقاط أهلية رخصة CDL هو:","options":["60 يوماً","120 يوماً","سنة واحدة","3 سنوات"],"explanation":"ينص دليل Louisiana CDL على أنك ستفقد رخصة CDL لمدة لا تقل عن ثلاث سنوات إذا وقعت مخالفة عند مَعبر سكة حديد أثناء قيادة مركبة CMV موسومة بلوحات للمواد الخطرة (مقابل 60/120 يوماً لمخالفات المعابر الخطيرة غير الموسومة بلوحات). المصدر: دليل Louisiana CDL، القسم 1.2.5 (Railroad-highway Grade Crossing Violations)."},"74":{"q":"بدون تصريح للأبعاد الزائدة من Louisiana DOTD، ما هو الحد الأقصى القانوني للعَرض لمركبة تجارية وحمولتها على الطرق السريعة في لويزيانا؟","options":["8 feet 0 inches","8 feet 6 inches","9 feet 0 inches","10 feet 0 inches"],"explanation":"حدود الأبعاد القانونية في لويزيانا هي 8 feet 6 inches عرضاً، و13 feet 6 inches ارتفاعاً، و80,000 pounds؛ والحمولات التي تتجاوز ذلك تتطلب تصريح أبعاد/أوزان زائدة من DOTD، مع تقييد الحركة المصرّح بها عموماً من شروق الشمس إلى غروبها. المصدر: Louisiana DOTD Weights & Standards؛ LAC Title 73, Part I, Chapter 3."},"75":{"q":"أي جهة تُصدر رخص القيادة التجارية (CDLs) في لويزيانا؟","options":["مكتب المركبات الآلية في لويزيانا (OMV)","شرطة ولاية لويزيانا","الإدارة الفيدرالية لسلامة ناقلات النقل بالشاحنات (FMCSA)","إدارة النقل والتطوير في لويزيانا (DOTD)"],"explanation":"تُصدر رخص CDL في لويزيانا عن طريق مكتب المركبات الآلية (OMV)، وهو جزء من إدارة السلامة العامة في لويزيانا. تضع FMCSA المعايير الفيدرالية لكنها لا تُصدر الرخص؛ وتتولى DOTD شؤون الطرق وتصاريح الأبعاد/الأوزان الزائدة، وليس رخص CDL. المصدر: صفحات CDL الخاصة بـ Louisiana OMV (expresslane.la.gov)."},"76":{"q":"قبل الحصول على الرخصة، يجب على كل متقدم لرخصة CDL في لويزيانا أن يحصل أولاً على أي وثيقة؟","options":["تصريح تعلّم القيادة التجارية (CLP)","رقم صلاحية تشغيل فيدرالي للنقل بين الولايات","تصريح أبعاد/أوزان زائدة من DOTD","تصديق سائق مؤقت"],"explanation":"في لويزيانا يجب أن تحمل تصريح تعلّم القيادة التجارية (CLP) قبل أن تتمكن من إجراء اختبار المهارات لرخصة CDL والحصول على الرخصة. يتيح لك تصريح CLP التدرّب على الطرق العامة بصحبة حامل رخصة CDL. المصدر: صفحة 'New CDL' الخاصة بـ Louisiana OMV."},"77":{"q":"كم يجب أن ينتظر حامل تصريح CLP في لويزيانا بعد إصدار التصريح للمرة الأولى قبل أن يصبح مؤهلاً لإجراء اختبار المهارات لرخصة CDL؟","options":["14 يوماً","30 يوماً","10 أيام","60 يوماً"],"explanation":"تطبّق لويزيانا فترة الانتظار الفيدرالية البالغة 14 يوماً: فحامل تصريح CLP غير مؤهل لإجراء اختبار المهارات لرخصة CDL خلال أول 14 يوماً بعد الإصدار الأولي لتصريح CLP. المصدر: صفحة 'New CDL' الخاصة بـ Louisiana OMV (49 CFR 383.25)."},"78":{"q":"ما هي أقصى مدة يمكن أن يظل فيها تصريح CLP في لويزيانا سارياً، باحتساب مدته الأولية إضافة إلى التمديد المسموح به؟","options":["360 يوماً (180 يوماً إضافة إلى تمديد واحد مدته 180 يوماً)","180 يوماً دون السماح بأي تمديد","سنة واحدة (365 يوماً)","90 يوماً إضافة إلى تمديد واحد مدته 90 يوماً"],"explanation":"يُصدَر تصريح CLP في لويزيانا لمدة تصل إلى 180 يوماً ويمكن تمديده مرة واحدة لمدة 180 يوماً إضافية، بحد أقصى 360 يوماً. المصدر: صفحة 'New CDL' الخاصة بـ Louisiana OMV (49 CFR 383.25)."},"79":{"q":"كم عدد فئات التصديق الذاتي المتمايزة التي يجب على متقدم رخصة CDL/CLP في لويزيانا الاختيار من بينها بشأن نوع النقل التجاري الذي سيمارسه؟","options":["أربع","اثنتان","ثلاث","خمس"],"explanation":"هناك أربع فئات للتصديق الذاتي: غير المُعفى بين الولايات (NI)، والمُعفى بين الولايات (EI)، وغير المُعفى داخل الولاية (NA)، والمُعفى داخل الولاية (EA). المصدر: مواد التصديق الذاتي لرخصة CDL الخاصة بـ Louisiana OMV (49 CFR 383.71)."},"80":{"q":"أي فئتين من فئات التصديق الذاتي تستوجبان على حامل رخصة CDL في لويزيانا أن يمتلك ويحتفظ بشهادة فاحص طبي في ملفه؟","options":["غير المُعفى بين الولايات وغير المُعفى داخل الولاية","المُعفى بين الولايات والمُعفى داخل الولاية","غير المُعفى بين الولايات والمُعفى بين الولايات","المُعفى داخل الولاية وغير المُعفى داخل الولاية"],"explanation":"يجب على السائقين الذين يُصدّقون ذاتياً بأنهم غير مُعفين بين الولايات (NI) أو غير مُعفين داخل الولاية (NA) أن يستوفوا معايير الأهلية الطبية وأن يحتفظوا بشهادة فاحص طبي سارية في الملف. أما الفئتان 'المُعفاتان' (EI، EA) فغير مُلزَمتين بذلك. المصدر: مواد التصديق الذاتي الخاصة بـ Louisiana OMV (49 CFR 383.71)."},"81":{"q":"السائق الذي ينقل البضائع داخل لويزيانا فقط مقابل أجر ويجب أن يستوفي المعايير الطبية ينبغي أن يُصدّق ذاتياً تحت أي فئة؟","options":["غير المُعفى داخل الولاية (NA)","غير المُعفى بين الولايات (NI)","المُعفى بين الولايات (EI)","المُعفى داخل الولاية (EA)"],"explanation":"العمل التجاري داخل لويزيانا فقط ('داخل الولاية') مع الخضوع لمعايير الأهلية الطبية هو فئة غير المُعفى داخل الولاية (NA). أما الفئات بين الولايات فتنطبق على عبور حدود الولايات. المصدر: تعريفات التصديق الذاتي الخاصة بـ Louisiana OMV (49 CFR 383.71)."},"82":{"q":"أي نموذج طبي يجب على متقدم رخصة CDL في لويزيانا الذي يُصدّق ذاتياً بأنه غير مُعفى أن يقدّمه كإثبات للأهلية الطبية؟","options":["شهادة الفاحص الطبي (النموذج MCSA-5876)","إعفاء طبي للأبعاد/الأوزان الزائدة من DOTD","النموذج التكميلي لرخصة CDL (DPSMV2211)","إقرار لياقة من شرطة ولاية لويزيانا"],"explanation":"يجب على متقدمي رخصة CDL غير المُعفين تقديم شهادة فاحص طبي سارية (النموذج MCSA-5876) مُعبّأة من قبل فاحص معتمد. أما النموذج DPSMV2211 فهو نموذج الطلب التكميلي لرخصة CDL، وليس الشهادة الطبية. المصدر: صفحتا 'New CDL' / 'Submit CDL Medical Certificate' الخاصتان بـ Louisiana OMV."},"83":{"q":"مَن المخوّل بإجراء الفحص البدني الذي تستند إليه شهادة الفاحص الطبي لرخصة CDL في لويزيانا؟","options":["فاحص طبي مُدرَج في السجل الوطني للفاحصين الطبيين المعتمدين التابع لـ FMCSA","أي طبيب مرخّص يختاره السائق","طبيب يعمل لدى Louisiana OMV","أي ممرض ممارس مرخّص بغض النظر عن وضعه في السجل"],"explanation":"يجب أن يُجري الفحص البدني فاحص طبي معتمد ومُدرَج في السجل الوطني للفاحصين الطبيين المعتمدين التابع لـ FMCSA. المصدر: صفحتا 'New CDL' / معلومات الشهادة الطبية لرخصة CDL الخاصتان بـ Louisiana OMV."},"84":{"q":"بأي من الطرق التالية يقبل Louisiana OMV شهادة الفاحص الطبي لرخصة CDL؟","options":["عبر البريد الإلكتروني أو الفاكس أو البريد العادي إلى OMV","فقط بالحضور شخصياً إلى أحد مكاتب OMV الميدانية","فقط من خلال رفع الفاحص لها إلى FMCSA","فقط بالبريد المسجّل مع ورقة غلاف موثّقة"],"explanation":"يقبل Louisiana OMV شهادة الفاحص الطبي عبر البريد الإلكتروني (OMV_CDL_Medical@dps.la.gov) أو الفاكس أو البريد العادي. المصدر: صفحة 'Submit CDL Medical Certificate' الخاصة بـ Louisiana OMV."},"85":{"q":"قبل كم من الوقت من انتهاء صلاحية الشهادة الطبية لحامل رخصة CDL يرسل Louisiana OMV إشعاراً يطلب إجراء فحص طبي جديد؟","options":["60 يوماً قبل انتهاء الصلاحية","30 يوماً قبل انتهاء الصلاحية","90 يوماً قبل انتهاء الصلاحية","10 أيام قبل انتهاء الصلاحية"],"explanation":"يُنشئ Louisiana OMV إشعاراً للعميل قبل 60 يوماً من انتهاء صلاحية الشهادة الطبية الموجودة في الملف، يطلب فيه نموذج فحص وشهادة جديدين. المصدر: صفحة معلومات الشهادة الطبية لرخصة CDL الخاصة بـ Louisiana OMV."},"86":{"q":"إذا لم يقدّم حامل رخصة CDL في لويزيانا شهادة طبية جديدة، فمتى يُصنَّف السائق على أنه 'غير مؤهل طبياً'؟","options":["بعد 10 أيام من انتهاء صلاحية الشهادة الطبية الموجودة في الملف","فوراً في تاريخ انتهاء الصلاحية","بعد 60 يوماً من انتهاء صلاحية الشهادة","بعد 30 يوماً من انتهاء صلاحية الشهادة"],"explanation":"يؤدي عدم استيفاء متطلبات التصديق الذاتي/الطبية إلى تصنيف السائق على أنه 'غير مؤهل طبياً' بعد 10 أيام من انتهاء صلاحية الشهادة الطبية الموجودة في الملف؛ وتُلغى رخصة CDL لاحقاً إذا استمر عدم الامتثال. المصدر: صفحة معلومات الشهادة الطبية لرخصة CDL الخاصة بـ Louisiana OMV."},"87":{"q":"يتألف اختبار المهارات لرخصة CDL في لويزيانا من أي ثلاثة أجزاء، تُؤدّى بالترتيب؟","options":["الفحص قبل الرحلة، والتحكم الأساسي بالمركبة، والقيادة على الطريق","الاختبار المعرفي الكتابي، وفحص البصر، والقيادة على الطريق","الفحص قبل الرحلة، ومناولة المواد الخطرة، وتفريغ ضغط الفرامل الهوائية","التحكم الأساسي بالمركبة، وتدقيق دفتر السجل، والقيادة على الطريق"],"explanation":"يتكوّن اختبار المهارات لرخصة CDL في لويزيانا من ثلاثة أجزاء: الفحص قبل الرحلة، واختبار التحكم الأساسي بالمركبة، واختبار القيادة على الطريق. المصدر: دليل Louisiana CDL / صفحات CDL الخاصة بـ Louisiana OMV (49 CFR 383.113)."},"88":{"q":"أي تدريب يجب على متقدم في لويزيانا إكماله قبل إجراء اختبار المهارات لرخصة CDL لأول رخصة من الفئة A أو الفئة B؟","options":["تدريب السائق المبتدئ (ELDT) من مزوّد مسجّل لدى FMCSA","دورة قيادة دفاعية من Louisiana OMV","دورة لمناولة الأحمال ذات الأبعاد الزائدة من DOTD","ندوة لفحص محطات الوزن تديرها الولاية"],"explanation":"يجب إكمال تدريب السائق المبتدئ (ELDT) المقدَّم من مدرسة مُدرَجة في سجل مزوّدي التدريب التابع لـ FMCSA قبل إجراء اختبار المهارات لرخصة CDL الأولى (وقبل اختبار المعرفة الخاص بالمواد الخطرة). المصدر: صفحة 'New CDL' الخاصة بـ Louisiana OMV (49 CFR Part 380 Subpart F)."},"89":{"q":"قبل الاختبار، ما هو أول اختبار يجب على متقدم رخصة CDL في لويزيانا اجتيازه ليتأهل للحصول على تصريح تعلّم القيادة التجارية؟","options":["الاختبار المعرفي الكتابي العام (اختبار المعرفة)","اختبار مهارات القيادة على الطريق","اختبار التحكم الأساسي بالمركبة","اختبار الفحص قبل الرحلة"],"explanation":"يجب على المتقدمين اجتياز الاختبارات المعرفية الكتابية المطلوبة، بدءاً بالاختبار المعرفي العام، للحصول على تصريح CLP؛ أما اختبارات المهارات فتأتي لاحقاً بعد حيازة تصريح CLP. المصدر: دليل Louisiana CDL / صفحات CDL الخاصة بـ OMV."},"90":{"q":"في الاختبار المعرفي الكتابي العام لرخصة CDL في لويزيانا المكوّن من 50 سؤالاً، ما هي الدرجة الدنيا المطلوبة للنجاح؟","options":["80% (40 من 50 صحيحة)","70% (35 من 50 صحيحة)","75% (38 من 50 صحيحة)","90% (45 من 50 صحيحة)"],"explanation":"يتكوّن الاختبار المعرفي العام من 50 سؤالاً متعدد الخيارات، ويُطلب تحقيق درجة 80% (40 من 50) للنجاح، تماشياً مع المعيار الفيدرالي لرخصة CDL. المصدر: دليل Louisiana CDL / مواد الاختبار الخاصة بـ OMV (49 CFR 383.135)."},"91":{"q":"ما هو الحد الأدنى للعمر للحصول على رخصة CDL في لويزيانا مقتصرة على التشغيل داخل الولاية (ضمن الولاية)؟","options":["18 عاماً","21 عاماً","19 عاماً","16 عاماً"],"explanation":"يجب أن يكون عمر المتقدم 18 عاماً على الأقل لحمل رخصة CDL في لويزيانا مقتصرة على التشغيل داخل الولاية؛ ويُشترط بلوغ 21 عاماً للقيادة بين الولايات ولنقل المواد الخطرة. المصدر: صفحات CDL الخاصة بـ Louisiana OMV (49 CFR 383.3 / 391.11)."},"92":{"q":"ما الوثائق التي يجب على متقدم رخصة CDL في لويزيانا تقديمها عند التقديم، إضافة إلى الهوية والشهادة الطبية؟","options":["إثبات الإقامة في لويزيانا (مثل كشوف المرافق أو عقد إيجار)","خطاب رعاية موثّق من صاحب العمل","مسح طريق من DOTD للبضائع المقصودة","نسخة من صلاحية تشغيل USDOT الخاصة بالناقل"],"explanation":"تشترط لويزيانا إثبات الإقامة في لويزيانا (مثل كشوف المرافق أو عقد الإيجار أو تسجيل الناخبين) إلى جانب النموذج التكميلي لرخصة CDL (DPSMV2211) وشهادة الفاحص الطبي. المصدر: صفحة 'New CDL' الخاصة بـ Louisiana OMV."},"93":{"q":"كم عدد السنوات التي تكون فيها رخصة CDL في لويزيانا سارية عادةً قبل وجوب تجديدها؟","options":["6 سنوات","4 سنوات","8 سنوات","5 سنوات"],"explanation":"تكون رخصة CDL في لويزيانا سارية عموماً لمدة 6 سنوات. ويجب الحفاظ طوال هذه المدة على التصديق الذاتي لنوع التشغيل وعلى شهادة طبية سارية (للسائقين غير المُعفين). المصدر: معلومات تجديد رخصة CDL الخاصة بـ Louisiana OMV."},"94":{"q":"فيما يتعلق برسوم اختبار المهارات لرخصة CDL في لويزيانا الذي يُجريه فاحص طرف ثالث، أي عبارة تُعدّ الوصف الأدق للإجراء؟","options":["يمكن إجراء اختبار المهارات عبر فاحصي طرف ثالث معتمدين، والرسم الدقيق يحدّده الفاحص ويمكن أن يتغيّر، لذا ينبغي على المتقدمين التأكد من المبلغ الحالي","اختبار المهارات مجاني دائماً عند إجرائه في أي مكتب من مكاتب OMV","رسم اختبار المهارات محدّد بموجب القانون الفيدرالي وهو متطابق في كل ولاية","لا يجوز فرض أي رسم لاختبار المهارات إطلاقاً إذا أحضر المتقدم مركبته الخاصة"],"explanation":"تسمح لويزيانا بأن يُجري اختبار المهارات فاحصو طرف ثالث معتمدون، والرسم يحدّده الفاحص وهو عرضة للتغيير، لذا ينبغي على المتقدمين التحقق من المبلغ الحالي بدلاً من الاعتماد على رقم ثابت. المصدر: صفحات CDL الخاصة بـ Louisiana OMV (برنامج اختبار الطرف الثالث)."}}};
